}

.formatting-toolbar-button:hover {
    background-color: #4a5568;
    color: #ffffff;
}

.formatting-toolbar-button svg {
    width: 16px;
    height: 16px;
}

.sticky-toolbar {
    position: -webkit-sticky;
    position: sticky;
    top: 0;
    z-index: 10;
}

.prose-sepia {
    --tw-prose-body: #5b4636;
    --tw-prose-headings: #5b4636;
    --tw-prose-lead: #5b4636;
    --tw-prose-links: #5b4636;
    --tw-prose-bold: #5b4636;
    --tw-prose-counters: #5b4636;
    --tw-prose-bullets: #5b4636;
