}

.pdf-preview-container {
    display: flex;
    justify-content: center;
    align-items: flex-start;
    padding: 2rem;
    overflow: auto;
    background-color: #1a202c;
}

.pdf-preview-scaler {
    transform-origin: top center;
    transition: transform 0.2s ease-out;
}

.pdf-switch {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}
.pdf-switch input {
  opacity: 0;
  width: 0;
  height: 0;
}
.pdf-switch .slider {
  position: relative;
  cursor: pointer;
  width: 34px;
  height: 20px;
  background-color: #4a5568;
  border-radius: 10px;
  transition: background-color 0.2s;
}
.pdf-switch .slider:before {
  position: absolute;
  content: "";
  height: 16px;
  width: 16px;
  left: 2px;
  bottom: 2px;
  background-color: white;
  border-radius: 50%;
  transition: transform 0.2s;
}
.pdf-switch input:checked + .slider {
  background-color: #6366f1;
}
.pdf-switch input:checked + .slider:before {
  transform: translateX(14px);
}

.vertical-preview-container {
    overflow-x: auto;
    overflow-y: hidden;
    padding: 1.5rem;
    display: flex;
    flex-direction: row-reverse; 
}

.vertical-writing {
    writing-mode: vertical-rl;
    text-orientation: mixed;
    white-space: nowrap;
    height: 100%;
    width: auto;
}

.vertical-writing > div {
    display: inline-block;
    vertical-align: top;
    white-space: pre-wrap;
    height: 100%;
    margin-left: 2em;
    line-height: 1.9;
}

.vertical-writing.prose h1.chapter-title::before {
    left: auto;
    right: -1.2em;
    top: 0;
    transform: none;
}

.timeline-event-wrapper {
    position: relative;
    transition: transform 0.2s ease-out;
}

.timeline-event-wrapper.dragging {
    opacity: 0.5;
    background-color: #374151;
}

.timeline-event-wrapper.drag-over-top::before,
.timeline-event-wrapper.drag-over-bottom::after {
    content: '';
    position: absolute;
    left: 0;
    right: 0;
    height: 4px;
    background-color: #6366f1;
    border-radius: 2px;
    z-index: 10;
}

.timeline-event-wrapper.drag-over-top::before {
    top: -4px;
}

.timeline-event-wrapper.drag-over-bottom::after {
    bottom: -4px;
}

.outline-panel-container {
    display: flex;
    flex-direction: column;
    height: 100%;
}
.outline-list {
    flex-grow: 1;
    overflow-y: auto;
}
.outline-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.5rem;
    border-radius: 0.375rem;
    transition: background-color 0.2s;
    border: 1px solid transparent;
    position: relative;
}
.outline-item:hover {
    background-color: rgba(255, 255, 255, 0.05);
}
.outline-item .drag-handle {
    cursor: grab;
    color: #6b7280;
}
.outline-item:hover .drag-handle {
    color: #9ca3af;
}
.outline-item .title {
    flex-grow: 1;
    text-align: left;
    font-size: 0.875rem;
    color: #d1d5db;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    background: none;
    border: none;
    padding: 0;
    cursor: pointer;
}
.outline-item .title:hover {
    text-decoration: underline;
}
.outline-item .actions {
    display: flex;
    gap: 0.25rem;
    opacity: 0;
    transition: opacity 0.2s;
    z-index: 10;
}
.outline-item:hover .actions {
    opacity: 1;
}
.mobile-always-show {
    opacity: 1 !important;
    pointer-events: auto !important;
    visibility: visible !important;
}
.outline-item .actions button {
    border-radius: 9999px;
    background: none;
    border: none;
