kbd {
    background-color: #4a5568;
    color: #e2e8f0;
    border-radius: 4px;
    padding: 2px 6px;
    font-size: 0.8em;
    font-family: monospace;
    border: 1px solid #2d3748;
    box-shadow: 1px 1px 1px #1a202c;
