  border-width: 0;
}

.btn-pressable {
    transition: transform 0.15s cubic-bezier(0.4, 0, 0.2, 1), background-color 0.15s, color 0.15s, border-color 0.15s;
}
.btn-pressable:active {
    transform: translateY(1px);
    transition-duration: 0.05s;
}

.btn-invert-indigo { background-color: #4f46e5; color: white; }
.btn-invert-indigo:hover { background-color: white; color: #4f46e5; }

.btn-invert-gray { background-color: #4a5568; color: white; }
.btn-invert-gray:hover { background-color: white; color: #4a5568; }

.btn-invert-gray-700 { background-color: #374151; color: white; }
.btn-invert-gray-700:hover { background-color: white; color: #374151; }

.btn-invert-green { background-color: #16a34a; color: white; }
.btn-invert-green:hover { background-color: white; color: #16a34a; }

.btn-invert-blue { background-color: #2563eb; color: white; }
.btn-invert-blue:hover { background-color: white; color: #2563eb; }

.btn-invert-red { background-color: #dc2626; color: white; }
.btn-invert-red:hover { background-color: white; color: #dc2626; }

