/* ツールチップのアニメーション */
@keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
@keyframes zoomIn { from { transform: scale(0.95) translate(-50%, -100%); } to { transform: scale(1) translate(-50%, -100%); } }

.animate-in {
  animation-duration: 150ms;
  animation-timing-function: cubic-bezier(0.4, 0, 0.2, 1);
  animation-fill-mode: forwards;
}

.fade-in { animation-name: fadeIn; }
.zoom-in { animation-name: zoomIn; }

.highlight-chunk {
    background-color: rgba(255, 255, 0, 0.2);
    border-radius: 8px;
    transition: background-color 0.5s ease-in-out;
}

/* 文字色適用を促すアニメーション */
@keyframes pulse-prompt {
  0%, 100% {
    transform: scale(1);
    filter: drop-shadow(0 0 0px rgba(99, 102, 241, 0));
  }
  50% {
    transform: scale(1.25);
    filter: drop-shadow(0 0 8px rgba(99, 102, 241, 0.8));
  }
}

.animate-pulse-prompt {
  animation: pulse-prompt 1.2s ease-in-out infinite;
  z-index: 10;
}

