import React, { useState, useRef, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { useStore } from '../store/index';
import { helpTexts } from '../helpTexts';

interface TooltipProps {
    helpId: string;
    children: React.ReactElement<any>;
}

export const Tooltip: React.FC<TooltipProps> = ({ helpId, children }) => {
    const [isVisible, setIsVisible] = useState(false);
    const [position, setPosition] = useState({ top: 0, left: 0 });
    const userMode = useStore(state => state.userMode);
    const timeoutRef = useRef<number | null>(null);

    const isMac = useMemo(() => navigator.platform.toUpperCase().indexOf('MAC') >= 0, []);
    const modifier = isMac ? '⌘' : 'Ctrl';

    const data = helpTexts[helpId]?.[userMode];

    const showTooltip = (e: React.MouseEvent) => {
        const rect = e.currentTarget.getBoundingClientRect();
        setPosition({
            top: rect.top - 8,
            left: rect.left + rect.width / 2
        });

        if (timeoutRef.current) window.clearTimeout(timeoutRef.current);
        timeoutRef.current = window.setTimeout(() => {
            setIsVisible(true);
        }, 400); // 誤爆防止ディレイ
    };

    const hideTooltip = () => {
        if (timeoutRef.current) window.clearTimeout(timeoutRef.current);
        setIsVisible(false);
    };

    if (!data) return children;

    const trigger = React.cloneElement(children, {
        onMouseEnter: (e: React.MouseEvent) => {
            children.props.onMouseEnter?.(e);
            showTooltip(e);
        },
        onMouseLeave: (e: React.MouseEvent) => {
            children.props.onMouseLeave?.(e);
            hideTooltip();
        },
        onMouseDown: (e: React.MouseEvent) => {
            children.props.onMouseDown?.(e);
            hideTooltip();
        }
    });

    return (
        <>
            {trigger}
            {isVisible && createPortal(
                <div 
                    style={{ 
                        position: 'fixed',
                        top: position.top,
                        left: position.left,
                        transform: 'translate(-50%, -100%)',
                        zIndex: 9999
                    }}
                    className="pointer-events-none animate-in fade-in zoom-in duration-150"
                >
                    <div className="bg-gray-900 border border-gray-700 text-white p-2.5 rounded-lg shadow-2xl min-w-[160px] max-w-[240px]">
                        <div className="flex justify-between items-center mb-1">
                            <span className="font-bold text-xs text-indigo-300">{data.title}</span>
                            {data.shortcut && (
                                <span className="text-[10px] bg-gray-800 px-1.5 py-0.5 rounded text-gray-400 border border-gray-700">
                                    {modifier}+{data.shortcut}
                                </span>
                            )}
                        </div>
                        <p className="text-[11px] text-gray-200 leading-relaxed whitespace-pre-wrap">{data.desc}</p>
                        {data.tech && (
                            <div className="mt-1.5 pt-1.5 border-t border-gray-800 text-[9px] text-emerald-400 font-mono">
                                dev: {data.tech}
                            </div>
                        )}
                        <div className="absolute left-1/2 -bottom-1 -translate-x-1/2 w-2 h-2 bg-gray-900 border-r border-b border-gray-700 rotate-45"></div>
                    </div>
                </div>,
                document.body
            )}
        </>
    );
};

