import React, { useState, useRef, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { useStore } from '../store/index';
import { helpTexts } from '../helpTexts';

interface TooltipProps {
    helpId: string;
    children: React.ReactElement<any>;
    placement?: 'top' | 'right';
}

export const Tooltip: React.FC<TooltipProps> = ({ helpId, children, placement = 'top' }) => {
    const [isVisible, setIsVisible] = useState(false);
    const [position, setPosition] = useState({ top: 0, left: 0 });
    const userMode = useStore(state => state.userMode);
    const timeoutRef = useRef<number | null>(null);

    const isMac = useMemo(() => navigator.platform.toUpperCase().indexOf('MAC') >= 0, []);
    const modifier = isMac ? '⌘' : 'Ctrl';

    const data = helpTexts[helpId]?.[userMode];

    const showTooltip = (e: React.MouseEvent) => {
        const rect = e.currentTarget.getBoundingClientRect();

        if (placement === 'right') {
            setPosition({
                top: rect.top + rect.height / 2,
                left: rect.right + 10
            });
        } else {
            setPosition({
                top: rect.top - 8,
                left: rect.left + rect.width / 2
            });
        }

        if (timeoutRef.current) window.clearTimeout(timeoutRef.current);
        timeoutRef.current = window.setTimeout(() => {
            setIsVisible(true);
        }, 400); // 誤爆防止ディレイ
    };

    const hideTooltip = () => {
        if (timeoutRef.current) window.clearTimeout(timeoutRef.current);
        setIsVisible(false);
    };

    if (!data) return children;

    const trigger = React.cloneElement(children, {
        onMouseEnter: (e: React.MouseEvent) => {
            children.props.onMouseEnter?.(e);
            showTooltip(e);
        },
        onMouseLeave: (e: React.MouseEvent) => {
            children.props.onMouseLeave?.(e);
            hideTooltip();
        },
        onMouseDown: (e: React.MouseEvent) => {
            children.props.onMouseDown?.(e);
            hideTooltip();
        }
    });

    const transform = placement === 'right' ? 'translateY(-50%)' : 'translate(-50%, -100%)';
    const arrowClass = placement === 'right' 
        ? "absolute top-1/2 -left-1 -translate-y-1/2 w-2 h-2 bg-gray-900 border-l border-b border-gray-700 rotate-45"
        : "absolute left-1/2 -bottom-1 -translate-x-1/2 w-2 h-2 bg-gray-900 border-r border-b border-gray-700 rotate-45";

    return (
        <>
            {trigger}
            {isVisible && createPortal(
                <div 
                    style={{ 
                        position: 'fixed',
                        top: position.top,
                        left: position.left,
                        zIndex: 9999
                    }}
                    className="pointer-events-none"
                >
                    <div 
                        style={{ transform }}
                        className="animate-in zoom-in duration-150"
                    >
                        <div className="bg-gray-900 border border-gray-700 text-white p-2.5 rounded-lg shadow-2xl min-w-[160px] max-w-[240px] relative">
                            <div className="flex justify-between items-center mb-1 gap-2">
                                <span className="font-bold text-xs text-indigo-300 whitespace-nowrap">{data.title}</span>
                                {data.shortcut && (
                                    <span className="text-[10px] bg-gray-800 px-1.5 py-0.5 rounded text-gray-400 border border-gray-700 whitespace-nowrap">
                                        {modifier}+{data.shortcut}
                                    </span>
                                )}
                            </div>
                            <p className="text-[11px] text-gray-200 leading-relaxed whitespace-pre-wrap">{data.desc}</p>
                            {data.tech && (
                                <div className="mt-1.5 pt-1.5 border-t border-gray-800 text-[9px] text-emerald-400 font-mono">
                                    dev: {data.tech}
                                </div>
                            )}
                            {/* 矢印 */}
                            <div className={arrowClass}></div>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </>
    );
};

import React, { useMemo } from 'react';
import * as Icons from '../icons';
import { useStore } from '../store/index';
import { LeftPanelTab } from '../types';
import { Tooltip } from './Tooltip';

const tabConfig: { id: LeftPanelTab; icon: React.ReactNode; label: string; helpId: string; proOnly?: boolean }[] = [
    { id: 'settings', icon: <Icons.SettingsIcon />, label: 'プロジェクト設定', helpId: 'settings' },
    { id: 'characters', icon: <Icons.UserPlusIcon />, label: 'キャラクター', helpId: 'characters' },
    { id: 'worlds', icon: <Icons.GlobeIcon />, label: '世界観', helpId: 'worlds' },
    { id: 'knowledge', icon: <Icons.LightbulbIcon />, label: 'ナレッジ', helpId: 'knowledge' },
    { id: 'plots', icon: <Icons.ClipboardListIcon />, label: 'プロット', helpId: 'plots' },
    { id: 'outline', icon: <Icons.ListOrderedIcon />, label: 'アウトライン', helpId: 'outline' },
];

export const ActivityBar = () => {
    const {
        leftPanelTab,
        setLeftPanelTab,
        isSimpleMode,
        userMode,
        isLeftSidebarOpen,
        setIsLeftSidebarOpen
    } = useStore(state => ({
        leftPanelTab: state.leftPanelTab,
        setLeftPanelTab: state.setLeftPanelTab,
        isSimpleMode: state.allProjectsData[state.activeProjectId]?.isSimpleMode,
        userMode: state.userMode,
        isLeftSidebarOpen: state.isLeftSidebarOpen,
        setIsLeftSidebarOpen: state.setIsLeftSidebarOpen,
    }));

    const visibleTabConfig = useMemo(() => {
        if (userMode === 'simple') {
            return tabConfig.filter(tab => ['characters', 'knowledge', 'settings'].includes(tab.id));
        }
        if (userMode === 'standard') {
             return tabConfig.filter(tab => !tab.proOnly);
        }
        return tabConfig;
    }, [userMode]);

    if (isSimpleMode || userMode === 'simple') return null;

    const handleTabClick = (id: LeftPanelTab) => {
         if (leftPanelTab === id) {
             setIsLeftSidebarOpen(!isLeftSidebarOpen);
         } else {
             setLeftPanelTab(id);
             if (!isLeftSidebarOpen) setIsLeftSidebarOpen(true);
         }
    };

    return (
        <div className="w-14 bg-gray-900 flex flex-col items-center py-4 space-y-2 border-r border-gray-700/50 flex-shrink-0 z-20">
            {visibleTabConfig.map(tab => (
                <Tooltip key={tab.id} helpId={tab.helpId} placement="right">
                    <button
                        onClick={() => handleTabClick(tab.id)}
                        className={`p-2 rounded-lg transition-colors ${leftPanelTab === tab.id && isLeftSidebarOpen ? 'bg-indigo-600 text-white' : 'text-gray-400 hover:bg-gray-700 hover:text-white'}`}
                    >
                        {React.cloneElement<any>(tab.icon as React.ReactElement, { className: 'h-6 w-6' })}
                    </button>
                </Tooltip>
            ))}
        </div>
    );
};

import React, { useState, useRef, useMemo } from 'react';
