const SuggestionHistoryModal = ({ isOpen, onClose, knowledgeSuggestions, onApproveKnowledge, plotSuggestions, onApprovePlot, loadingKnowledge }) => {
    const [activeTab, setActiveTab] = useState<'knowledge' | 'plot'>('knowledge');
    const modalRef = useRef(null);

    useEffect(() => {
        const handleClickOutside = (event) => {
            if (modalRef.current && !modalRef.current.contains(event.target)) {
                onClose();
            }
        };
        if (isOpen) {
            document.addEventListener('mousedown', handleClickOutside);
        }
        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, [isOpen, onClose]);

    useEffect(() => {
        if(isOpen) {
            if(knowledgeSuggestions.length > 0) {
                setActiveTab('knowledge');
            } else if (plotSuggestions.length > 0) {
                setActiveTab('plot');
            }
        }
    }, [isOpen, knowledgeSuggestions, plotSuggestions]);

    if (!isOpen) return null;

    const renderContent = () => {
        if (activeTab === 'knowledge') {
            return knowledgeSuggestions.length === 0 ? (
                <p className="text-sm text-gray-400 text-center py-8">履歴はありません。</p>
            ) : (
                knowledgeSuggestions.map(suggestion => {
                    const isThisLoading = loadingKnowledge === suggestion.content;
                    return (
                        <div key={suggestion.id} className="bg-gray-900/50 p-3 rounded-md text-sm">
                            <p className="text-gray-300">{suggestion.content}</p>
                            <div className="text-right mt-2">
                                <Tooltip helpId="apply_ai">
                                    <button 
                                        onClick={() => onApproveKnowledge({ content: suggestion.content, id: suggestion.id })}
                                        disabled={isThisLoading}
                                        className="px-3 py-1 rounded-md text-xs font-semibold btn-pressable btn-invert-teal flex items-center justify-center w-28 disabled:bg-gray-500 disabled:cursor-not-allowed"
                                    >
                                        {isThisLoading ? (
                                            <>
                                                <Icons.LoaderIcon className="h-4 w-4 mr-1"/>
                                                <span>追加中...</span>
                                            </>
                                        ) : (
                                            'この提案を承認'
                                        )}
                                    </button>
                                </Tooltip>
                            </div>
                        </div>
                    );
                })
            );
        }
        if (activeTab === 'plot') {
            return plotSuggestions.length === 0 ? (
                <p className="text-sm text-gray-400 text-center py-8">履歴はありません。</p>
            ) : (
                plotSuggestions.map(suggestion => (
                    <div key={suggestion.id} className="bg-gray-900/50 p-3 rounded-md text-sm">
                        <p className="font-bold text-cyan-400">{suggestion.title}</p>
                        <p className="text-gray-300 mt-1">{suggestion.summary}</p>
                        <div className="text-right mt-2">
                            <Tooltip helpId="apply_ai">
                                <button onClick={() => { onApprovePlot(suggestion, 'plot'); }} className="px-3 py-1 rounded-md text-xs font-semibold btn-pressable btn-invert-teal">この提案を承認</button>
                            </Tooltip>
                        </div>
                    </div>
                ))
            );
        }
    };

    const TabButton = ({ tabId, label, icon }) => (
        <button
            onClick={() => setActiveTab(tabId)}
            className={`flex-1 flex items-center justify-center gap-2 px-3 py-2 text-sm font-medium transition-colors rounded-t-md ${activeTab === tabId ? 'bg-gray-800 text-indigo-400' : 'bg-gray-900/50 text-gray-400 hover:text-white'}`}
        >
            {icon}
            {label}
        </button>
    );

    return (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex justify-center items-center z-50">
            <div
                ref={modalRef}
                className="bg-gray-800 rounded-lg shadow-xl w-full max-w-lg border border-gray-700 max-h-[80vh] flex flex-col"
            >
                <div className="flex justify-between items-center p-6 pb-4 flex-shrink-0">
                    <h2 className="text-xl font-bold text-indigo-400 flex items-center gap-2">
                        <Icons.HistoryIcon />
                        提案履歴
                    </h2>
                    <button onClick={onClose} className="p-2 rounded-full hover:bg-gray-700 transition">
                        <Icons.XIcon />
                    </button>
                </div>
                <div className="px-6 flex-shrink-0">
                     <div className="flex border-b border-gray-700">
                        <TabButton tabId="knowledge" label="ナレッジ" icon={<Icons.LightbulbIcon className="h-4 w-4" />} />
                        <TabButton tabId="plot" label="プロット" icon={<Icons.ClipboardListIcon className="h-4 w-4" />} />
                    </div>
                </div>
                <div className="flex-grow overflow-y-auto p-6 pt-4 space-y-3">
                    {renderContent()}
                </div>
            </div>
        </div>
    );
};


