import React from 'react';
import * as Icons from '../icons';
import { useStore } from '../store/index';
import { SaveStatusIndicator } from './SaveStatusIndicator';
import { SettingsPanel } from './panels/SettingsPanel';
import { CharacterListPanel } from './panels/CharacterListPanel';
import { WorldListPanel } from './panels/WorldListPanel';
import { KnowledgeListPanel } from './panels/KnowledgeListPanel';
import { PlotListPanel } from './panels/PlotListPanel';
import { OutlinePanel } from './panels/OutlinePanel';
import { LeftPanelTab } from '../types';
import { Tooltip } from './Tooltip';

interface LeftPanelProps {
    onExportProject: () => void;
    onExportTxt: () => void;
    isMobile?: boolean;
}

export const LeftPanel: React.FC<LeftPanelProps> = ({ onExportProject, onExportTxt, isMobile = false }) => {
    const {
        leftSidebarWidth,
        saveStatus,
        leftPanelTab,
        setLeftPanelTab,
        setActiveProjectId,
        isSimpleMode,
        userMode,
        setIsLeftSidebarOpen
    } = useStore(state => ({
        leftSidebarWidth: state.leftSidebarWidth,
        saveStatus: state.saveStatus,
        leftPanelTab: state.leftPanelTab,
        setLeftPanelTab: state.setLeftPanelTab,
        setActiveProjectId: state.setActiveProjectId,
        isSimpleMode: state.allProjectsData[state.activeProjectId]?.isSimpleMode,
        userMode: state.userMode,
        setIsLeftSidebarOpen: state.setIsLeftSidebarOpen,
    }));

    const resizeTransitionClass = isMobile ? '' : 'transition-[width] duration-300 ease-in-out';
    const widthStyle = isMobile ? { width: '100%', height: '100%' } : { width: `${leftSidebarWidth}px` };

    const renderContent = () => {
        if (isSimpleMode) {
             return (
                <div className="p-4 space-y-4">
                    <SettingsPanel onExportProject={onExportProject} onExportTxt={onExportTxt} />
                    <CharacterListPanel isMobile={isMobile} />
                    <WorldListPanel isMobile={isMobile} />
                </div>
            );
        }

        const currentTabId = userMode === 'simple' ? 'settings' : leftPanelTab;

        switch (currentTabId) {
            case 'settings': return <SettingsPanel onExportProject={onExportProject} onExportTxt={onExportTxt} />;
            case 'characters': return <CharacterListPanel isMobile={isMobile} />;
            case 'worlds': return <WorldListPanel isMobile={isMobile} />;
            case 'knowledge': return <KnowledgeListPanel isMobile={isMobile} />;
            case 'plots': return <PlotListPanel isMobile={isMobile} />;
            case 'outline': return <OutlinePanel isMobile={isMobile} />;
            default: return null;
        }
    };

    const tabs: { id: LeftPanelTab; icon: React.ReactNode; label: string; }[] = [
        { id: 'settings', icon: <Icons.SettingsIcon />, label: '設定' },
        { id: 'characters', icon: <Icons.UserPlusIcon />, label: 'キャラ' },
        { id: 'worlds', icon: <Icons.GlobeIcon />, label: '世界観' },
        { id: 'knowledge', icon: <Icons.LightbulbIcon />, label: 'ナレッジ' },
        { id: 'plots', icon: <Icons.ClipboardListIcon />, label: 'プロット' },
        { id: 'outline', icon: <Icons.ListOrderedIcon />, label: '構成' },
    ];

    return (
        <div
            className={`flex-shrink-0 bg-gray-800 flex flex-col ${resizeTransitionClass} border-r border-gray-700/50`}
            style={widthStyle}
            id="tutorial-left-panel"
        >
            {isMobile && (
                <div className="flex items-center justify-between p-2 bg-gray-900 border-b border-gray-700/50">
                     <h3 className="text-sm font-bold text-gray-300 ml-2">設定・ツール</h3>
                     <button 
                        onClick={() => setIsLeftSidebarOpen(false)}
                        className="p-2 text-gray-400 hover:text-white"
                    >
                        <Icons.XIcon className="h-5 w-5" />
                    </button>
                </div>
            )}

            {isMobile && !isSimpleMode && userMode !== 'simple' && (
                <div className="flex overflow-x-auto bg-gray-900 border-b border-gray-700/50 no-scrollbar flex-shrink-0">
                    {tabs.map(tab => (
                         <button
                            key={tab.id}
                            onClick={() => setLeftPanelTab(tab.id)}
                            className={`flex-shrink-0 flex flex-col items-center justify-center px-4 py-2 text-xs min-w-[60px] ${leftPanelTab === tab.id ? 'text-indigo-400 border-b-2 border-indigo-400 bg-gray-800' : 'text-gray-400 hover:text-gray-200 hover:bg-gray-800'}`}
                        >
                            {React.cloneElement<any>(tab.icon as React.ReactElement, { className: 'h-5 w-5 mb-1' })}
                            <span>{tab.label}</span>
                        </button>
                    ))}
                </div>
            )}

            <div className="flex-grow flex flex-col overflow-hidden">
                {!isMobile && (
                    <div className="p-4 border-b border-gray-700/50 flex flex-col gap-4">
                        <div className="flex justify-between items-center">
                            <Tooltip helpId="settings">
                                <button onClick={() => setActiveProjectId(null)} className="flex items-center text-sm text-gray-300 hover:text-white transition btn-pressable">
                                    <Icons.ArrowLeftIcon />
                                    プロジェクト一覧へ
                                </button>
                            </Tooltip>
                            <SaveStatusIndicator status={saveStatus} />
                        </div>
                    </div>
                )}
                <div className="flex-grow overflow-y-auto pb-20 sm:pb-0">
                    {renderContent()}
                    {isMobile && (
                         <div 
                            className="p-4 mt-4 border-t border-gray-700"
                            style={{ paddingBottom: 'calc(1rem + env(safe-area-inset-bottom))' }}
                         >
                            <button onClick={() => setActiveProjectId(null)} className="w-full flex items-center gap-2 px-3 py-2 text-sm bg-gray-700 hover:bg-gray-600 text-gray-300 rounded-md transition btn-pressable">
                                <Icons.ArrowLeftIcon className="h-4 w-4"/>
                                <span>プロジェクト一覧へ</span>
                            </button>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import * as Icons from '../icons';
import { useStore } from '../store/index';
import { EditableParagraph } from './EditableParagraph';
import { TextSelectionToolbar } from './TextSelectionToolbar';
import { NovelChunk } from '../types';
import { FONT_MAP, defaultDisplaySettings } from '../constants';
import { Tooltip } from './Tooltip';

export const NovelEditor: React.FC = () => {
    const activeProjectId = useStore(state => state.activeProjectId);
    const activeProjectData = useStore(state => state.allProjectsData[activeProjectId]);

    if (!activeProjectData) return null;

    const { novelContent, settings, knowledgeBase, displaySettings: projectDisplaySettings } = activeProjectData;
    const displaySettings = projectDisplaySettings || defaultDisplaySettings;

    const highlightedChunkId = useStore(state => state.highlightedChunkId);
    const editingChunkId = useStore(state => state.editingChunkId);
    const newChunkText = useStore(state => state.newChunkText);
    const isNewChunkInputOpen = useStore(state => state.isNewChunkInputOpen);

    const setEditingChunkId = useStore(state => state.setEditingChunkId);
    const handleNovelTextChange = useStore(state => state.handleNovelTextChange);
    const handleToggleChunkPin = useStore(state => state.handleToggleChunkPin);
    const setNewChunkText = useStore(state => state.setNewChunkText);
    const setIsNewChunkInputOpen = useStore(state => state.setIsNewChunkInputOpen);
    const handleAddNewChunk = useStore(state => state.handleAddNewChunk);
    const setUserInput = useStore(state => state.setUserInput);
    const setIsRightSidebarOpen = useStore(state => state.setIsRightSidebarOpen);

    const novelContentRef = useRef<HTMLDivElement>(null);
    const newChunkTextareaRef = useRef<HTMLTextAreaElement>(null);
    const isMac = useMemo(() => navigator.platform.toUpperCase().indexOf('MAC') >= 0, []);
    const modifierKeyText = isMac ? '⌘Cmd' : 'Ctrl';

    const [selectionToolbar, setSelectionToolbar] = useState<{ top: number; left: number } | null>(null);
    const selectionRef = useRef({ text: '', range: null });

    useEffect(() => {
        if (newChunkTextareaRef.current) {
            newChunkTextareaRef.current.style.height = 'auto';
            const scrollHeight = newChunkTextareaRef.current.scrollHeight;
            newChunkTextareaRef.current.style.height = `${scrollHeight}px`;
        }
    }, [newChunkText]);

    useEffect(() => {
        if (editingChunkId) {
            document.getElementById(`chunk-${editingChunkId}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
    }, [editingChunkId]);

    useEffect(() => {
        const handleSelectionChange = () => {
            const selection = window.getSelection();
            if (selection && selection.rangeCount > 0) {
                const range = selection.getRangeAt(0);
                const text = selection.toString().trim();

                if (text && novelContentRef.current?.contains(range.commonAncestorContainer)) {
                    selectionRef.current = { text, range };
                    const rect = range.getBoundingClientRect();
                    const editorRect = novelContentRef.current.getBoundingClientRect();
                    setSelectionToolbar({
                        top: rect.top - editorRect.top - 40,
                        left: rect.left - editorRect.left + rect.width / 2,
                    });
                } else {
                    setSelectionToolbar(null);
                    selectionRef.current = { text: '', range: null };
                }
            }
        };

        const editorElement = novelContentRef.current;
        if (editorElement) {
            document.addEventListener('selectionchange', handleSelectionChange);
            editorElement.addEventListener('mousedown', () => setSelectionToolbar(null));
        }
        return () => {
            document.removeEventListener('selectionchange', handleSelectionChange);
            if (editorElement) {
                editorElement.removeEventListener('mousedown', () => setSelectionToolbar(null));
            }
        };
    }, []);

    const handleToolbarAction = (actionType: 'proofread' | 'summarize' | 'poetic' | 'dialogue') => {
        const selectedText = selectionRef.current.text;
        if (!selectedText) return;

        let prompt = '';
        switch (actionType) {
            case 'proofread':
                prompt = `以下の文章の誤字脱字や文法的な誤りを修正してください。:\n\n「${selectedText}」`;
                break;
            case 'summarize':
                prompt = `以下の文章を簡潔に要約してください。:\n\n「${selectedText}」`;
                break;
            case 'poetic':
                prompt = `以下の文章を、より詩的で感情豊かな表現に書き換えてください。:\n\n「${selectedText}」`;
                break;
            case 'dialogue':
                prompt = `以下の地の文を、キャラクターの会話文に変換してください。:\n\n「${selectedText}」`;
                break;
        }

        setUserInput(prompt);
        setIsRightSidebarOpen(true);
        setSelectionToolbar(null);
        window.getSelection()?.removeAllRanges();
    };

    const chapters = useMemo(() => {
        if (!novelContent) return [];
        const result: { id: string; title: string; memo?: string; chunks: NovelChunk[] }[] = [];
        let currentChapterChunks: NovelChunk[] = [];

        const extractTitleFromChunkText = (chunkText: string) => {
            if (!chunkText.startsWith('# ')) return '';
            const firstLine = chunkText.split('\n')[0];
            return firstLine.substring(2).trim();
        };

        novelContent.forEach((chunk) => {
            const isTitle = chunk.text.startsWith('# ');
            if (isTitle) {
                if (currentChapterChunks.length > 0) {
                    const firstChunkOfPreviousBlock = currentChapterChunks[0];
                    const isPreviousBlockTitled = firstChunkOfPreviousBlock.text.startsWith('# ');

                    if (isPreviousBlockTitled) {
                        result.push({ id: firstChunkOfPreviousBlock.id, title: extractTitleFromChunkText(firstChunkOfPreviousBlock.text) || '無題の章', memo: firstChunkOfPreviousBlock.memo, chunks: currentChapterChunks });
                    } else {
                        result.push({ id: firstChunkOfPreviousBlock.id, title: '章に属さない文章', chunks: currentChapterChunks });
                    }
                }
                currentChapterChunks = [chunk];
            } else {
                currentChapterChunks.push(chunk);
            }
        });

        if (currentChapterChunks.length > 0) {
            const firstChunk = currentChapterChunks[0];
            const isTitled = firstChunk.text.startsWith('# ');
            result.push({ id: firstChunk.id, title: isTitled ? (extractTitleFromChunkText(firstChunk.text) || '無題の章') : '章に属さない文章', memo: isTitled ? firstChunk.memo : undefined, chunks: currentChapterChunks });
        }

        return result;
    }, [novelContent]);

    const handleNewChunkKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
        if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
            e.preventDefault();
            if (newChunkText.trim()) {
                handleAddNewChunk();
            }
        }
    };

    const themes = { light: { bg: 'bg-white', text: 'text-gray-800', prose: '' }, sepia: { bg: 'bg-[#fbf0d9]', text: 'text-[#5b4636]', prose: 'prose-sepia' }, dark: { bg: 'bg-gray-800', text: 'text-gray-200', prose: 'prose-invert' } };
    const contentStyles = { fontFamily: FONT_MAP[displaySettings.fontFamily] || FONT_MAP['sans'], fontSize: `${displaySettings.fontSize}px`, lineHeight: 1.8 };
    const proseClasses = ['prose', 'prose-lg', 'max-w-full', (themes[displaySettings.theme] || themes.light).prose].filter(Boolean).join(' ');
    const themeClass = themes[displaySettings?.theme] || themes.light;
    const newChunkInputTextColor = {
        light: 'black',
        sepia: '#555555',
        dark: '#d1d5db',
    }[displaySettings.theme] || 'black';

    return (
        <>
            <Tooltip helpId="editor_main">
                <div
                    id="novel-editor-content"
                    tabIndex={-1}
                    ref={novelContentRef}
                    className={`flex-1 p-6 overflow-y-auto min-h-0 transition-colors duration-300 ${themeClass.bg} ${themeClass.text} focus:outline-none focus:ring-2 focus:ring-indigo-500 relative`}
                    data-tutorial-id="tutorial-center-panel"
                >
                    {selectionToolbar && <TextSelectionToolbar position={selectionToolbar} onAction={handleToolbarAction} />}
                    <div className={proseClasses}>
                        {chapters.map(chapter => (
                            <div key={chapter.id} id={`chapter-scroll-${chapter.id}`} className="chapter-group">
                                {chapter.chunks.map(chunk => (
                                    <EditableParagraph key={chunk.id} chunk={chunk} characters={settings.filter(s => s.type === 'character')} knowledgeBase={knowledgeBase} onTextChange={handleNovelTextChange} onTogglePin={handleToggleChunkPin} isHighlighted={chunk.id === highlightedChunkId} isEditing={chunk.id === editingChunkId} onStartEdit={() => setEditingChunkId(chunk.id)} onEndEdit={() => setEditingChunkId(null)} scrollContainerRef={novelContentRef} />
                                ))}
                            </div>
                        ))}
                        {novelContent.length === 0 && <p className="text-gray-500">ここに物語が生成されます...</p>}
                    </div>
                </div>
            </Tooltip>
            <div 
                className={`border-t border-gray-700/50 flex-shrink-0 ${themeClass.bg}`}
                style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}
            >
                <div className="group flex justify-between items-center p-2 cursor-pointer hover:bg-gray-700" onClick={() => setIsNewChunkInputOpen(p => !p)} aria-expanded={isNewChunkInputOpen} aria-controls="new-chunk-panel">
                    <h3 className="text-sm font-semibold text-gray-400 group-hover:text-white transition-colors">本文を直接入力</h3>
                    <button className="p-1 text-gray-400 group-hover:text-white transition-colors btn-pressable" aria-label={isNewChunkInputOpen ? '入力を閉じる' : '入力を開く'}>{isNewChunkInputOpen ? <Icons.ChevronDownIcon className="h-5 w-5" /> : <Icons.ChevronUpIcon className="h-5 w-5" />}</button>
                </div>
                <div id="new-chunk-panel" className={`transition-all duration-300 ease-in-out overflow-hidden ${isNewChunkInputOpen ? 'max-h-96' : 'max-h-0'}`}>
                    <div className="p-4 pt-0">
                        <textarea
                            ref={newChunkTextareaRef}
                            value={newChunkText}
                            onChange={(e) => setNewChunkText(e.target.value)}
                            onKeyDown={handleNewChunkKeyDown}
                            placeholder="ここに新しい段落を直接入力できます..."
                            className={`w-full border rounded-md p-3 focus:ring-indigo-500 focus:border-indigo-500 resize-none transition-colors duration-300`}
                            style={{ ...contentStyles, color: newChunkInputTextColor, backgroundColor: 'rgba(128, 128, 128, 0.1)' }}
                            rows={3}
                        />
                        <div className="flex justify-end mt-2"><button onClick={handleAddNewChunk} disabled={!newChunkText.trim()} className="px-4 py-2 text-sm rounded-md disabled:bg-gray-500 btn-pressable btn-invert-indigo">本文に追加 <span className="text-xs opacity-80 ml-1">({modifierKeyText}+Enterで追加)</span></button></div>
                    </div>
                </div>
            </div>
        </>
    );
};

import React, { useMemo } from 'react';
import * as Icons from '../../icons';
import { useStore } from '../../store/index';
import { Tooltip } from '../Tooltip';

interface SettingsPanelProps {
    onExportProject: () => void;
    onExportTxt: () => void;
}

export const SettingsPanel: React.FC<SettingsPanelProps> = ({ onExportProject, onExportTxt }) => {
    const { openModal, userMode } = useStore(state => ({
        openModal: state.openModal,
        userMode: state.userMode,
    }));

    const tools = useMemo(() => [
        { label: '相関図', icon: <Icons.UserCogIcon />, action: () => openModal('characterChart'), color: 'text-violet-300', helpId: 'chart_open' },
        { label: 'タイムライン', icon: <Icons.ClockIcon />, action: () => openModal('timeline'), color: 'text-orange-300' },
        { label: '固有名詞生成', icon: <Icons.DiceIcon />, action: () => openModal('nameGenerator'), color: 'text-teal-300' },
    ], [openModal]);

    const exports = [
        { label: 'プロジェクト(.json)', icon: <Icons.FileCodeIcon />, action: onExportProject },
        { label: 'テキスト(.txt)', icon: <Icons.FileTextIcon />, action: onExportTxt },
        { label: '装飾付き(.html)', icon: <Icons.ImageIcon />, action: () => openModal('htmlExport') },
    ];

    const visibleTools = useMemo(() => {
        if (userMode === 'simple') return [];
        return tools;
    }, [userMode, tools]);

    return (
        <div className="p-4 space-y-6">
            <div>
                <h3 className="text-sm font-semibold text-gray-400 mb-2">設定</h3>
                <button onClick={() => openModal('aiSettings')} className="w-full flex items-center justify-center gap-2 px-4 py-2 bg-indigo-600/80 rounded-md hover:bg-indigo-600 transition font-semibold btn-pressable text-white">
                    <Icons.SettingsIcon /> プロジェクト設定
                </button>
            </div>

            {visibleTools.length > 0 && (
                <div>
                    <h3 className="text-sm font-semibold text-gray-400 mb-2">ツール</h3>
                    <div className="space-y-2">
                        {visibleTools.map(tool => (
                            <Tooltip key={tool.label} helpId={tool.helpId || ''}>
                                <button onClick={tool.action} className={`w-full text-sm px-3 py-2 bg-gray-700 hover:bg-gray-600 rounded-md transition flex items-center gap-2 btn-pressable ${tool.color}`}>
                                    {React.cloneElement<any>(tool.icon as React.ReactElement, { className: 'h-5 w-5 flex-shrink-0' })}
                                    <span>{tool.label}</span>
                                </button>
                            </Tooltip>
                        ))}
                    </div>
                </div>
            )}

            <div>
                <h3 className="text-sm font-semibold text-gray-400 mb-2">書き出し</h3>
                <div className="space-y-2">
                    {exports.map(exp => (
                        <button key={exp.label} onClick={exp.action} className="w-full text-sm px-3 py-2 bg-gray-700 hover:bg-gray-600 rounded-md transition flex items-center gap-2 btn-pressable text-gray-300">
                             {React.cloneElement<any>(exp.icon as React.ReactElement, { className: 'h-4 w-4 mr-1 flex-shrink-0' })}
                            <span>{exp.label}</span>
                        </button>
                    ))}
                </div>
            </div>
        </div>
    );
};

import React, { useState } from 'react';
import * as Icons from '../../icons';
import { useStore } from '../../store/index';
import { Tooltip } from '../Tooltip';

export const PlotListPanel = ({ isFloating = false, isMobile = false }) => {
    const { plotBoard, plotTypeColors, openModal, handleDeleteSetting, addFloatingWindow } = useStore(state => {
        const activeProject = state.allProjectsData?.[state.activeProjectId];
        return {
            plotBoard: activeProject?.plotBoard || [],
            plotTypeColors: activeProject?.plotTypeColors || {},
            openModal: state.openModal,
            handleDeleteSetting: state.handleDeleteSetting,
            addFloatingWindow: state.addFloatingWindow,
        };
    });

    const [deletingId, setDeletingId] = useState<string | null>(null);

    const plotsToShow = React.useMemo(() => {
        return [...plotBoard].reverse().slice(0, 15);
    }, [plotBoard]);

    const initiateDelete = (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        setDeletingId(id);
    };

    const confirmDelete = (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        handleDeleteSetting(id, 'plot', true);
        setDeletingId(null);
    };

    const cancelDelete = (e: React.MouseEvent) => {
        e.stopPropagation();
        setDeletingId(null);
    };

    return (
        <div className="flex flex-col h-full">
            {!isFloating && (
                <div className="p-2 border-b border-gray-700/50 flex justify-between items-center">
                    <h3 className="text-sm font-semibold text-cyan-300 flex items-center gap-2">
                        <Icons.ClipboardListIcon className="h-4 w-4" />
                        プロットボード
                    </h3>
                    <div className="flex items-center">
                        {!isMobile && (
                            <button
                                onClick={() => addFloatingWindow('plots')}
                                className="p-1 rounded-full text-gray-400 hover:text-white hover:bg-gray-700 btn-pressable"
                                title="ウィンドウ化"
                            >
                                <Icons.ExternalLinkIcon className="h-4 w-4" />
                            </button>
                        )}
                        <Tooltip helpId="plot_plus">
                            <button onClick={() => openModal('plot')} className="p-1 rounded-full text-cyan-300 hover:bg-cyan-500/20 btn-pressable" title="新規カード作成"><Icons.PlusCircleIcon /></button>
                        </Tooltip>
                    </div>
                </div>
            )}
            <div className="flex-grow overflow-y-auto p-2 space-y-2">
                {plotsToShow.map(p => {
                    const color = plotTypeColors[p.type] || '#6b7280';
                    return (
                        <div key={p.id} className={`p-2 rounded-lg ${deletingId === p.id ? 'bg-red-900/20 border border-red-500' : 'bg-gray-800/50'}`} style={deletingId !== p.id ? { borderLeft: `3px solid ${color}` } : {}}>
                            <div className="flex justify-between items-start">
                                <p className="font-bold text-sm text-cyan-400 truncate">{p.title}</p>
                                <div className="flex gap-1 flex-shrink-0">
                                    {deletingId === p.id ? (
                                        <div className="flex items-center gap-1 animate-fade-in">
                                            <span className="text-xs text-red-300 font-bold mr-1">削除?</span>
                                            <button onClick={(e) => confirmDelete(e, p.id)} className="px-2 py-1 text-xs bg-red-600 text-white rounded hover:bg-red-500 shadow-md">はい</button>
                                            <button onClick={cancelDelete} className="px-2 py-1 text-xs bg-gray-600 text-white rounded hover:bg-gray-500 shadow-md">いいえ</button>
                                        </div>
                                    ) : (
                                        <>
                                            <button onClick={() => openModal('plot', p)} className="p-1 text-gray-400 hover:text-yellow-400 btn-pressable flex-shrink-0" title="編集"><Icons.EditIcon /></button>
                                            <button onClick={(e) => initiateDelete(e, p.id)} className="p-1 text-gray-400 hover:text-red-400 btn-pressable flex-shrink-0" title="削除"><Icons.TrashIcon /></button>
                                        </>
                                    )}
                                </div>
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

