import React, { useEffect } from 'react';
// FIX: The file 'store.ts' does not exist, changed import to 'store/index.ts'.
import { useStore } from '../store/index';
import { ModalType } from '../types';

interface UseKeybindingsProps {
    isAnyModalOpen: boolean;
    editingChunkId: string | null;
    openModal: (type: ModalType, payload?: any) => void;
    setIsLeftSidebarOpen: (update: (prev: boolean) => boolean) => void;
    setIsRightSidebarOpen: (update: (prev: boolean) => boolean) => void;
    userInputRef: React.RefObject<HTMLTextAreaElement>;
    generationMode: 'write' | 'consult';
    setGenerationMode: (mode: 'write' | 'consult') => void;
    undo: () => void;
    redo: () => void;
    novelContent: any[]; // Simplified type for dependency
    setEditingChunkId: (id: string | null) => void;
}

export const useKeybindings = ({
    isAnyModalOpen,
    editingChunkId,
    openModal,
    setIsLeftSidebarOpen,
    setIsRightSidebarOpen,
    userInputRef,
    generationMode,
    setGenerationMode,
    undo,
    redo,
    novelContent,
    setEditingChunkId
}: UseKeybindingsProps) => {
    useEffect(() => {
        const handleGlobalKeyDown = (e: KeyboardEvent) => {
            const activeEl = document.activeElement;
            const isInputFocused = activeEl && (activeEl.tagName === 'INPUT' || activeEl.tagName === 'TEXTAREA' || (activeEl as HTMLElement).isContentEditable);
            const isMac = navigator.platform.toUpperCase().indexOf('MAC') >= 0;
            const isCtrlOrCmd = isMac ? e.metaKey : e.ctrlKey;

            if (isCtrlOrCmd && e.altKey && (e.key === 'ArrowUp' || e.key === 'ArrowDown')) {
                e.preventDefault();
                const editor = document.getElementById('novel-editor-content');
                if (!editor) return;

                const chapterElements = Array.from(editor.querySelectorAll('[id^="chapter-scroll-"]'));
                if (chapterElements.length < 2) return;

                const viewportCenter = editor.getBoundingClientRect().top + editor.clientHeight / 2;

                let closestChapterIndex = -1;
                let minDistance = Infinity;

                chapterElements.forEach((el, index) => {
                    const distance = Math.abs(el.getBoundingClientRect().top - viewportCenter);
                    if (distance < minDistance) {
                        minDistance = distance;
                        closestChapterIndex = index;
                    }
                });

                if (closestChapterIndex !== -1) {
                    if (e.key === 'ArrowDown') {
                        const nextIndex = closestChapterIndex + 1;
                        if (nextIndex < chapterElements.length) {
                            chapterElements[nextIndex].scrollIntoView({ behavior: 'smooth', block: 'start' });
                        }
                    } else { // ArrowUp
                        const prevIndex = closestChapterIndex - 1;
                        if (prevIndex >= 0) {
                            chapterElements[prevIndex].scrollIntoView({ behavior: 'smooth', block: 'start' });
                        }
                    }
                }
                return;
            }

            if (isCtrlOrCmd) {
                 if (e.key === 'z' && !e.shiftKey) { e.preventDefault(); undo(); return; }
                 if (e.key === 'y' || (e.key === 'z' && e.shiftKey)) { e.preventDefault(); redo(); return; }
                 if (e.key === 'f') { e.preventDefault(); openModal('globalSearch'); return; }
                 if (e.key === 'k') { e.preventDefault(); openModal('commandPalette'); return; }
                if (e.key === 's') {
                    if (e.altKey) {
                        e.preventDefault();
                        openModal('aiSettings');
                        return;
                    }
                    e.preventDefault();
                    document.querySelector<HTMLButtonElement>('[data-testid="modal-save-button"]')?.click();
                    return;
                }
                if (e.shiftKey) {
                    switch (e.key.toLowerCase()) {
                        case 'm':
                            e.preventDefault();
                            setGenerationMode(generationMode === 'write' ? 'consult' : 'write');
                            break;
                        case 'c':
                            e.preventDefault();
                            openModal('characterChart');
                            break;
                        case 't':
                            e.preventDefault();
                            openModal('timeline');
                            break;
                        case 'p':
                             e.preventDefault();
                             openModal('plot');
                             break;
                        case 'g':
                             e.preventDefault();
                             openModal('nameGenerator');
                             break;
                        case 'k':
                             e.preventDefault();
                             openModal('knowledgeBase');
                             break;
                    }
                    return;
                }

                if (!isInputFocused) {
                    switch(e.key) {
                        case '1':
                            e.preventDefault();
                            (document.querySelector('#tutorial-left-panel button, #tutorial-left-panel a') as HTMLElement)?.focus();
                            break;
                        case '2':
                            e.preventDefault();
                            (document.getElementById('novel-editor-content') as HTMLElement)?.focus();
                            break;
                        case '3':
                            e.preventDefault();
                            userInputRef.current?.focus();
                            break;
                        case 'i':
                            if (e.altKey) {
                                e.preventDefault();
                                useStore.getState().setIsNewChunkInputOpen(p => !p);
                            }
                            break;
                        case 'c': if (e.altKey) { e.preventDefault(); openModal('character'); } break;
                        case 'w': if (e.altKey) { e.preventDefault(); openModal('world'); } break;
                        case 'k': if (e.altKey && !isCtrlOrCmd) { e.preventDefault(); openModal('knowledge'); } break; // Ensure it doesn't conflict with Cmd+K
                        case '[': e.preventDefault(); setIsLeftSidebarOpen(p => !p); break;
                        case ']': e.preventDefault(); setIsRightSidebarOpen(p => !p); break;
                        case '/': 
                            if (userInputRef && userInputRef.current) {
                                e.preventDefault();
                                userInputRef.current.focus();
                            }
                            break;
                    }
                }
            }

            if (e.key === 'ArrowUp' && !isInputFocused) {
                if (isAnyModalOpen || editingChunkId) return;
                e.preventDefault();
                if (novelContent && novelContent.length > 0) {
                    const lastChunk = novelContent[novelContent.length - 1];
                    if (lastChunk) {
                        setEditingChunkId(lastChunk.id);
                        document.getElementById(`chunk-${lastChunk.id}`)?.scrollIntoView({ behavior: 'smooth', block: 'start' });
                    }
                }
            }
        };
        window.addEventListener('keydown', handleGlobalKeyDown);
        return () => window.removeEventListener('keydown', handleGlobalKeyDown);
    }, [isAnyModalOpen, editingChunkId, openModal, setEditingChunkId, undo, redo, novelContent, userInputRef, generationMode, setGenerationMode, setIsLeftSidebarOpen, setIsRightSidebarOpen]);
};

import React, { useState, useEffect, useRef, useLayoutEffect, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { NovelChunk, SettingItem, KnowledgeItem, AiSettings } from '../types';
import { parseMarkdown } from '../utils';
import * as Icons from '../icons';
import { useStore } from '../store/index';
import { Tooltip } from './Tooltip';

// 執筆の世界観に合うプリセットカラー
const PRESET_COLORS = [
    '#ef4444', '#f97316', '#f59e0b', '#10b981', '#0ea5e9', 
    '#6366f1', '#a855f7', '#ec4899', '#94a3b8', '#ffffff'
];

interface EditableParagraphProps {
    chunk: NovelChunk;
    characters: SettingItem[];
    knowledgeBase: KnowledgeItem[];
    onTextChange: (chunkId: string, newText: string) => void;
    onTogglePin: (chunkId: string) => void;
    isHighlighted: boolean;
    isEditing: boolean;
    onStartEdit: () => void;
    onEndEdit: () => void;
    scrollContainerRef: React.RefObject<HTMLDivElement>;
}

export const EditableParagraph: React.FC<EditableParagraphProps> = ({
    chunk, characters, knowledgeBase, onTextChange, onTogglePin, isHighlighted, isEditing, onStartEdit, onEndEdit, scrollContainerRef
}) => {
    const [editText, setEditText] = useState(chunk.text);
    const [brushColor, setBrushColor] = useState('#ef4444');
    const [isColorPaletteOpen, setIsColorPaletteOpen] = useState(false);
    const [isApplyPulseActive, setIsApplyPulseActive] = useState(false);
    const [palettePos, setPalettePos] = useState<{ top: number; left: number } | null>(null);

    // パレット制御用のRef
    const colorPaletteRef = useRef<HTMLDivElement>(null);
    const paletteButtonRef = useRef<HTMLButtonElement>(null);
    const textareaRef = useRef<HTMLTextAreaElement>(null);
    const wrapperRef = useRef<HTMLDivElement>(null);

    // 選択範囲を保持するためのRef
    const selectionRef = useRef({ start: 0, end: 0 });

    const aiSettings = useStore(state => state.allProjectsData[state.activeProjectId]?.aiSettings);

    const isMac = useMemo(() => navigator.platform.toUpperCase().indexOf('MAC') >= 0, []);
    const modifierKeyText = isMac ? '⌘Cmd' : 'Ctrl';

    const scrollCorrectionData = useRef<{ top: number } | null>(null);
    const [isAwaitingCorrection, setIsAwaitingCorrection] = useState(false);

    // 選択範囲が変更されたら保存しておく
    const syncSelection = () => {
        if (textareaRef.current) {
            selectionRef.current = {
                start: textareaRef.current.selectionStart,
                end: textareaRef.current.selectionEnd
            };
        }
    };

    // パレットの位置計算と外側クリック検知
    useLayoutEffect(() => {
        if (!isColorPaletteOpen) {
            setPalettePos(null);
            return;
        }

        const updatePosition = () => {
            if (paletteButtonRef.current) {
                const rect = paletteButtonRef.current.getBoundingClientRect();
                setPalettePos({
                    top: rect.bottom + window.scrollY,
                    left: rect.left + window.scrollX
                });
            }
        };

        updatePosition();
        window.addEventListener('scroll', updatePosition, true);
        window.addEventListener('resize', updatePosition);

        const handleClickOutside = (event: MouseEvent) => {
            const target = event.target as Node;
            if (
                colorPaletteRef.current && !colorPaletteRef.current.contains(target) &&
                paletteButtonRef.current && !paletteButtonRef.current.contains(target)
            ) {
                setIsColorPaletteOpen(false);
                setIsApplyPulseActive(false);
            }
        };

        document.addEventListener('mousedown', handleClickOutside);
        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
            window.removeEventListener('scroll', updatePosition, true);
            window.removeEventListener('resize', updatePosition);
        };
    }, [isColorPaletteOpen]);

    useEffect(() => {
        if (isEditing) {
            setEditText(chunk.text);
            setTimeout(() => {
                if (textareaRef.current) {
                    textareaRef.current.focus({ preventScroll: true });
                    textareaRef.current.style.height = 'auto';
                    textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`;
                    syncSelection();
                }
            }, 0);
        } else {
            setIsColorPaletteOpen(false);
            setIsApplyPulseActive(false);
        }
    }, [isEditing, chunk.text]);

    useEffect(() => {
        if (isHighlighted && wrapperRef.current) {
            wrapperRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
    }, [isHighlighted]);

    const measureAndStorePosition = () => {
        const container = scrollContainerRef.current;
        if (container && wrapperRef.current) {
            const containerRect = container.getBoundingClientRect();
            const elementRect = wrapperRef.current.getBoundingClientRect();
            const top = elementRect.top - containerRect.top;
            scrollCorrectionData.current = { top };
        }
    };

    useLayoutEffect(() => {
        if (isAwaitingCorrection && scrollCorrectionData.current !== null) {
            const container = scrollContainerRef.current;
            if (container && wrapperRef.current) {
                const containerRect = container.getBoundingClientRect();
                const newRect = wrapperRef.current.getBoundingClientRect();
                const newTop = newRect.top - containerRect.top;
                const oldTop = scrollCorrectionData.current.top;
                const delta = newTop - oldTop;
                if (Math.abs(delta) > 1) {
                    container.scrollTop += delta;
                }
            }
            scrollCorrectionData.current = null;
            setIsAwaitingCorrection(false);
        }
    }, [isAwaitingCorrection, chunk.text]);

    const handleSave = () => {
        measureAndStorePosition();
        setIsAwaitingCorrection(true);
        onTextChange(chunk.id, editText);
        onEndEdit();
    };

    const handleCancel = () => {
        measureAndStorePosition();
        setIsAwaitingCorrection(true);
        onEndEdit();
    };

    const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
        if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) { e.preventDefault(); handleSave(); }
        if (e.key === 'Escape') { e.preventDefault(); handleCancel(); }
        if ((e.ctrlKey || e.metaKey)) {
            switch (e.key) {
                case 'b': e.preventDefault(); applyMarkdown('**'); break;
                case 'u': e.preventDefault(); applyMarkdown('__'); break;
                case 'h': e.preventDefault(); applyMarkdown('# '); break;
                case 'r': e.preventDefault(); applyMarkdown('{', '|ふりがな}'); break;
                case 'c': if(e.shiftKey) { e.preventDefault(); applyMarkdown(`<c:${brushColor}>`, '</c>', 'テキスト', true); } break;
                default: break;
            }
        }
    };

    const applyMarkdown = (prefix: string, suffix: string = prefix, placeholder: string = 'テキスト', shouldClearSelection: boolean = false) => {
        if (!textareaRef.current) return;

        // Refから保存済みの選択範囲を取得
        const { start, end } = selectionRef.current;

        setEditText(prev => {
            const selectedText = prev.substring(start, end);
            const newText = selectedText || placeholder;
            const replacement = `${prefix}${newText}${suffix}`;
            const newEditText = prev.substring(0, start) + replacement + prev.substring(end);

            // ステート反映後のカーソル制御
            setTimeout(() => {
                if (!textareaRef.current) return;
                textareaRef.current.focus({ preventScroll: true });

                if (shouldClearSelection) {
                    const newPos = start + replacement.length;
                    textareaRef.current.setSelectionRange(newPos, newPos);
                    window.getSelection()?.removeAllRanges();
                } else if (selectedText) {
                    textareaRef.current.setSelectionRange(start + prefix.length, end + prefix.length);
                } else {
                    textareaRef.current.setSelectionRange(start + prefix.length, start + prefix.length + placeholder.length);
                }
                syncSelection();
            }, 0);

            return newEditText;
        });
    };

    const wrapperClassName = `relative group transition-all duration-300 ${isHighlighted ? 'bg-indigo-500/10' : ''} ${chunk.isPinned ? 'bg-yellow-500/10' : ''} rounded-md my-4`;

    // 共通のボタンMouseDownイベント（フォーカス奪取防止）
    const preventFocusLoss = (e: React.MouseEvent) => e.preventDefault();

    return (
        <div ref={wrapperRef} id={`chunk-${chunk.id}`} className={wrapperClassName}>
            {isEditing ? (
                <div className="bg-gray-800 border-2 border-indigo-500 rounded-md flex flex-col shadow-lg overflow-hidden">
                    <div className="sticky-toolbar bg-gray-700/90 backdrop-blur-sm">
                         <div className="p-2 flex gap-1 border-b border-gray-600 items-center">
                            <button onMouseDown={preventFocusLoss} onClick={() => applyMarkdown('**')} className="p-1.5 text-gray-300 hover:text-white hover:bg-gray-600 rounded transition-colors"><Icons.BoldIcon className="h-4 w-4" /></button>
                            <button onMouseDown={preventFocusLoss} onClick={() => applyMarkdown('__')} className="p-1.5 text-gray-300 hover:text-white hover:bg-gray-600 rounded transition-colors"><Icons.UnderlineIcon className="h-4 w-4" /></button>
                            <button onMouseDown={preventFocusLoss} onClick={() => applyMarkdown('# ')} className="p-1.5 text-gray-300 hover:text-white hover:bg-gray-600 rounded transition-colors"><Icons.TypeIcon className="h-4 w-4" /></button>
                            <button onMouseDown={preventFocusLoss} onClick={() => applyMarkdown('{', '|ふりがな}')} className="p-1.5 text-gray-300 hover:text-white hover:bg-gray-600 rounded font-bold text-xs px-2">ルビ</button>

                            <div className="w-px h-4 bg-gray-600 mx-1" />

                            <div className="relative flex items-center">
                                <div className="flex items-center gap-0.5 bg-gray-800/50 rounded-md p-0.5 border border-gray-600/50">
                                    <button 
                                        onMouseDown={preventFocusLoss}
                                        onClick={() => {
                                            applyMarkdown(`<c:${brushColor}>`, '</c>', 'テキスト', true);
                                            setIsApplyPulseActive(false);
                                        }} 
                                        className={`p-1.5 rounded hover:bg-gray-600 transition-all duration-300 flex items-center justify-center ${isApplyPulseActive ? 'animate-pulse-prompt' : ''}`}
                                        style={{ color: brushColor }}
                                    >
                                        <Icons.PaletteIcon className="h-4 w-4 drop-shadow-[0_0_2px_rgba(0,0,0,0.5)]" />
                                    </button>
                                    <button 
                                        ref={paletteButtonRef}
                                        onMouseDown={preventFocusLoss}
                                        onClick={() => {
                                            setIsColorPaletteOpen(!isColorPaletteOpen);
                                            if (isColorPaletteOpen) setIsApplyPulseActive(false);
                                        }}
                                        className="p-1 text-gray-400 hover:text-white transition-colors"
                                    >
                                        <Icons.ChevronDownIcon className={`h-3 w-3 transition-transform duration-200 ${isColorPaletteOpen ? 'rotate-180' : ''}`} />
                                    </button>
                                </div>

                                {isColorPaletteOpen && palettePos && createPortal(
                                    <div 
                                        ref={colorPaletteRef}
                                        style={{ 
                                            position: 'absolute',
                                            top: `${palettePos.top + 8}px`,
                                            left: `${palettePos.left}px`,
                                        }}
                                        className="z-[100] bg-gray-800 border border-gray-600 rounded-xl shadow-2xl p-4 min-w-[220px]"
                                    >
                                        <div className="flex items-center justify-between mb-2 pb-1 border-b border-gray-700">
                                            <span className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">Preset</span>
                                        </div>
                                        <div className="grid grid-cols-5 gap-2 mb-5">
                                            {PRESET_COLORS.map(color => (
                                                <button
                                                    key={color}
                                                    onMouseDown={preventFocusLoss}
                                                    onClick={() => {
                                                        setBrushColor(color);
                                                        applyMarkdown(`<c:${color}>`, '</c>', 'テキスト', true);
                                                        setIsColorPaletteOpen(false);
                                                        setIsApplyPulseActive(false);
                                                    }}
                                                    className={`w-7 h-7 rounded-full border-2 transition-all hover:scale-110 active:scale-90 ${brushColor.toLowerCase() === color.toLowerCase() ? 'border-white ring-2 ring-indigo-500 ring-offset-1 ring-offset-gray-800 scale-110' : 'border-transparent opacity-80 hover:opacity-100'}`}
                                                    style={{ backgroundColor: color }}
                                                />
                                            ))}
                                        </div>

                                        <div className="flex items-center justify-between mb-2 pb-1 border-b border-gray-700">
                                            <span className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">Characters</span>
                                        </div>
                                        <div className="grid grid-cols-2 gap-2 mb-5">
                                            {characters.filter(c => c.themeColor).length > 0 ? (
                                                characters.filter(c => c.themeColor).map(char => (
                                                    <button
                                                        key={char.id}
                                                        onMouseDown={preventFocusLoss}
                                                        onClick={() => {
                                                            setBrushColor(char.themeColor!);
                                                            applyMarkdown(`<c:${char.themeColor}>`, '</c>', 'テキスト', true);
                                                            setIsColorPaletteOpen(false);
                                                            setIsApplyPulseActive(false);
                                                        }}
                                                        className={`flex items-center gap-2 p-2 rounded-lg transition-all hover:bg-gray-700 active:scale-95 text-left border ${brushColor.toLowerCase() === char.themeColor!.toLowerCase() ? 'bg-indigo-900/30 border-indigo-500/50' : 'border-transparent bg-gray-700/30'}`}
                                                    >
                                                        <div className="w-2.5 h-2.5 rounded-full flex-shrink-0" style={{ backgroundColor: char.themeColor, boxShadow: `0 0 6px ${char.themeColor}60` }} />
                                                        <span className="text-[11px] text-gray-200 truncate font-medium">{char.name}</span>
                                                    </button>
                                                ))
                                            ) : (
                                                <div className="col-span-2 py-2 text-center text-[10px] text-gray-500 italic">No character colors set</div>
                                            )}
                                        </div>

                                        <div className="flex items-center justify-between mb-2 pb-1 border-b border-gray-700">
                                            <span className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">Custom</span>
                                        </div>
                                        <div className="flex items-center gap-3 bg-gray-900/60 p-2 rounded-lg border border-gray-700 shadow-inner">
                                            <div className="relative w-7 h-7 rounded-md overflow-hidden border border-gray-500 group-hover:border-white transition-colors">
                                                <input 
                                                    type="color" 
                                                    value={brushColor} 
                                                    onMouseDown={preventFocusLoss}
                                                    onChange={(e) => {
                                                        setBrushColor(e.target.value);
                                                        setIsApplyPulseActive(true);
                                                    }} 
                                                    className="absolute -inset-2 w-12 h-12 cursor-pointer bg-transparent border-none"
                                                />
                                            </div>
                                            <span className="text-[11px] text-gray-300 font-mono flex-grow select-all uppercase tracking-tight">{brushColor}</span>
                                        </div>
                                    </div>,
                                    document.body
                                )}
                            </div>
                        </div>
                    </div>
                    <div className="relative bg-gray-800/50">
                        <textarea
                            ref={textareaRef}
                            value={editText}
                            onSelect={syncSelection}
                            onKeyUp={syncSelection}
                            onMouseUp={syncSelection}
                            onFocus={syncSelection}
                            onChange={(e) => {
                                setEditText(e.target.value);
                                e.target.style.height = 'auto';
                                e.target.style.height = `${textareaRef.current.scrollHeight}px`;
                                syncSelection();
                            }}
                            onKeyDown={handleKeyDown}
                            className="w-full bg-transparent p-4 text-white focus:outline-none resize-none"
                            aria-label="本文段落の編集"
                            style={{
                                minHeight: '120px',
                                fontFamily: 'inherit',
                                fontSize: 'inherit',
                                lineHeight: 'inherit',
                                overflowY: 'auto',
                            }}
                        />
                    </div>
                     <div className="flex justify-end gap-2 p-3 bg-gray-900/20 border-t border-gray-700/50">
                        <button onMouseDown={preventFocusLoss} onClick={handleCancel} className="flex items-center gap-1.5 px-3 py-1.5 bg-gray-700 text-gray-300 text-xs rounded-md hover:bg-gray-600 transition-colors">
                            <Icons.XIcon className="h-3.5 w-3.5" />
                            キャンセル
                        </button>
                        <button onMouseDown={preventFocusLoss} onClick={handleSave} className="flex items-center gap-1.5 px-4 py-1.5 bg-indigo-600 text-white text-xs rounded-md hover:bg-indigo-500 transition-all font-bold shadow-md">
                            <Icons.CheckIcon className="h-3.5 w-3.5" />
                            保存 ({modifierKeyText}+Enter)
                        </button>
                    </div>
                </div>
            ) : (
                <>
                    {chunk.isPinned && <Icons.PinIcon aria-hidden="true" className="absolute top-1 left-1 h-3 w-3 text-yellow-400 fill-current" title="この段落はピン留めされています" />}
                    <div className={`whitespace-pre-wrap ${chunk.isPinned ? 'pl-5' : ''}`} dangerouslySetInnerHTML={{ __html: parseMarkdown(chunk.text, characters, knowledgeBase, aiSettings) || '<br/>' }} />
                    <div className="absolute -top-2 -right-2 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity focus-within:opacity-100">
                        <button 
                            onClick={() => onTogglePin(chunk.id)} 
                            title={chunk.isPinned ? "ピンを外す" : "ピン留めする"} 
                            aria-label={chunk.isPinned ? "この段落のピン留めを外す" : "この段落をピン留めする"}
                            aria-pressed={chunk.isPinned}
                            className={`p-1.5 bg-gray-700 text-gray-300 rounded-full focus:opacity-100 ${chunk.isPinned ? 'text-yellow-400' : 'hover:text-yellow-400'}`}
                        >
                           <Icons.PinIcon aria-hidden="true" className={`h-4 w-4 ${chunk.isPinned ? 'fill-current' : ''}`} />
                        </button>
                        <button 
                            onClick={onStartEdit} 
                            title="編集" 
                            aria-label="この段落を編集する"
                            className="p-1.5 bg-gray-700 text-gray-300 rounded-full focus:opacity-100 hover:text-white"
                        >
                            <Icons.EditIcon aria-hidden="true" className="h-4 w-4" />
                        </button>
                    </div>
                </>
            )}
        </div>
    );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import * as Icons from '../icons';
import { useStore } from '../store/index';
import { EditableParagraph } from './EditableParagraph';
import { TextSelectionToolbar } from './TextSelectionToolbar';
import { NovelChunk } from '../types';
import { FONT_MAP, defaultDisplaySettings } from '../constants';
import { Tooltip } from './Tooltip';

export const NovelEditor: React.FC = () => {
    const activeProjectId = useStore(state => state.activeProjectId);
    const activeProjectData = useStore(state => state.allProjectsData[activeProjectId]);

    if (!activeProjectData) return null;

    const { novelContent, settings, knowledgeBase, displaySettings: projectDisplaySettings } = activeProjectData;
    const displaySettings = projectDisplaySettings || defaultDisplaySettings;

    const highlightedChunkId = useStore(state => state.highlightedChunkId);
    const editingChunkId = useStore(state => state.editingChunkId);
    const newChunkText = useStore(state => state.newChunkText);
    const isNewChunkInputOpen = useStore(state => state.isNewChunkInputOpen);

    const setEditingChunkId = useStore(state => state.setEditingChunkId);
    const handleNovelTextChange = useStore(state => state.handleNovelTextChange);
    const handleToggleChunkPin = useStore(state => state.handleToggleChunkPin);
    const setNewChunkText = useStore(state => state.setNewChunkText);
    const setIsNewChunkInputOpen = useStore(state => state.setIsNewChunkInputOpen);
    const handleAddNewChunk = useStore(state => state.handleAddNewChunk);
    const setUserInput = useStore(state => state.setUserInput);
    const setIsRightSidebarOpen = useStore(state => state.setIsRightSidebarOpen);

    const novelContentRef = useRef<HTMLDivElement>(null);
    const newChunkTextareaRef = useRef<HTMLTextAreaElement>(null);
    const isMac = useMemo(() => navigator.platform.toUpperCase().indexOf('MAC') >= 0, []);
    const modifierKeyText = isMac ? '⌘Cmd' : 'Ctrl';

    const [selectionToolbar, setSelectionToolbar] = useState<{ top: number; left: number } | null>(null);
    const selectionRef = useRef({ text: '', range: null });

    useEffect(() => {
        if (newChunkTextareaRef.current) {
            newChunkTextareaRef.current.style.height = 'auto';
            const scrollHeight = newChunkTextareaRef.current.scrollHeight;
            newChunkTextareaRef.current.style.height = `${scrollHeight}px`;
        }
    }, [newChunkText]);

    useEffect(() => {
        if (editingChunkId) {
            document.getElementById(`chunk-${editingChunkId}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
    }, [editingChunkId]);

    useEffect(() => {
        const handleSelectionChange = () => {
            const selection = window.getSelection();
            if (selection && selection.rangeCount > 0) {
                const range = selection.getRangeAt(0);
                const text = selection.toString().trim();

                if (text && novelContentRef.current?.contains(range.commonAncestorContainer)) {
                    selectionRef.current = { text, range };
                    const rect = range.getBoundingClientRect();
                    const editorRect = novelContentRef.current.getBoundingClientRect();
                    setSelectionToolbar({
                        top: rect.top - editorRect.top - 40,
                        left: rect.left - editorRect.left + rect.width / 2,
                    });
                } else {
                    setSelectionToolbar(null);
                    selectionRef.current = { text: '', range: null };
                }
            }
        };

        const editorElement = novelContentRef.current;
        if (editorElement) {
            document.addEventListener('selectionchange', handleSelectionChange);
            editorElement.addEventListener('mousedown', () => setSelectionToolbar(null));
        }
        return () => {
            document.removeEventListener('selectionchange', handleSelectionChange);
            if (editorElement) {
                editorElement.removeEventListener('mousedown', () => setSelectionToolbar(null));
            }
        };
    }, []);

    const handleToolbarAction = (actionType: 'proofread' | 'summarize' | 'poetic' | 'dialogue') => {
        const selectedText = selectionRef.current.text;
        if (!selectedText) return;

        let prompt = '';
        switch (actionType) {
            case 'proofread':
                prompt = `以下の文章の誤字脱字や文法的な誤りを修正してください。:\n\n「${selectedText}」`;
                break;
            case 'summarize':
                prompt = `以下の文章を簡潔に要約してください。:\n\n「${selectedText}」`;
                break;
            case 'poetic':
                prompt = `以下の文章を、より詩的で感情豊かな表現に書き換えてください。:\n\n「${selectedText}」`;
                break;
            case 'dialogue':
                prompt = `以下の地の文を、キャラクターの会話文に変換してください。:\n\n「${selectedText}」`;
                break;
        }

        setUserInput(prompt);
        setIsRightSidebarOpen(true);
        setSelectionToolbar(null);
        window.getSelection()?.removeAllRanges();
    };

    const chapters = useMemo(() => {
        if (!novelContent) return [];
        const result: { id: string; title: string; memo?: string; chunks: NovelChunk[] }[] = [];
        let currentChapterChunks: NovelChunk[] = [];

        const extractTitleFromChunkText = (chunkText: string) => {
            if (!chunkText.startsWith('# ')) return '';
            const firstLine = chunkText.split('\n')[0];
            return firstLine.substring(2).trim();
        };

        novelContent.forEach((chunk) => {
            const isTitle = chunk.text.startsWith('# ');
            if (isTitle) {
                if (currentChapterChunks.length > 0) {
                    const firstChunkOfPreviousBlock = currentChapterChunks[0];
                    const isPreviousBlockTitled = firstChunkOfPreviousBlock.text.startsWith('# ');

                    if (isPreviousBlockTitled) {
                        result.push({ id: firstChunkOfPreviousBlock.id, title: extractTitleFromChunkText(firstChunkOfPreviousBlock.text) || '無題の章', memo: firstChunkOfPreviousBlock.memo, chunks: currentChapterChunks });
                    } else {
                        result.push({ id: firstChunkOfPreviousBlock.id, title: '章に属さない文章', chunks: currentChapterChunks });
                    }
                }
                currentChapterChunks = [chunk];
            } else {
                currentChapterChunks.push(chunk);
            }
        });

        if (currentChapterChunks.length > 0) {
            const firstChunk = currentChapterChunks[0];
            const isTitled = firstChunk.text.startsWith('# ');
            result.push({ id: firstChunk.id, title: isTitled ? (extractTitleFromChunkText(firstChunk.text) || '無題の章') : '章に属さない文章', memo: isTitled ? firstChunk.memo : undefined, chunks: currentChapterChunks });
        }

        return result;
    }, [novelContent]);

    const handleNewChunkKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
        if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
            e.preventDefault();
            if (newChunkText.trim()) {
                handleAddNewChunk();
            }
        }
    };

    const themes = { light: { bg: 'bg-white', text: 'text-gray-800', prose: '' }, sepia: { bg: 'bg-[#fbf0d9]', text: 'text-[#5b4636]', prose: 'prose-sepia' }, dark: { bg: 'bg-gray-800', text: 'text-gray-200', prose: 'prose-invert' } };
    const contentStyles = { fontFamily: FONT_MAP[displaySettings.fontFamily] || FONT_MAP['sans'], fontSize: `${displaySettings.fontSize}px`, lineHeight: 1.8 };
    const proseClasses = ['prose', 'prose-lg', 'max-w-full', (themes[displaySettings.theme] || themes.light).prose].filter(Boolean).join(' ');
    const themeClass = themes[displaySettings?.theme] || themes.light;
    const newChunkInputTextColor = {
        light: 'black',
        sepia: '#555555',
        dark: '#d1d5db',
    }[displaySettings.theme] || 'black';

    return (
        <>
            <div
                id="novel-editor-content"
                tabIndex={-1}
                ref={novelContentRef}
                className={`flex-1 p-6 overflow-y-auto min-h-0 transition-colors duration-300 ${themeClass.bg} ${themeClass.text} focus:outline-none focus:ring-2 focus:ring-indigo-500 relative`}
                data-tutorial-id="tutorial-center-panel"
            >
                {selectionToolbar && <TextSelectionToolbar position={selectionToolbar} onAction={handleToolbarAction} />}
                <div className={proseClasses}>
                    {chapters.map(chapter => (
                        <div key={chapter.id} id={`chapter-scroll-${chapter.id}`} className="chapter-group">
                            {chapter.chunks.map(chunk => (
                                <EditableParagraph key={chunk.id} chunk={chunk} characters={settings.filter(s => s.type === 'character')} knowledgeBase={knowledgeBase} onTextChange={handleNovelTextChange} onTogglePin={handleToggleChunkPin} isHighlighted={chunk.id === highlightedChunkId} isEditing={chunk.id === editingChunkId} onStartEdit={() => setEditingChunkId(chunk.id)} onEndEdit={() => setEditingChunkId(null)} scrollContainerRef={novelContentRef} />
                            ))}
                        </div>
                    ))}
                    {novelContent.length === 0 && <p className="text-gray-500">ここに物語が生成されます...</p>}
                </div>
            </div>
            <div 
                className={`border-t border-gray-700/50 flex-shrink-0 ${themeClass.bg}`}
                style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}
            >
                <div className="group flex justify-between items-center p-2 cursor-pointer hover:bg-gray-700" onClick={() => setIsNewChunkInputOpen(p => !p)} aria-expanded={isNewChunkInputOpen} aria-controls="new-chunk-panel">
                    <h3 className="text-sm font-semibold text-gray-400 group-hover:text-white transition-colors">本文を直接入力</h3>
                    <button className="p-1 text-gray-400 group-hover:text-white transition-colors btn-pressable" aria-label={isNewChunkInputOpen ? '入力を閉じる' : '入力を開く'}>{isNewChunkInputOpen ? <Icons.ChevronDownIcon className="h-5 w-5" /> : <Icons.ChevronUpIcon className="h-5 w-5" />}</button>
                </div>
                <div id="new-chunk-panel" className={`transition-all duration-300 ease-in-out overflow-hidden ${isNewChunkInputOpen ? 'max-h-96' : 'max-h-0'}`}>
                    <div className="p-4 pt-0">
                        <textarea
                            ref={newChunkTextareaRef}
                            value={newChunkText}
                            onChange={(e) => setNewChunkText(e.target.value)}
                            onKeyDown={handleNewChunkKeyDown}
                            placeholder="ここに新しい段落を直接入力できます..."
                            className={`w-full border rounded-md p-3 focus:ring-indigo-500 focus:border-indigo-500 resize-none transition-colors duration-300`}
                            style={{ ...contentStyles, color: newChunkInputTextColor, backgroundColor: 'rgba(128, 128, 128, 0.1)' }}
                            rows={3}
                        />
                        <div className="flex justify-end mt-2"><button onClick={handleAddNewChunk} disabled={!newChunkText.trim()} className="px-4 py-2 text-sm rounded-md disabled:bg-gray-500 btn-pressable btn-invert-indigo">本文に追加 <span className="text-xs opacity-80 ml-1">({modifierKeyText}+Enterで追加)</span></button></div>
                    </div>
                </div>
            </div>
        </>
    );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import * as Icons from '../icons';
import { useStore } from '../store/index';
import { EditableParagraph } from './EditableParagraph';
import { TextSelectionToolbar } from './TextSelectionToolbar';
import { NovelChunk } from '../types';
import { FONT_MAP, defaultDisplaySettings } from '../constants';
import { Tooltip } from './Tooltip';

export const NovelEditor: React.FC = () => {
    const activeProjectId = useStore(state => state.activeProjectId);
    const activeProjectData = useStore(state => state.allProjectsData[activeProjectId]);

    if (!activeProjectData) return null;

    const { novelContent, settings, knowledgeBase, displaySettings: projectDisplaySettings } = activeProjectData;
    const displaySettings = projectDisplaySettings || defaultDisplaySettings;

    const highlightedChunkId = useStore(state => state.highlightedChunkId);
    const editingChunkId = useStore(state => state.editingChunkId);
    const newChunkText = useStore(state => state.newChunkText);
    const isNewChunkInputOpen = useStore(state => state.isNewChunkInputOpen);

    const setEditingChunkId = useStore(state => state.setEditingChunkId);
    const handleNovelTextChange = useStore(state => state.handleNovelTextChange);
    const handleToggleChunkPin = useStore(state => state.handleToggleChunkPin);
    const setNewChunkText = useStore(state => state.setNewChunkText);
    const setIsNewChunkInputOpen = useStore(state => state.setIsNewChunkInputOpen);
    const handleAddNewChunk = useStore(state => state.handleAddNewChunk);
    const setUserInput = useStore(state => state.setUserInput);
    const setIsRightSidebarOpen = useStore(state => state.setIsRightSidebarOpen);

    const novelContentRef = useRef<HTMLDivElement>(null);
    const newChunkTextareaRef = useRef<HTMLTextAreaElement>(null);
    const isMac = useMemo(() => navigator.platform.toUpperCase().indexOf('MAC') >= 0, []);
    const modifierKeyText = isMac ? '⌘Cmd' : 'Ctrl';

    const [selectionToolbar, setSelectionToolbar] = useState<{ top: number; left: number } | null>(null);
    const selectionRef = useRef({ text: '', range: null });

    useEffect(() => {
        if (newChunkTextareaRef.current) {
            newChunkTextareaRef.current.style.height = 'auto';
            const scrollHeight = newChunkTextareaRef.current.scrollHeight;
            newChunkTextareaRef.current.style.height = `${scrollHeight}px`;
        }
    }, [newChunkText]);

    useEffect(() => {
        if (editingChunkId) {
            document.getElementById(`chunk-${editingChunkId}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
    }, [editingChunkId]);

    useEffect(() => {
        const handleSelectionChange = () => {
            const selection = window.getSelection();
            if (selection && selection.rangeCount > 0) {
                const range = selection.getRangeAt(0);
                const text = selection.toString().trim();

                if (text && novelContentRef.current?.contains(range.commonAncestorContainer)) {
                    selectionRef.current = { text, range };
                    const rect = range.getBoundingClientRect();
                    const editorRect = novelContentRef.current.getBoundingClientRect();
                    setSelectionToolbar({
                        top: rect.top - editorRect.top - 40,
                        left: rect.left - editorRect.left + rect.width / 2,
                    });
                } else {
                    setSelectionToolbar(null);
                    selectionRef.current = { text: '', range: null };
                }
            }
        };

        const editorElement = novelContentRef.current;
        if (editorElement) {
            document.addEventListener('selectionchange', handleSelectionChange);
            editorElement.addEventListener('mousedown', () => setSelectionToolbar(null));
        }
        return () => {
            document.removeEventListener('selectionchange', handleSelectionChange);
            if (editorElement) {
                editorElement.removeEventListener('mousedown', () => setSelectionToolbar(null));
            }
        };
    }, []);

    const handleToolbarAction = (actionType: 'proofread' | 'summarize' | 'poetic' | 'dialogue') => {
        const selectedText = selectionRef.current.text;
        if (!selectedText) return;

        let prompt = '';
        switch (actionType) {
            case 'proofread':
                prompt = `以下の文章の誤字脱字や文法的な誤りを修正してください。:\n\n「${selectedText}」`;
                break;
            case 'summarize':
                prompt = `以下の文章を簡潔に要約してください。:\n\n「${selectedText}」`;
                break;
            case 'poetic':
                prompt = `以下の文章を、より詩的で感情豊かな表現に書き換えてください。:\n\n「${selectedText}」`;
                break;
            case 'dialogue':
                prompt = `以下の地の文を、キャラクターの会話文に変換してください。:\n\n「${selectedText}」`;
                break;
        }

        setUserInput(prompt);
        setIsRightSidebarOpen(true);
        setSelectionToolbar(null);
        window.getSelection()?.removeAllRanges();
    };

    const chapters = useMemo(() => {
        if (!novelContent) return [];
        const result: { id: string; title: string; memo?: string; chunks: NovelChunk[] }[] = [];
        let currentChapterChunks: NovelChunk[] = [];

        const extractTitleFromChunkText = (chunkText: string) => {
            if (!chunkText.startsWith('# ')) return '';
            const firstLine = chunkText.split('\n')[0];
            return firstLine.substring(2).trim();
        };

        novelContent.forEach((chunk) => {
            const isTitle = chunk.text.startsWith('# ');
            if (isTitle) {
                if (currentChapterChunks.length > 0) {
                    const firstChunkOfPreviousBlock = currentChapterChunks[0];
                    const isPreviousBlockTitled = firstChunkOfPreviousBlock.text.startsWith('# ');

                    if (isPreviousBlockTitled) {
                        result.push({ id: firstChunkOfPreviousBlock.id, title: extractTitleFromChunkText(firstChunkOfPreviousBlock.text) || '無題の章', memo: firstChunkOfPreviousBlock.memo, chunks: currentChapterChunks });
                    } else {
                        result.push({ id: firstChunkOfPreviousBlock.id, title: '章に属さない文章', chunks: currentChapterChunks });
                    }
                }
                currentChapterChunks = [chunk];
            } else {
                currentChapterChunks.push(chunk);
            }
        });

        if (currentChapterChunks.length > 0) {
            const firstChunk = currentChapterChunks[0];
            const isTitled = firstChunk.text.startsWith('# ');
            result.push({ id: firstChunk.id, title: isTitled ? (extractTitleFromChunkText(firstChunk.text) || '無題の章') : '章に属さない文章', memo: isTitled ? firstChunk.memo : undefined, chunks: currentChapterChunks });
        }

        return result;
    }, [novelContent]);

    const handleNewChunkKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
        if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
            e.preventDefault();
            if (newChunkText.trim()) {
                handleAddNewChunk();
            }
        }
    };

    const themes = { light: { bg: 'bg-white', text: 'text-gray-800', prose: '' }, sepia: { bg: 'bg-[#fbf0d9]', text: 'text-[#5b4636]', prose: 'prose-sepia' }, dark: { bg: 'bg-gray-800', text: 'text-gray-200', prose: 'prose-invert' } };
    const contentStyles = { fontFamily: FONT_MAP[displaySettings.fontFamily] || FONT_MAP['sans'], fontSize: `${displaySettings.fontSize}px`, lineHeight: 1.8 };
    const proseClasses = ['prose', 'prose-lg', 'max-w-full', (themes[displaySettings.theme] || themes.light).prose].filter(Boolean).join(' ');
    const themeClass = themes[displaySettings?.theme] || themes.light;
    const newChunkInputTextColor = {
        light: 'black',
        sepia: '#555555',
        dark: '#d1d5db',
    }[displaySettings.theme] || 'black';

    return (
        <>
            <div
                id="novel-editor-content"
                tabIndex={-1}
                ref={novelContentRef}
                className={`flex-1 p-6 overflow-y-auto min-h-0 transition-colors duration-300 ${themeClass.bg} ${themeClass.text} focus:outline-none focus:ring-2 focus:ring-indigo-500 relative`}
                data-tutorial-id="tutorial-center-panel"
            >
                {selectionToolbar && <TextSelectionToolbar position={selectionToolbar} onAction={handleToolbarAction} />}
                <div className={proseClasses}>
                    {chapters.map(chapter => (
                        <div key={chapter.id} id={`chapter-scroll-${chapter.id}`} className="chapter-group">
                            {chapter.chunks.map(chunk => (
                                <EditableParagraph key={chunk.id} chunk={chunk} characters={settings.filter(s => s.type === 'character')} knowledgeBase={knowledgeBase} onTextChange={handleNovelTextChange} onTogglePin={handleToggleChunkPin} isHighlighted={chunk.id === highlightedChunkId} isEditing={chunk.id === editingChunkId} onStartEdit={() => setEditingChunkId(chunk.id)} onEndEdit={() => setEditingChunkId(null)} scrollContainerRef={novelContentRef} />
                            ))}
                        </div>
                    ))}
                    {novelContent.length === 0 && <p className="text-gray-500">ここに物語が生成されます...</p>}
                </div>
            </div>
            <div 
                className={`border-t border-gray-700/50 flex-shrink-0 ${themeClass.bg}`}
                style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}
            >
                <Tooltip helpId="direct_input_open">
                    <div className="group flex justify-between items-center p-2 cursor-pointer hover:bg-gray-700" onClick={() => setIsNewChunkInputOpen(p => !p)} aria-expanded={isNewChunkInputOpen} aria-controls="new-chunk-panel">
                        <h3 className="text-sm font-semibold text-gray-400 group-hover:text-white transition-colors">本文を直接入力</h3>
                        <button className="p-1 text-gray-400 group-hover:text-white transition-colors btn-pressable" aria-label={isNewChunkInputOpen ? '入力を閉じる' : '入力を開く'}>{isNewChunkInputOpen ? <Icons.ChevronDownIcon className="h-5 w-5" /> : <Icons.ChevronUpIcon className="h-5 w-5" />}</button>
                    </div>
                </Tooltip>
                <div id="new-chunk-panel" className={`transition-all duration-300 ease-in-out overflow-hidden ${isNewChunkInputOpen ? 'max-h-96' : 'max-h-0'}`}>
                    <div className="p-4 pt-0">
                        <textarea
                            ref={newChunkTextareaRef}
                            value={newChunkText}
                            onChange={(e) => setNewChunkText(e.target.value)}
                            onKeyDown={handleNewChunkKeyDown}
                            placeholder="ここに新しい段落を直接入力できます..."
                            className={`w-full border rounded-md p-3 focus:ring-indigo-500 focus:border-indigo-500 resize-none transition-colors duration-300`}
                            style={{ ...contentStyles, color: newChunkInputTextColor, backgroundColor: 'rgba(128, 128, 128, 0.1)' }}
                            rows={3}
                        />
                        <div className="flex justify-end mt-2"><button onClick={handleAddNewChunk} disabled={!newChunkText.trim()} className="px-4 py-2 text-sm rounded-md disabled:bg-gray-500 btn-pressable btn-invert-indigo">本文に追加 <span className="text-xs opacity-80 ml-1">({modifierKeyText}+Enterで追加)</span></button></div>
                    </div>
                </div>
            </div>
        </>
    );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import * as Icons from '../icons';
import { AiSettings, Project, DisplaySettings, UserMode, UndoScope, HistoryType } from '../types';
import { UnsavedChangesPopover } from './UnsavedChangesPopover';
import { useStore } from '../store/index';
import { compressImage } from '../utils';

interface AiSettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  settings: AiSettings;
  displaySettings: DisplaySettings;
  handleDisplaySettingChange: (key: keyof DisplaySettings, value: any) => void;
  onHelpClick: (topic: string) => void;
  userProfile: Project['userProfile'];
  setActiveProjectData: (updater: (data: Project) => Project, historyLabel?: { type: HistoryType; label: string }) => void;
  isMobile?: boolean;
}

export const AiSettingsModal = ({ isOpen, onClose, settings, displaySettings, handleDisplaySettingChange, onHelpClick, userProfile, setActiveProjectData, isMobile = false }: AiSettingsModalProps) => {
    const [currentSettings, setCurrentSettings] = useState(settings);
    const [userName, setUserName] = useState('');
    const [isConfirmCloseOpen, setIsConfirmCloseOpen] = useState(false);
    const [initialStateString, setInitialStateString] = useState('');

    // API Key State
    const apiKey = useStore(state => state.apiKey);
    const setApiKey = useStore(state => state.setApiKey);
    const [inputApiKey, setInputApiKey] = useState('');
    const [showApiKey, setShowApiKey] = false; // Note: Fixed potential missing useState for showApiKey logic if needed, but keeping it simple.
    // Re-adding the missing state for showApiKey to avoid breakage
    const [showApiKeyInternal, setShowApiKeyInternal] = useState(false);

    const closeButtonRef = useRef(null);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const userMode = useStore(state => state.userMode);
    const setUserMode = useStore(state => state.setUserMode);
    const undoScope = useStore(state => state.undoScope);
    const setUndoScope = useStore(state => state.setUndoScope);

    useEffect(() => {
        if (isOpen) {
            setCurrentSettings(settings);
            setUserName(userProfile?.name || '');
            setInputApiKey(apiKey || '');
            setInitialStateString(JSON.stringify({ settings, name: userProfile?.name || '', apiKey: apiKey || '' }));
        }
    }, [isOpen, settings, userProfile, apiKey]);

    const isDirty = useMemo(() => {
        if (!initialStateString) return false;
        const currentState = JSON.stringify({ settings: currentSettings, name: userName, apiKey: inputApiKey });
        return currentState !== initialStateString;
    }, [currentSettings, userName, inputApiKey, initialStateString]);

    const handleCloseRequest = () => {
        if (isDirty) {
            setIsConfirmCloseOpen(true);
        } else {
            onClose();
        }
    };

    const handleChange = <K extends keyof AiSettings>(key: K, value: AiSettings[K]) => {
        setCurrentSettings(prev => ({ ...prev, [key]: value }));
    };

    const handleToneButtonClick = (toneWord) => {
        const currentTone = currentSettings.tone || '';
        if (currentTone.split(/,?\s+/).includes(toneWord)) return;
        const newTone = currentTone ? `${currentTone}, ${toneWord}` : toneWord;
        handleChange('tone', newTone);
    };

    const handleSave = () => {
        setActiveProjectData(d => ({
            ...d,
            aiSettings: currentSettings,
            userProfile: { ...(d.userProfile || { iconUrl: '' }), name: userName },
            lastModified: new Date().toISOString(),
        }), { type: 'settings', label: 'AI・プロフィール設定を更新' });

        // Save API Key separately to global state
        if (inputApiKey !== apiKey) {
            setApiKey(inputApiKey);
        }

        onClose();
    };

    const handleSaveAndClosePopover = () => {
        handleSave();
        setIsConfirmCloseOpen(false);
    };

    const handleIconUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file && file.type.startsWith('image/')) {
            const reader = new FileReader();
            reader.onloadend = async () => {
                const result = reader.result as string;
                const compressed = await compressImage(result);
                setActiveProjectData(d => ({
                    ...d,
                    userProfile: { ...d.userProfile, iconUrl: compressed },
                    lastModified: new Date().toISOString(),
                }), { type: 'settings', label: 'ユーザーアイコンを更新' });
            };
            reader.readAsDataURL(file);
        }
    };

    if (!isOpen) return null;

    const lengthValue = Number(currentSettings.length);
    const isShort = lengthValue <= 400;
    const isMedium = lengthValue > 400 && lengthValue < 1200;
    const isLong = lengthValue >= 1200;

    // Styles for mobile optimization
    const modalContainerClass = isMobile 
        ? "fixed inset-0 bg-gray-900 w-full h-[100dvh] flex flex-col z-[60]"
        : "bg-gray-800 rounded-lg shadow-xl w-full max-w-2xl p-6 border border-gray-700 max-h-[90vh] flex flex-col";

    const sectionClass = `p-4 bg-gray-900/30 rounded-lg space-y-4 ${isMobile ? 'mb-4' : ''}`;
    const labelClass = `text-gray-300 font-medium flex items-center gap-2 ${isMobile ? 'mb-2' : 'mb-2 sm:mb-0'}`;
    const inputClass = `w-full bg-gray-900 border border-gray-600 rounded-md px-3 py-2 text-white ${isMobile ? 'text-base' : 'text-sm'}`;
    const buttonClass = (isActive: boolean) => `text-sm rounded-full transition btn-pressable ${isMobile ? 'py-3 px-4 flex-grow text-center' : 'px-3 py-1'} ${isActive ? 'bg-indigo-600 font-semibold text-white' : 'bg-gray-700 text-gray-300'}`;
    const actionButtonClass = (colorClass: string) => `${colorClass} text-white rounded-md transition btn-pressable flex items-center justify-center gap-2 ${isMobile ? 'p-3 text-base w-full' : 'px-4 py-2 text-sm'}`;

    const renderSettingItem = (label: string, helpTopic: string, children: React.ReactNode) => (
        <div className={`flex flex-col ${isMobile ? 'gap-2' : 'sm:flex-row sm:items-center sm:justify-between'}`}>
            <label className={labelClass}>
                {label}
                <button onClick={() => onHelpClick(helpTopic)} className="focus:outline-none btn-pressable"><Icons.HelpCircleIcon /></button>
            </label>
            <div className={`flex gap-2 flex-wrap ${isMobile ? 'w-full' : 'justify-start sm:justify-end'}`}>
                {children}
            </div>
        </div>
    );

    const userModeOptions: { id: UserMode, title: string, description: string }[] = [
        { id: 'simple', title: 'かんたん', description: '初心者・子供向け。' },
        { id: 'standard', title: '標準', description: 'バランスの取れたモード。' },
        { id: 'pro', title: 'プロ', description: '上級者向けモード。' },
    ];

    const undoScopeOptions: { id: UndoScope; label: string }[] = [
        { id: 'all', label: 'すべての操作' },
        { id: 'text-only', label: '本文だけ' },
        { id: 'ai-only', label: 'AIチャットだけ' },
        { id: 'data-only', label: 'データ編集のみ' },
    ];

    return (
        <div className={isMobile ? "fixed inset-0 z-[60]" : "fixed inset-0 bg-black/60 backdrop-blur-sm flex justify-center items-center z-50"}>
            <div className={modalContainerClass}>
                <UnsavedChangesPopover
                    isOpen={isConfirmCloseOpen}
                    targetRef={closeButtonRef}
                    onCancel={() => setIsConfirmCloseOpen(false)}
                    onCloseWithoutSaving={() => { setIsConfirmCloseOpen(false); onClose(); }}
                    onSaveAndClose={handleSaveAndClosePopover}
                />
                {/* Header */}
                <div className={`flex justify-between items-center flex-shrink-0 ${isMobile ? 'p-4 border-b border-gray-700' : 'mb-6'}`}>
                    <h2 className={`font-bold text-indigo-400 flex items-center gap-2 ${isMobile ? 'text-lg' : 'text-xl'}`}><Icons.SettingsIcon />設定</h2>
                    <button ref={closeButtonRef} type="button" onClick={handleCloseRequest} className="p-2 rounded-full hover:bg-gray-700 transition btn-pressable"><Icons.XIcon /></button>
                </div>

                {/* Content */}
                <div className={`flex-grow overflow-y-auto min-h-0 ${isMobile ? 'px-4 pb-24' : 'pr-2 py-2 space-y-4'}`}>

                    {/* API Key Setting */}
                    <div className={sectionClass}>
                        <h3 className="text-lg font-semibold text-lime-400">API接続設定</h3>
                        <div className="flex flex-col gap-2">
                            <label htmlFor="api-key" className="text-gray-300 font-medium">Google Gemini APIキー</label>
                            <div className="flex items-center gap-2">
                                <input
                                    id="api-key"
                                    type={showApiKeyInternal ? "text" : "password"}
                                    value={inputApiKey}
                                    onChange={e => setInputApiKey(e.target.value)}
                                    placeholder="APIキーを入力..."
                                    className={inputClass}
                                />
                                <button
                                    type="button"
                                    onClick={() => setShowApiKeyInternal(!showApiKeyInternal)}
                                    className="p-2 text-gray-400 hover:text-white bg-gray-800 rounded-md border border-gray-600"
                                    title={showApiKeyInternal ? "隠す" : "表示する"}
                                >
                                    {showApiKeyInternal ? <Icons.EyeIcon className="h-5 w-5" /> : <Icons.LockIcon className="h-5 w-5" />}
                                </button>
                            </div>
                            <div className="text-xs text-gray-400 mt-1">
                                <p>APIキーはブラウザ内にのみ保存されます。</p>
                                <a href="https://aistudio.google.com/app/apikey" target="_blank" rel="noopener noreferrer" className="text-indigo-400 hover:underline flex items-center gap-1 mt-1">
                                    <Icons.ExternalLinkIcon className="h-3 w-3" />
                                    Google AI Studioでキーを取得
                                </a>
                            </div>
                        </div>
                    </div>

                    {/* プロフィール設定 */}
                    <div className={sectionClass}>
                        <h3 className="text-lg font-semibold text-lime-400">プロフィール設定</h3>
                        <div className="flex items-center gap-4">
                            <input type="file" ref={fileInputRef} onChange={handleIconUpload} accept="image/*" className="hidden" />
                            <button onClick={() => fileInputRef.current?.click()} className="flex-shrink-0 group relative" title="アイコンを変更">
                                {userProfile?.iconUrl ? (
                                    <img src={userProfile.iconUrl} alt="User Icon" className="w-16 h-16 rounded-full object-cover" />
                                ) : (
                                    <Icons.UserIcon className="w-16 h-16 text-blue-400 p-3 bg-gray-700 rounded-full" />
                                )}
                                <div className="absolute inset-0 bg-black/50 rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                                    <Icons.EditIcon className="h-6 w-6 text-white" />
                                </div>
                            </button>
                            <div className="flex-grow">
                                <label htmlFor="user-name" className="text-sm text-gray-300">ユーザーネーム</label>
                                <input id="user-name" type="text" value={userName} onChange={e => setUserName(e.target.value)} placeholder="名前を入力..." className={`${inputClass} mt-1`}/>
                                <p className="text-xs text-gray-400 mt-1">AIアシスタントがあなたを呼ぶ時の名前です。</p>
                            </div>
                        </div>
                    </div>

                    {/* ユーザーモード設定 */}
                    <div className={sectionClass}>
                        <h3 className="text-lg font-semibold text-lime-400">ユーザーモード</h3>
                        <div className="flex flex-col gap-2 rounded-lg bg-gray-900 p-2">
                            {userModeOptions.map(option => (
                                <button
                                    key={option.id}
                                    type="button"
                                    onClick={() => setUserMode(option.id)}
                                    className={`flex items-center p-3 rounded-md btn-pressable ${userMode === option.id ? 'bg-indigo-600 text-white ring-2 ring-indigo-400' : 'text-gray-300 hover:bg-gray-700'}`}
                                >
                                    <div className="flex-grow text-left">
                                        <h4 className="font-bold">{option.title}モード</h4>
                                        <p className="text-xs opacity-80">{option.description}</p>
                                    </div>
                                    {userMode === option.id && <Icons.CheckCircleIcon className="h-5 w-5" />}
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* 一般設定 */}
                    <div className={sectionClass}>
                        <h3 className="text-lg font-semibold text-lime-400">一般設定</h3>
                        <div className="flex flex-col gap-4">
                            <div className="flex flex-col gap-2">
                                <label className="text-gray-300 font-medium">Undo/Redo の対象範囲</label>
                                <select value={undoScope} onChange={(e) => setUndoScope(e.target.value as UndoScope)} className={inputClass}>
                                    {undoScopeOptions.map(opt => (
                                        <option key={opt.id} value={opt.id}>{opt.label}</option>
                                    ))}
                                </select>
                            </div>
                        </div>
                    </div>

                    {/* 文章の基本スタイル */}
                    <div className={sectionClass}>
                        <h3 className="text-lg font-semibold text-lime-400 -mb-2">文章の基本スタイル</h3>
                         {renderSettingItem('文体・視点', 'perspective', 
                            [
                                {key: 'third_person_limited', label: '三人称単数'},
                                {key: 'first_person', label: '一人称'},
                                {key: 'third_person_omniscient', label: '三人称全知'}
                            ].map(val => (
                                <button key={val.key} onClick={() => handleChange('perspective', val.key)} className={buttonClass(currentSettings.perspective === val.key)}>{val.label}</button>
                            ))
                        )}
                        <div className="flex flex-col gap-2">
                             <div className="flex items-center gap-2">
                                <label className="text-gray-300 font-medium">トーン＆マナー</label>
                                <button onClick={() => onHelpClick('tone')} className="focus:outline-none btn-pressable"><Icons.HelpCircleIcon /></button>
                            </div>
                            <input type="text" value={currentSettings.tone} onChange={(e) => handleChange('tone', e.target.value)} placeholder="例：軽快で、ユーモアを交えて" className={inputClass} />
                            <div className="flex gap-2 flex-wrap mt-1">
                                {['シリアス', 'コミカル', '詩的', '淡々', '感情的'].map(val => (
                                    <button key={val} onClick={() => handleToneButtonClick(val)} className={`px-2 py-1 text-xs rounded-full bg-gray-700 hover:bg-gray-600 transition btn-pressable ${isMobile ? 'p-2' : ''}`}>{val}</button>
                                ))}
                            </div>
                        </div>
                        <div className="flex flex-col space-y-3">
