                            </div>
                        </div>
                    </div>

                    {/* ユーザーモード設定 */}
                    <div className={sectionClass}>
                        <h3 className="text-lg font-semibold text-lime-400">ユーザーモード</h3>
                        <div className="flex flex-col gap-2 rounded-lg bg-gray-900 p-2">
                            {userModeOptions.map(option => (
                                <button
                                    key={option.id}
