                                ))}
                            </div>
                        </div>
                        <div className="flex flex-col space-y-3">
                            <div className={`flex ${isMobile ? 'flex-col gap-2' : 'items-center justify-between'}`}>
                                 <label className="text-gray-300 font-medium flex items-center gap-2">生成する文章量
                                   <button onClick={() => onHelpClick('length')} className="focus:outline-none btn-pressable"><Icons.HelpCircleIcon /></button>
