                         {renderSettingItem('創造性のレベル', 'creativity', 
                            ['控えめ', '普通', '大胆'].map(val => (
                                <button key={val} onClick={() => handleChange('creativity', val)} className={buttonClass(currentSettings.creativity === val)}>{val}</button>
                            ))
