import React, { useState } from 'react';
import * as Icons from '../icons';
import { useStore } from '../store/index';
import { AnalysisResult } from '../types';

export const ImportTextModal: React.FC = () => {
  const [inputText, setInputText] = useState('');
  const analyzeImportedText = useStore(state => state.analyzeImportedText);
  const lastAnalysisResult = useStore(state => state.lastAnalysisResult);
  const clearAnalysisResult = useStore(state => state.clearAnalysisResult);
  const closeModal = useStore(state => state.closeModal);
  const isLoading = useStore(state => state.isLoading);
  const openModal = useStore(state => state.openModal);

  const handleAnalyze = async () => {
    if (!inputText.trim()) return;
    await analyzeImportedText(inputText);
  };

  const renderBadge = (type: 'match' | 'similar' | 'new') => {
    const colors = {
      match: 'bg-green-500/20 text-green-400 border-green-500/50',
      similar: 'bg-yellow-500/20 text-yellow-400 border-yellow-500/50',
      new: 'bg-blue-500/20 text-blue-400 border-blue-500/50',
    };
    const labels = { match: '一致', similar: '類似', new: '新規' };
    return <span className={`px-1.5 py-0.5 rounded text-[10px] border font-bold ${colors[type]}`}>{labels[type]}</span>;
  };

  const handleAddAsCharacter = (name: string) => {
    openModal('character', { name });
  };

  const handleAddAsKnowledge = (name: string) => {
    openModal('knowledge', { name });
  };

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex justify-center items-center z-[80] p-4">
      <div className="bg-gray-800 rounded-lg shadow-xl w-full max-w-4xl h-[90vh] flex flex-col border border-gray-700">
        {/* Header */}
        <div className="flex justify-between items-center p-4 border-b border-gray-700 flex-shrink-0">
          <h2 className="text-xl font-bold text-indigo-400 flex items-center gap-2">
            <Icons.UploadIcon className="h-6 w-6" />
            テキストインポート解析
          </h2>
          <button onClick={closeModal} className="p-2 rounded-full hover:bg-gray-700 transition">
            <Icons.XIcon />
          </button>
        </div>

        <div className="flex-grow flex min-h-0">
          {/* Left: Input */}
          <div className="w-1/2 flex flex-col p-4 border-r border-gray-700">
            <label className="block text-sm font-medium text-gray-400 mb-2">取り込むテキストをペースト</label>
            <textarea
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              placeholder="ここに外部で書いた本文を貼り付けてください..."
              className="flex-grow bg-gray-900 border border-gray-600 rounded-md p-3 text-sm text-white resize-none focus:ring-2 focus:ring-indigo-500 outline-none"
            />
            <div className="mt-4 flex gap-3">
              <button
                onClick={handleAnalyze}
                disabled={isLoading || !inputText.trim()}
                className="flex-grow flex items-center justify-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-md transition font-bold disabled:opacity-50"
              >
                {isLoading ? <Icons.LoaderIcon className="animate-spin" /> : <Icons.SparklesIcon />}
                AIで設定を抽出
              </button>
              {lastAnalysisResult && (
                <button
                  onClick={clearAnalysisResult}
                  className="px-4 py-2 bg-gray-700 hover:bg-gray-600 text-white rounded-md transition"
                >
                  クリア
                </button>
              )}
            </div>
          </div>

          {/* Right: Analysis Result */}
          <div className="w-1/2 flex flex-col p-4 overflow-y-auto bg-gray-900/30">
            {lastAnalysisResult ? (
              <div className="space-y-6">
                {/* Characters */}
                <div>
                  <h3 className="text-sm font-bold text-blue-300 mb-3 border-b border-blue-500/30 pb-1 flex items-center gap-2">
                    <Icons.UserIcon className="h-4 w-4" /> 登場人物候補
                  </h3>
                  <div className="space-y-2">
                    {lastAnalysisResult.characters.match.map(name => (
                      <div key={name} className="flex items-center justify-between bg-gray-800/50 p-2 rounded text-sm">
                        <span className="text-gray-200">{name}</span>
                        {renderBadge('match')}
                      </div>
                    ))}
                    {lastAnalysisResult.characters.similar.map((item, idx) => (
                      <div key={idx} className="flex flex-col bg-gray-800/50 p-2 rounded text-sm">
                        <div className="flex items-center justify-between mb-1">
                          <span className="text-gray-200">{item.text}</span>
                          {renderBadge('similar')}
                        </div>
                        <span className="text-[10px] text-yellow-500/80">既存: {item.target} の可能性</span>
                      </div>
                    ))}
                    {lastAnalysisResult.characters.new.map(name => (
                      <div key={name} className="flex items-center justify-between bg-gray-800/50 p-2 rounded text-sm">
                        <span className="text-white font-semibold">{name}</span>
                        <div className="flex items-center gap-2">
                          <button onClick={() => handleAddAsCharacter(name)} className="text-[10px] text-indigo-400 hover:underline">登録</button>
                          {renderBadge('new')}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>

                {/* World Terms */}
                <div>
                  <h3 className="text-sm font-bold text-green-300 mb-3 border-b border-green-500/30 pb-1 flex items-center gap-2">
                    <Icons.GlobeIcon className="h-4 w-4" /> 固有名詞・用語
                  </h3>
                  <div className="space-y-2">
                    {lastAnalysisResult.worldTerms.match.map(name => (
                      <div key={name} className="flex items-center justify-between bg-gray-800/50 p-2 rounded text-sm">
                        <span className="text-gray-200">{name}</span>
                        {renderBadge('match')}
                      </div>
                    ))}
                    {lastAnalysisResult.worldTerms.new.map(name => (
                      <div key={name} className="flex items-center justify-between bg-gray-800/50 p-2 rounded text-sm">
                        <span className="text-white font-semibold">{name}</span>
                        <div className="flex items-center gap-2">
                          <button onClick={() => handleAddAsKnowledge(name)} className="text-[10px] text-indigo-400 hover:underline">登録</button>
                          {renderBadge('new')}
