                      </div>
                    ))}
                  </div>
                </div>

                {/* Dialogues */}
                <div>
                  <h3 className="text-sm font-bold text-amber-300 mb-3 border-b border-amber-500/30 pb-1 flex items-center gap-2">
                    <Icons.PenSquareIcon className="h-4 w-4" /> セリフ解析
                  </h3>
                  <div className="space-y-2">
                    {lastAnalysisResult.dialogues.slice(0, 10).map((d, i) => (
                      <div key={i} className="bg-gray-800/50 p-2 rounded text-xs">
                        <p className="text-gray-300 italic mb-1">"{d.text}"</p>
                        <p className="text-right text-amber-400/80">→ 推定話者: {d.possibleSpeaker || '不明'}</p>
                      </div>
                    ))}
                    {lastAnalysisResult.dialogues.length > 10 && (
                      <p className="text-[10px] text-gray-500 text-center">他 {lastAnalysisResult.dialogues.length - 10} 件のセリフ</p>
                    )}
                  </div>
                </div>

                {/* Notes */}
                {lastAnalysisResult.notes.length > 0 && (
                  <div className="bg-indigo-900/20 border border-indigo-500/30 p-3 rounded-lg">
                    <h4 className="text-xs font-bold text-indigo-300 mb-2">解析ノート</h4>
                    <ul className="list-disc list-inside text-xs text-indigo-200/80 space-y-1">
                      {lastAnalysisResult.notes.map((note, i) => <li key={i}>{note}</li>)}
                    </ul>
