            ) : (
              <div className="flex flex-col items-center justify-center h-full text-gray-500 text-center">
                <Icons.SparklesIcon className="h-12 w-12 mb-4 opacity-20" />
                <p>左側のフォームにテキストを入力して<br />「AIで設定を抽出」を押してください。</p>
              </div>
            )}
          </div>
        </div>

        {/* Footer */}
        <div className="p-4 border-t border-gray-700 flex justify-end gap-3 flex-shrink-0">
          <button
            onClick={closeModal}
            className="px-6 py-2 bg-gray-600 hover:bg-gray-500 text-white rounded-md transition font-bold"
          >
            閉じる
          </button>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { useStore } from '../store/index';
import { HelpModal, GeneralHelpModal } from './HelpModals';
