            <>
              {/* Input Phase */}
              <div className="w-1/2 flex flex-col p-4 border-r border-gray-700">
                <label className="block text-sm font-medium text-gray-400 mb-2">取り込むテキストをペースト</label>
                <textarea
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  placeholder="ここに外部で書いた本文を貼り付けてください..."
                  className="flex-grow bg-gray-900 border border-gray-600 rounded-md p-3 text-sm text-white resize-none focus:ring-2 focus:ring-indigo-500 outline-none"
                />
                <div className="mt-4 flex gap-3">
                  <button
                    onClick={handleAnalyze}
                    disabled={isLoading || !inputText.trim()}
                    className="flex-grow flex items-center justify-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-md transition font-bold disabled:opacity-50"
                  >
                    {isLoading ? <Icons.LoaderIcon className="animate-spin" /> : <Icons.SparklesIcon />}
                    AIで設定を抽出
                  </button>
                </div>
              </div>
              <div className="w-1/2 flex flex-col items-center justify-center p-8 text-gray-500 text-center">
                <Icons.SparklesIcon className="h-16 w-16 mb-4 opacity-20" />
                <h3 className="text-lg font-bold mb-2">執筆準備をスマートに</h3>
                <p className="text-sm">
                  外部で執筆したテキストを貼り付けると、AIが自動で登場人物や用語を抽出します。<br/>
                  抽出された設定は、既存の設定と照らし合わせて、ボタンひとつで追加・紐付けが可能です。
                </p>
              </div>
            </>
          ) : (
            /* Reflection Phase */
            <div className="w-full flex flex-col min-h-0 bg-gray-900/30 overflow-y-auto p-6">
              {!lastAnalysisResult ? (
                  <div className="flex justify-center items-center h-full">
                    <Icons.LoaderIcon className="animate-spin h-8 w-8 text-indigo-500" />
                  </div>
              ) : (
                <div className="space-y-8 max-w-4xl mx-auto w-full">

                  {/* キャラクター反映 */}
                  <section>
                    <h3 className="text-lg font-bold text-blue-300 mb-4 border-b border-blue-500/30 pb-2 flex items-center gap-2">
                        <Icons.UserIcon className="h-5 w-5" /> 登場人物の反映
                    </h3>
                    <div className="space-y-3">
                        {/* Similar Characters */}
                        {lastAnalysisResult.characters.similar.map((item, idx) => (
                            <div key={`sim-${idx}`} className="bg-gray-800 border border-gray-700 p-4 rounded-lg flex items-center gap-4">
                                <input 
                                    type="checkbox" 
                                    checked={selectedChars[item.text]?.action === 'link'} 
                                    onChange={(e) => setSelectedChars(prev => ({
                                        ...prev,
                                        [item.text]: { action: e.target.checked ? 'link' : 'ignore', targetId: prev[item.text]?.targetId || existingCharacters.find(c => c.name === item.target)?.id }
                                    }))}
                                    className="w-5 h-5 rounded border-gray-600 bg-gray-900 text-indigo-600 focus:ring-indigo-500"
                                />
                                <div className="flex-grow">
                                    <div className="flex items-center gap-2 mb-1">
                                        <span className="text-gray-200 font-bold">{item.text}</span>
                                        <span className="bg-yellow-500/10 text-yellow-500 border border-yellow-500/30 text-[10px] px-1.5 py-0.5 rounded font-bold">表記ゆれ疑い</span>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <span className="text-xs text-gray-500">既存キャラへの紐付け:</span>
                                        <select 
                                            value={selectedChars[item.text]?.targetId || ''}
                                            onChange={(e) => setSelectedChars(prev => ({
                                                ...prev,
                                                [item.text]: { action: 'link', targetId: e.target.value }
                                            }))}
                                            className="bg-gray-900 border border-gray-600 text-xs text-white rounded px-2 py-1 outline-none focus:border-indigo-500"
                                        >
                                            <option value="">選択してください...</option>
                                            {existingCharacters.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                                        </select>
                                    </div>
                                </div>
                            </div>
                        ))}
                        {/* New Characters */}
                        {lastAnalysisResult.characters.new.map((name) => (
                            <div key={`new-${name}`} className="bg-gray-800 border border-gray-700 p-4 rounded-lg flex items-center gap-4">
                                <input 
                                    type="checkbox" 
                                    checked={selectedChars[name]?.action === 'create'} 
                                    onChange={(e) => setSelectedChars(prev => ({
                                        ...prev,
                                        [name]: { action: e.target.checked ? 'create' : 'ignore' }
                                    }))}
                                    className="w-5 h-5 rounded border-gray-600 bg-gray-900 text-indigo-600 focus:ring-indigo-500"
                                />
                                <div className="flex-grow">
                                    <span className="text-white font-bold">{name}</span>
                                    <span className="ml-2 bg-blue-500/10 text-blue-500 border border-blue-500/30 text-[10px] px-1.5 py-0.5 rounded font-bold uppercase tracking-wider">NEW</span>
                                </div>
                            </div>
                        ))}
                        {lastAnalysisResult.characters.new.length === 0 && lastAnalysisResult.characters.similar.length === 0 && (
                            <p className="text-sm text-gray-500 italic px-4">反映可能な新規キャラクターは見つかりませんでした。</p>
                        )}
                    </div>
                  </section>

                  {/* 世界観・用語反映 */}
                  <section>
                    <h3 className="text-lg font-bold text-green-300 mb-4 border-b border-green-500/30 pb-2 flex items-center gap-2">
                        <Icons.GlobeIcon className="h-5 w-5" /> 世界観・用語の反映
                    </h3>
                    <div className="space-y-3">
                        {lastAnalysisResult.worldTerms.new.map((name) => (
                            <div key={`term-${name}`} className="bg-gray-800 border border-gray-700 p-4 rounded-lg flex items-center gap-4">
                                <div className="flex-grow">
                                    <div className="flex items-center gap-2 mb-2">
                                        <span className="text-white font-bold">{name}</span>
                                        <span className="bg-blue-500/10 text-blue-500 border border-blue-500/30 text-[10px] px-1.5 py-0.5 rounded font-bold uppercase tracking-wider">NEW</span>
                                    </div>
                                    <div className="flex gap-4">
                                        <label className="flex items-center gap-2 cursor-pointer group">
                                            <input 
                                                type="radio" 
                                                name={`action-${name}`} 
                                                checked={selectedTerms[name]?.action === 'world'} 
                                                onChange={() => setSelectedTerms(prev => ({ ...prev, [name]: { action: 'world' } }))}
                                                className="w-4 h-4 bg-gray-900 border-gray-600 text-indigo-600 focus:ring-indigo-500"
                                            />
                                            <span className="text-xs text-gray-400 group-hover:text-gray-200 transition">世界観設定に追加</span>
                                        </label>
                                        <label className="flex items-center gap-2 cursor-pointer group">
                                            <input 
                                                type="radio" 
                                                name={`action-${name}`} 
                                                checked={selectedTerms[name]?.action === 'knowledge'} 
                                                onChange={() => setSelectedTerms(prev => ({ ...prev, [name]: { action: 'knowledge' } }))}
                                                className="w-4 h-4 bg-gray-900 border-gray-600 text-indigo-600 focus:ring-indigo-500"
                                            />
                                            <span className="text-xs text-gray-400 group-hover:text-gray-200 transition">ナレッジに追加</span>
                                        </label>
                                        <label className="flex items-center gap-2 cursor-pointer group">
                                            <input 
                                                type="radio" 
                                                name={`action-${name}`} 
                                                checked={!selectedTerms[name] || selectedTerms[name]?.action === 'ignore'} 
                                                onChange={() => setSelectedTerms(prev => ({ ...prev, [name]: { action: 'ignore' } }))}
                                                className="w-4 h-4 bg-gray-900 border-gray-600 text-indigo-600 focus:ring-indigo-500"
                                            />
                                            <span className="text-xs text-gray-400 group-hover:text-gray-200 transition">無視</span>
                                        </label>
                                    </div>
                                </div>
                            </div>
                        ))}
                        {lastAnalysisResult.worldTerms.new.length === 0 && (
                            <p className="text-sm text-gray-500 italic px-4">反映可能な新規用語は見つかりませんでした。</p>
                        )}
                    </div>
                  </section>

                  {/* セリフ解析結果 */}
                  <section>
                    <h3 className="text-lg font-bold text-amber-300 mb-4 border-b border-amber-500/30 pb-2 flex items-center gap-2">
                        <Icons.PenSquareIcon className="h-5 w-5" /> セリフ解析（参考）
                    </h3>
                    <div className="bg-amber-900/10 border border-amber-500/20 rounded-lg p-4 mb-4">
                        <p className="text-xs text-amber-200/70">
                            ※ セリフ的な話者はAIによる推定です。この情報は既存設定の補完には反映されませんが、本文取り込み時の参考にしてください。
                        </p>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                        {lastAnalysisResult.dialogues.map((d, i) => (
                            <div key={i} className="bg-gray-800/50 p-3 rounded-lg border border-gray-700/50 text-sm">
                                <p className="text-gray-300 italic mb-2 select-all">"{d.text}"</p>
                                <div className="flex justify-between items-center text-[10px]">
                                    <span className="text-gray-500 uppercase tracking-tighter">AI 推定話者</span>
                                    <span className="text-amber-400 font-bold bg-amber-400/10 px-2 py-0.5 rounded">{d.possibleSpeaker || '不明'}</span>
                                </div>
                            </div>
                        ))}
                    </div>
                  </section>

                  {/* 解析ノート */}
                  {lastAnalysisResult.notes.length > 0 && (
                    <section className="bg-indigo-900/20 border border-indigo-500/30 p-4 rounded-xl">
                        <h4 className="text-sm font-bold text-indigo-300 mb-3 flex items-center gap-2">
                            <Icons.InfoIcon className="h-4 w-4" /> 解析ノート
                        </h4>
                        <ul className="list-disc list-inside space-y-2">
                            {lastAnalysisResult.notes.map((note, i) => (
                                <li key={i} className="text-xs text-indigo-200/80 leading-relaxed">{note}</li>
                            ))}
                        </ul>
                    </section>
                  )}

                  {/* 反映要約エリア */}
                  <div className="sticky bottom-0 bg-indigo-600 text-white p-4 rounded-lg shadow-2xl flex items-center justify-between animate-in slide-in-from-bottom duration-300">
                    <div className="flex items-center gap-6">
                        <div className="flex flex-col">
                            <span className="text-[10px] opacity-70 font-bold uppercase tracking-widest">SUMMARY</span>
                            <div className="flex gap-4 text-sm font-bold">
                                <span>キャラ: {reflectSummary.chars} 件追加</span>
                                <span>用語: {reflectSummary.terms} 件追加</span>
                            </div>
                        </div>
                    </div>
                    <button 
                        onClick={handleApply}
                        disabled={reflectSummary.chars === 0 && reflectSummary.terms === 0}
                        className="px-8 py-2 bg-white text-indigo-600 rounded-md font-bold hover:bg-indigo-50 transition active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        設定に反映して本文を取り込む
                    </button>
                  </div>

                </div>
              )}
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="p-4 border-t border-gray-700 flex justify-between items-center flex-shrink-0">
          <button
            onClick={step === 'reflect' ? handleBackToInput : closeModal}
            className="px-6 py-2 bg-gray-700 hover:bg-gray-600 text-white rounded-md transition font-bold flex items-center gap-2"
          >
            {step === 'reflect' ? <><Icons.ArrowLeftIcon className="h-4 w-4"/>戻る</> : 'キャンセル'}
          </button>

          {step === 'input' && lastAnalysisResult && (
              <button
                onClick={() => setStep('reflect')}
                className="px-6 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-md transition font-bold"
              >
                反映選択に進む
              </button>
          )}
        </div>
      </div>
    </div>
  );
};

import * as React from 'react';

export type UserMode = 'simple' | 'standard' | 'pro';

export interface AiSettings {
    perspective: string;
    length: number;
    tone: string;
    creativity: string;
    knowledgeAdherence: string;
    suggestionFrequency: string;
    memoryScope: string;
    assistantPersona: string;
    markdownFrequency: string;
    showSpeakerInDialogue: boolean;
    writingStyleMimicry: boolean;
    generateMultipleContinuations: boolean;
    applySpeakerColorToDialogue: boolean;
}

export interface DisplaySettings {
    theme: 'light' | 'sepia' | 'dark';
    fontFamily: string;
    fontSize: number;
    swapSidebars?: boolean;
}

export interface NovelChunk {
    id: string;
    text: string;
    memo?: string;
    isPinned?: boolean;
}

export interface ChatMessage {
    role: 'user' | 'assistant';
    text: string;
    mode: 'write' | 'consult';
}

export interface SettingItem {
    id: string;
    type: 'character' | 'world';
    name: string;
    longDescription?: string;
    memo?: string;
    exportDescription?: string;
    isAutoFilled?: boolean;

    // Character specific
    furigana?: string;
    gender?: string;
    age?: string;
    species?: string;
    firstPersonPronoun?: string;
    personality?: string;
    origin?: string;
    affiliation?: string;
    speechPattern?: string;
    secret?: string;
    themeColor?: string;
    hairColor?: string;
    eyeColor?: string;
    appearance?: {
        imageUrl: string;
        traits: { key: string, value: string }[];
    };

    // World specific
    fields?: { key: string, value: string }[];
    mapImageUrl?: string;
}

export interface KnowledgeItem {
    id: string;
    name: string;
    content: string;
    category?: string;
    tags?: string[];
    isPinned?: boolean;
    isAutoFilled?: boolean;
}

export interface PlotItem {
    id: string;
    title: string;
    summary: string;
    type: string;
    linkedEventId?: string;
    lastModified?: number;
}

export interface AnalysisResult {
  characters: {
    match: string[];
    similar: { text: string; target: string }[];
    new: string[];
  };
  worldTerms: {
    match: string[];
    similar: { text: string; target: string }[];
    new: string[];
  };
  dialogues: {
    text: string;
    possibleSpeaker: string | null;
  }[];
  notes: string[];
}

export interface AppState {
    allProjectsData: { [key: string]: Project };
    activeProjectId: string | null;
    userInput: string;
    isLoading: boolean;
    aiSuggestions: {
        knowledge: string[];
        plot: PlotItem[];
    };
    archivedKnowledgeSuggestions: { id: string; content: string }[];
    archivedPlotSuggestions: PlotItem[];
    generationMode: 'write' | 'consult';
    highlightedChunkId: string | null;
    projectTitle: string;
    editingChunkId: string | null;
    saveStatus: 'synced' | 'saving' | 'dirty';
    isImageGenerating: boolean;
    leftPanelTab: LeftPanelTab;
    floatingWindows: FloatingWindow[];
    isLeftSidebarOpen: boolean;
    isRightSidebarOpen: boolean;
    leftSidebarWidth: number;
    rightSidebarWidth: number;
    newChunkText: string;
    isNewChunkInputOpen: boolean;
    isLeftPanelDropdownOpen: boolean;
    continuationChoices: { id: string; title: string; text: string }[] | null;
    historyTree: HistoryTree;
    lastUserPrompt: string | null;
    draggedChapterId: string | null;
    dropTargetId: string | null;
    isTutorialActive: boolean;
    tutorialStep: number;
    isKnowledgeTutorialActive: boolean;
    knowledgeTutorialStep: number;
    isChartTutorialActive: boolean;
    chartTutorialStep: number;
    isPlotBoardTutorialActive: boolean;
    plotBoardTutorialStep: number;
    isTimelineTutorialActive: boolean;
    timelineTutorialStep: number;
    hasCompletedGlobalTutorial?: boolean;
    hasCompletedGlobalKnowledgeTutorial?: boolean;
    hasCompletedGlobalChartTutorial?: boolean;
    hasCompletedGlobalPlotBoardTutorial?: boolean;
    hasCompletedGlobalTimelineTutorial?: boolean;
    userMode: UserMode;
    undoScope: UndoScope;
    toast: ToastMessage | null;
    historyPanelHeight: number;
    isHistoryPanelDocked: boolean;
    highlightedEventId: string | null;

    // Unified Modal State
    activeModal: ModalType | null;
    modalPayload: any;
    isModalDirty: boolean;
    isConfirmingClose: boolean;
    pendingModalRequest: null | { type: ModalType; payload: any };

    // Quick Settings
    pinnedSettingIds: string[];

    // Analysis Results
    lastAnalysisResult: AnalysisResult | null;
}

export interface Project {
    id: string;
    name: string;
    lastModified: string;
    isSimpleMode?: boolean;
    settings: SettingItem[];
    novelContent: NovelChunk[];
    chatHistory: ChatMessage[];
    knowledgeBase: KnowledgeItem[];
    plotBoard: PlotItem[];
    plotTypeColors: { [key: string]: string };
    plotRelations: PlotRelation[];
    plotNodePositions: PlotNodePosition[];
    timeline: TimelineEvent[];
    timelineLanes: TimelineLane[];
    aiSettings: AiSettings;
    displaySettings: DisplaySettings;
    characterRelations: Relation[];
    nodePositions: NodePosition[];
    userProfile?: {
        iconUrl: string;
        name?: string;
    };
    historyTree?: HistoryTree;
}

export type LeftPanelTab = 'settings' | 'characters' | 'worlds' | 'knowledge' | 'plots' | 'outline' | 'history';

export interface FloatingWindow {
    id: string;
    type: LeftPanelTab;
    position: { x: number; y: number };
    size: { width: number; height: number };
    zIndex: number;
}

export type HistoryType = "editor" | "character" | "world" | "knowledge" | "plot" | "timeline" | "chart" | "ai" | "settings" | "outline";
export type UndoScope = "all" | "text-only" | "ai-only" | "data-only";

export interface HistoryNode {
  id: string;
  parentId: string | null;
  childrenIds: string[];
  timestamp: number;
  type: HistoryType;
  label: string;
  payload: Project;
}

export interface HistoryTree {
    nodes: Record<string, HistoryNode>;
    currentNodeId: string | null;
    rootId: string | null;
}

export interface ToastMessage {
    id: number;
    message: string;
    type: 'info' | 'success' | 'error';
}

export type ModalType =
  | 'character'
  | 'world'
  | 'knowledge'
  | 'plot'
  | 'aiSettings'
  | 'preview'
  | 'help'
  | 'generalHelp'
  | 'characterChart'
  | 'htmlExport'
  | 'timeline'
  | 'nameGenerator'
  | 'knowledgeBase'
  | 'chapterSettings'
  | 'globalSearch'
  | 'commandPalette'
  | 'syncDialog'
  | 'tutorialModeSelection'
  | 'displaySettings'
  | 'importText';

export interface AppActions {
    loadInitialState: () => void;
    setActiveProjectId: (id: string | null) => void;
    createProject: (projectName: string, mode: 'simple' | 'standard') => void;
    deleteProject: (projectId: string) => void;
    importProject: (event: React.ChangeEvent<HTMLInputElement>) => void;
    exportHtml: (options: any) => void;

    setSimpleMode: (isSimple: boolean) => void;
    setUserInput: (input: string) => void;
    setGenerationMode: (mode: 'write' | 'consult') => void;
    setHighlightedChunkId: (id: string | null) => void;
    setLeftPanelTab: (tab: LeftPanelTab) => void;
    addFloatingWindow: (type: LeftPanelTab) => void;
    removeFloatingWindow: (id: string) => void;
    focusWindow: (id: string) => void;
    updateWindowPosition: (id: string, position: { x: number; y: number }) => void;
    updateWindowSize: (id: string, size: { width: number; height: number }) => void;
    setIsLeftSidebarOpen: (isOpen: boolean | ((prev: boolean) => boolean)) => void;
    setIsRightSidebarOpen: (isOpen: boolean | ((prev: boolean) => boolean)) => void;
    setLeftSidebarWidth: (width: number) => void;
    setRightSidebarWidth: (width: number) => void;
    setNewChunkText: (text: string) => void;
    setIsNewChunkInputOpen: (isOpen: boolean | ((prev: boolean) => boolean)) => void;
    setIsLeftPanelDropdownOpen: (isOpen: boolean) => void;
    setContinuationChoices: (choices: { id: string; title: string; text: string }[] | null) => void;
    setProjectTitle: (title: string) => void;
    setIsEditingTitle: (isEditing: boolean) => void;

    // Unified Modal Actions
    openModal: (type: ModalType, payload?: any) => void;
    closeModal: () => void;
    forceCloseModal: () => void;
    confirmCloseAction: (action: 'save' | 'discard') => void;
    cancelCloseAction: () => void;
    setModalDirty: (isDirty: boolean) => void;

    setActiveProjectData: (updater: (data: Project) => Project, historyLabel?: { type: HistoryType; label: string }) => void;
    handleSaveSetting: (newItem: Partial<SettingItem | KnowledgeItem>, type?: 'character' | 'world' | 'knowledge') => void;
    handleDeleteSetting: (id: string, type: 'character' | 'world' | 'knowledge' | 'plot') => void;
    handleSavePlotBoard: (data: { items: PlotItem[], relations: PlotRelation[], positions: PlotNodePosition[], colors: { [key: string]: string } }) => void;
    handleDisplaySettingChange: (key: keyof DisplaySettings, value: any) => void;
    handleSaveChart: (relations: Relation[], positions: NodePosition[]) => void;
    handleSaveTimeline: (timeline: TimelineEvent[], lanes: TimelineLane[]) => void;
    handleSaveChapterSettings: (details: { id: string; newTitle: string; newMemo: string; isUncategorized: boolean }) => void;
    handleDeleteChapter: (chapterId: string) => void;

    setEditingChunkId: (id: string | null) => void;
    handleNovelTextChange: (chunkId: string, newText: string) => void;
    handleToggleChunkPin: (chunkId: string) => void;
    handleAddNewChunk: () => void;
    addChapter: () => void;
    handleChapterDrop: (dropOnChapterId: string) => void;

    submitMessage: (promptOverride?: string) => Promise<void>;
    handleAdoptContinuation: (text: string) => void;
    handleRejectContinuation: (id: string) => void;
    regenerateContinuations: () => Promise<void>;
    handleApproveSuggestion: (suggestion: any, type: 'knowledge' | 'plot') => void;
    handleRejectSuggestion: (suggestion: any, type: 'knowledge' | 'plot') => void;
    setIsImageGenerating: (isGenerating: boolean) => void;

    handleToggleKnowledgePin: (knowledgeId: string) => void;

    navigateToSetting: (item: SettingItem, type: 'character' | 'world') => void;
    navigateToKnowledge: (item: KnowledgeItem) => void;
    navigateToPlot: (item: PlotItem) => void;
    navigateToChunk: (chunkId: string) => void;
    navigateToEvent: (eventId: string) => void;
    setHighlightedEventId: (id: string | null) => void;

    addHistory: (projectData: Project, label: { type: HistoryType, label: string }) => void;
    undo: () => void;
    redo: () => void;
    jumpToHistory: (nodeId: string) => void;

    startTutorial: () => void;
    nextTutorialStep: () => void;
    prevTutorialStep: () => void;
    endTutorial: () => void;
    setTutorialStep: (step: number) => void;

    startKnowledgeTutorial: () => void;
    nextKnowledgeTutorialStep: () => void;
    endKnowledgeTutorial: () => void;
    setKnowledgeTutorialStep: (step: number) => void;

    startChartTutorial: () => void;
    nextChartTutorialStep: () => void;
    endChartTutorial: () => void;
    setChartTutorialStep: (step: number) => void;

    startPlotBoardTutorial: () => void;
    nextPlotBoardTutorialStep: () => void;
    endPlotBoardTutorial: () => void;
    setPlotBoardTutorialStep: (step: number) => void;

    startTimelineTutorial: () => void;
    nextTimelineTutorialStep: () => void;
    endTimelineTutorial: () => void;
    setTimelineTutorialStep: (step: number) => void;

    setUserMode: (mode: UserMode) => void;
    setUndoScope: (scope: UndoScope) => void;
    showToast: (message: string, type?: ToastMessage['type']) => void;
    setHistoryPanelHeight: (height: number) => void;
    setIsHistoryPanelDocked: (isDocked: boolean) => void;

    // Linking Actions
    createEventFromPlot: (plotId: string) => void;
    createPlotFromEvent: (eventId: string) => void;
    syncLinkedData: () => void;
    unlinkItems: () => void;

    // Quick Settings
    togglePinnedSetting: (id: string) => void;

    // Analysis
    analyzeImportedText: (text: string) => Promise<void>;
    clearAnalysisResult: () => void;
}

export interface Relation {
    id: string;
    source: string;
    target: string;
    label: string;
    color?: string;
    callName?: string;
}

export interface NodePosition {
    characterId: string;
    x: number;
    y: number;
}

export interface TimelineEvent {
    id: string;
    title: string;
    timestamp: string;
    description: string;
    laneId: string;
    locationId?: string;
    customLocationName?: string;
    linkedPlotId?: string;
    lastModified?: number;
}

export interface TimelineLane {
    id: string;
    name: string;
    color: string;
}

export interface PlotRelation {
    id: string;
    source: string;
    target: string;
    label: string;
    memo?: string;
    color?: string;
}

export interface PlotNodePosition {
    plotId: string;
    x: number;
    y: number;
}

import { v4 as uuidv4 } from 'uuid';
import { Project, SettingItem, KnowledgeItem, PlotItem, Relation, NodePosition, TimelineEvent, PlotRelation, PlotNodePosition, TimelineLane, DisplaySettings, NovelChunk, HistoryType, AnalysisResult } from '../types';
import { getChapterChunks, parseMarkdown } from '../utils';
import { FONT_MAP } from '../constants';
import * as analysisApi from '../analysisApi';

const initialState = {
    saveStatus: 'synced' as 'synced' | 'saving' | 'dirty',
    lastAnalysisResult: null as AnalysisResult | null,
};

export interface DataSlice {
    saveStatus: 'synced' | 'saving' | 'dirty';
    lastAnalysisResult: AnalysisResult | null;
    setActiveProjectData: (updater: (data: Project) => Project, historyLabel?: { type: HistoryType; label: string }, options?: { mode: 'merge' | 'replace' }) => void;
    handleSaveSetting: (newItem: Partial<SettingItem | KnowledgeItem>, type?: 'character' | 'world' | 'knowledge') => void;
    handleDeleteSetting: (id: string, type: 'character' | 'world' | 'knowledge' | 'plot', skipConfirm?: boolean) => void;
    handleSavePlotBoard: (data: { items: PlotItem[], relations: PlotRelation[], positions: PlotNodePosition[], colors: { [key: string]: string } }) => void;
    handleDisplaySettingChange: (key: keyof DisplaySettings, value: any) => void;
    handleSaveChart: (relations: Relation[], positions: NodePosition[]) => void;
    handleSaveTimeline: (timeline: TimelineEvent[], lanes: TimelineLane[]) => void;
    handleSaveChapterSettings: (details: { id: string; newTitle: string; newMemo: string; isUncategorized: boolean }) => void;
    handleDeleteChapter: (chapterId: string) => void;
    handleNovelTextChange: (chunkId: string, newText: string) => void;
    handleToggleChunkPin: (chunkId: string) => void;
    handleAddNewChunk: () => void;
    addChapter: () => void;
    handleChapterDrop: (dropOnChapterId: string) => void;
    handleToggleKnowledgePin: (knowledgeId: string) => void;
    navigateToSetting: (item: SettingItem, type: 'character' | 'world') => void;
    navigateToKnowledge: (item: KnowledgeItem) => void;
    navigateToPlot: (item: PlotItem) => void;
    navigateToChunk: (chunkId: string) => void;
    navigateToEvent: (eventId: string) => void;
    exportHtml: (options: any) => void;
    createEventFromPlot: (plotId: string) => void;
    createPlotFromEvent: (eventId: string) => void;
    syncLinkedData: () => void;
    unlinkItems: () => void;

    // Analysis
    analyzeImportedText: (text: string) => Promise<void>;
    clearAnalysisResult: () => void;
    applyAnalysisResults: (selections: {
        characters: { name: string; action: 'create' | 'link' | 'ignore'; targetId?: string }[];
        worldTerms: { name: string; action: 'world' | 'knowledge' | 'ignore' }[];
    }, importedText: string) => void;
}

export const createDataSlice = (set, get): DataSlice => ({
    ...initialState,
    setActiveProjectData: (updater, historyLabel, options = { mode: "merge" }) => {
        const { activeProjectId, allProjectsData, addHistory } = get();
        if (!activeProjectId) return;

        const currentProject = allProjectsData[activeProjectId];

        const newProjectData = updater(currentProject);

        set(state => ({
            allProjectsData: {
                ...state.allProjectsData,
                [activeProjectId]: newProjectData
            }
        }));

        if (historyLabel) {
            addHistory(newProjectData, historyLabel);
        }
    },
    handleSaveSetting: (newItem, type) => {
        const { activeModal } = get();
        const itemType = type || activeModal;
        const isNew = !newItem.id;
        const labelAction = isNew ? '作成' : '更新';
        const labelName = newItem.name || '無題';
        let labelType: HistoryType;
        let labelText: string;

        switch(itemType) {
            case 'character':
                labelType = 'character';
                labelText = `キャラクター「${labelName}」を${labelAction}`;
                break;
            case 'world':
                labelType = 'world';
                labelText = `世界観「${labelName}」を${labelAction}`;
                break;
            case 'knowledge':
                labelType = 'knowledge';
                labelText = `ナレッジ「${labelName}」を${labelAction}`;
                break;
            default:
                labelType = 'settings';
                labelText = '設定を更新';
        }

        get().setActiveProjectData(d => {
            let updatedProject = { ...d, lastModified: new Date().toISOString() };
            // セーブ時に自動補完フラグを折る
            const baseItem = { ...newItem, isAutoFilled: false };

            switch (itemType) {
                case 'character':
                case 'world':
                    const newSettings = newItem.id
                        ? d.settings.map(s => s.id === newItem.id ? { ...s, ...(baseItem as Partial<SettingItem>) } : s)
                        : [...d.settings, { ...baseItem, id: uuidv4(), type: itemType } as SettingItem];
                    updatedProject.settings = newSettings;
                    break;
                case 'knowledge':
                    const newKnowledgeBase = newItem.id
                        ? d.knowledgeBase.map(k => k.id === newItem.id ? { ...k, ...(baseItem as Partial<KnowledgeItem>) } : k)
                        : [...d.knowledgeBase, { ...baseItem, id: uuidv4() } as KnowledgeItem];
                    updatedProject.knowledgeBase = newKnowledgeBase;
                    break;
            }
            return updatedProject;
        }, { type: labelType, label: labelText });
        get().closeModal();
    },
    handleDeleteSetting: (id: string, type: 'character' | 'world' | 'knowledge' | 'plot', skipConfirm = false) => {
        if (!skipConfirm && !window.confirm('本当に削除しますか？この操作は取り消せません。')) {
            return;
        }

        const { activeProjectId, allProjectsData, setActiveProjectData } = get();
        if (!activeProjectId) return;
        const project = allProjectsData[activeProjectId];
        if (!project) return;

        let labelText = '';
        switch (type) {
            case 'character':
            case 'world':
                const setting = project.settings.find(s => s.id === id);
                labelText = `${type === 'character' ? 'キャラクター' : '世界観'}「${setting?.name || '無題'}」を削除`;
                break;
            case 'knowledge':
                const knowledge = project.knowledgeBase.find(k => k.id === id);
                labelText = `ナレッジ「${knowledge?.name || '無題'}」を削除`;
                break;
            case 'plot':
                const plot = project.plotBoard.find(p => p.id === id);
                labelText = `プロット「${plot?.title || '無題'}」を削除`;
                break;
        }

        setActiveProjectData(d => {
            let updatedProject = { ...d, lastModified: new Date().toISOString() };
            switch (type) {
                case 'character':
                case 'world':
                    updatedProject.settings = d.settings.filter(s => s.id !== id);
                    if (type === 'character') {
                        updatedProject.characterRelations = (d.characterRelations || []).filter(r => r.source !== id && r.target !== id);
                        updatedProject.nodePositions = (d.nodePositions || []).filter(p => p.characterId !== id);
                    }
                    if (type === 'world') {
                        updatedProject.timeline = (d.timeline || []).map(event => 
                            event.locationId === id ? { ...event, locationId: '' } : event
                        );
                    }
                    break;
                case 'knowledge':
                    updatedProject.knowledgeBase = d.knowledgeBase.filter(k => k.id !== id);
                    break;
                case 'plot':
                    updatedProject.plotBoard = d.plotBoard.filter(p => p.id !== id);
                    updatedProject.plotRelations = (d.plotRelations || []).filter(r => r.source !== id && r.target !== id);
                    updatedProject.plotNodePositions = (d.plotNodePositions || []).filter(p => p.plotId !== id);
                    updatedProject.timeline = (d.timeline || []).map(event => 
                        event.linkedPlotId === id ? { ...event, linkedPlotId: undefined } : event
                    );
                    break;
            }
            return updatedProject;
        }, { type, label: labelText });
        get().closeModal();
    },
    handleSavePlotBoard: (data: { items: PlotItem[], relations: PlotRelation[], positions: PlotNodePosition[], colors: { [key: string]: string } }) => {
        const { openModal, allProjectsData, activeProjectId, setActiveProjectData } = get();
        const oldProject = allProjectsData[activeProjectId];
        if (oldProject) {
            const oldPlotsMap = new Map(oldProject.plotBoard.map(p => [p.id, p]));
            const timelineMap = new Map(oldProject.timeline.map(e => [e.id, e]));

            for (const newPlot of data.items) {
                const oldPlot = oldPlotsMap.get(newPlot.id) as PlotItem | undefined;
                if (oldPlot && newPlot.linkedEventId && (newPlot.lastModified || 0) > (oldPlot.lastModified || 0)) {
                    const linkedEvent = timelineMap.get(newPlot.linkedEventId) as TimelineEvent | undefined;
                    if (linkedEvent && (linkedEvent.lastModified || 0) < (newPlot.lastModified || 0)) {
                        if(linkedEvent.title !== newPlot.title || linkedEvent.description !== newPlot.summary) {
                            openModal('syncDialog', { plotId: newPlot.id, eventId: newPlot.linkedEventId });
                        }
                    }
                }
            }
        }

        const currentProject = allProjectsData[activeProjectId];
        const newPlotIds = new Set(data.items.map(p => p.id));
        const updatedTimeline = currentProject ? currentProject.timeline.map(event => {
            if (event.linkedPlotId && !newPlotIds.has(event.linkedPlotId)) {
                return { ...event, linkedPlotId: undefined };
            }
            return event;
        }) : [];

        setActiveProjectData(d => ({
            ...d,
            plotBoard: data.items,
            plotRelations: data.relations,
            plotNodePositions: data.positions,
            plotTypeColors: data.colors,
            timeline: updatedTimeline,
            lastModified: new Date().toISOString(),
        }), { type: 'plot', label: 'プロットボードを更新' });
    },
    handleDisplaySettingChange: (key, value) => {
        get().setActiveProjectData(d => ({ ...d, displaySettings: { ...d.displaySettings, [key]: value } }), { type: 'settings', label: '表示設定を更新' });
    },
    handleSaveChart: (relations, positions) => {
        get().setActiveProjectData(d => ({ ...d, characterRelations: relations, nodePositions: positions, lastModified: new Date().toISOString() }), { type: 'chart', label: '相関図を更新' });
    },
    handleSaveTimeline: (timeline: TimelineEvent[], lanes: TimelineLane[]) => {
        const { openModal, allProjectsData, activeProjectId, setActiveProjectData } = get();
        const oldProject = allProjectsData[activeProjectId];
        if (oldProject) {
            const oldEventsMap = new Map(oldProject.timeline.map(e => [e.id, e]));
            const plotBoardMap = new Map(oldProject.plotBoard.map(p => [p.id, p]));

            for (const newEvent of timeline) {
                const oldEvent = oldEventsMap.get(newEvent.id) as TimelineEvent | undefined;
                if (oldEvent && newEvent.linkedPlotId && (newEvent.lastModified || 0) > (oldEvent.lastModified || 0)) {
                    const linkedPlot = plotBoardMap.get(newEvent.linkedPlotId) as PlotItem | undefined;
                    if (linkedPlot && (linkedPlot.lastModified || 0) < (newEvent.lastModified || 0)) {
                        if (linkedPlot.title !== newEvent.title || linkedPlot.summary !== newEvent.description) {
                            openModal('syncDialog', { plotId: newEvent.linkedPlotId, eventId: newEvent.id });
                        }
                    }
                }
            }
        }

        const currentProject = allProjectsData[activeProjectId];
        const newEventIds = new Set(timeline.map(e => e.id));
        const updatedPlotBoard = currentProject ? currentProject.plotBoard.map(plot => {
            if (plot.linkedEventId && !newEventIds.has(plot.linkedEventId)) {
                return { ...plot, linkedEventId: undefined };
            }
            return plot;
        }) : [];

        setActiveProjectData(d => ({ 
            ...d, 
            timeline: timeline, 
            timelineLanes: lanes, 
            plotBoard: updatedPlotBoard,
            lastModified: new Date().toISOString() 
        }), { type: 'timeline', label: 'タイムラインを更新' });
    },
    handleSaveChapterSettings: ({ id, newTitle, newMemo, isUncategorized }) => {
        get().setActiveProjectData(d => {
            if (isUncategorized) {
                const chapter = d.novelContent.find(c => c.id === id);
                if (!chapter) return d;
                const newTitleChunk: NovelChunk = { id: uuidv4(), text: `# ${newTitle}`, memo: newMemo };
                const firstContentChunkIndex = d.novelContent.findIndex(c => c.id === id);
                return { ...d, novelContent: [...d.novelContent.slice(0, firstContentChunkIndex), newTitleChunk, ...d.novelContent.slice(firstContentChunkIndex)] };
            } else {
                return { ...d, novelContent: d.novelContent.map(c => c.id === id ? { ...c, text: `# ${newTitle}`, memo: newMemo } : c) };
            }
        }, { type: 'outline', label: `章「${newTitle}」の設定を更新` });
    },
    handleDeleteChapter: (chapterId) => {
        const { activeProjectId, allProjectsData } = get();
        const activeProject = allProjectsData[activeProjectId];
        if (!activeProject) return;
        const chunks = activeProject.novelContent;
        const chapterIndex = chunks.findIndex(c => c.id === chapterId);
        if (chapterIndex === -1) return;
        let endIndex = chunks.length;
        for (let i = chapterIndex + 1; i < chunks.length; i++) {
            if (chunks[i].text.startsWith('# ')) {
                endIndex = i;
                break;
            }
        }
        const chapterTitle = chunks[chapterIndex].text.startsWith('# ') 
            ? chunks[chapterIndex].text.substring(2).trim() 
            : '章に属さない文章';

        get().setActiveProjectData(d => {
            const newNovelContent = [...d.novelContent];
            newNovelContent.splice(chapterIndex, endIndex - chapterIndex);
            return { ...d, novelContent: newNovelContent, lastModified: new Date().toISOString() };
        }, { type: 'outline', label: `章「${chapterTitle}」を削除` });
    },
    handleNovelTextChange: (chunkId, newText) => {
        get().setActiveProjectData(d => ({
            ...d,
            novelContent: d.novelContent.map(chunk => chunk.id === chunkId ? { ...chunk, text: newText } : chunk),
            lastModified: new Date().toISOString()
        }), { type: 'editor', label: '本文を編集' });
    },
    handleToggleChunkPin: (chunkId) => {
        get().setActiveProjectData(d => ({
            ...d,
            novelContent: d.novelContent.map(chunk => chunk.id === chunkId ? { ...chunk, isPinned: !chunk.isPinned } : chunk)
        }), { type: 'editor', label: '段落のピン留めを切り替え' });
    },
    handleAddNewChunk: () => {
        const { newChunkText } = get();
        if (!newChunkText.trim()) return;
        const newChunks = newChunkText.split(/\n\s*\n/).map(text => ({ id: uuidv4(), text: text.trim() })).filter(chunk => chunk.text);
        if (newChunks.length > 0) {
            get().setActiveProjectData(d => ({ ...d, novelContent: [...d.novelContent, ...newChunks] }), { type: 'editor', label: '新しい段落を追加' });
        }
        set({ newChunkText: '' });
    },
    addChapter: () => {
        const newChapterChunk: NovelChunk = { id: uuidv4(), text: '# 無題の章', memo: '' };
        get().setActiveProjectData(d => ({ ...d, novelContent: [...d.novelContent, newChapterChunk] }), { type: 'outline', label: '新しい章を追加' });
        get().openModal('chapterSettings', { id: newChapterChunk.id, title: '無題の章', memo: '', isUncategorized: false });
    },
    handleChapterDrop: (dropOnChapterId) => {
        const { draggedChapterId } = get();
        if (!draggedChapterId || draggedChapterId === dropOnChapterId) return;

        get().setActiveProjectData(d => {
            const novelContent = [...d.novelContent];
            const draggedChunks = getChapterChunks(novelContent, draggedChapterId);
            const dropOnChunks = getChapterChunks(novelContent, dropOnChapterId);
            if (draggedChunks.length === 0 || dropOnChunks.length === 0) return d;
            const draggedChunkIds = new Set(draggedChunks.map(c => c.id));
            const contentWithoutDragged = novelContent.filter(c => !draggedChunkIds.has(c.id));
            const dropIndex = contentWithoutDragged.findIndex(c => c.id === dropOnChunks[0].id);
            if (dropIndex === -1) return d;
            const newNovelContent = [
                ...contentWithoutDragged.slice(0, dropIndex),
                ...draggedChunks,
                ...contentWithoutDragged.slice(dropIndex)
            ];
            return { ...d, novelContent: newNovelContent, lastModified: new Date().toISOString() };
        }, { type: 'outline', label: '章の順序を変更' });
    },
    handleToggleKnowledgePin: (knowledgeId) => {
        get().setActiveProjectData(d => ({
            ...d,
            knowledgeBase: d.knowledgeBase.map(k => k.id === knowledgeId ? { ...k, isPinned: !k.isPinned } : k)
        }), { type: 'knowledge', label: 'ナレッジのピン留めを切り替え' });
    },
    navigateToSetting: (item, type) => { get().closeModal(); get().openModal(type, item); },
    navigateToKnowledge: (item) => { get().closeModal(); get().openModal('knowledge', item); },
    navigateToPlot: (item) => { get().closeModal(); get().openModal('plot', item); },
    navigateToChunk: (chunkId) => {
        get().closeModal();
        set({ highlightedChunkId: chunkId });
        setTimeout(() => document.getElementById(`chunk-${chunkId}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' }), 100);
    },
    navigateToEvent: (eventId: string) => {
        get().closeModal();
        get().openModal('timeline');
        set({ highlightedEventId: eventId });
    },
    createEventFromPlot: (plotId) => {
        const { setActiveProjectData, allProjectsData, activeProjectId, showToast } = get();
        const project = allProjectsData[activeProjectId];
        if (!project) return;
        const plot = project.plotBoard.find(p => p.id === plotId);
        if (!plot) return;
        if (plot.linkedEventId) {
            showToast('このプロットはすでにリンクされています', 'info');
            return;
        }
        const newEvent: TimelineEvent = {
            id: uuidv4(),
            title: plot.title,
            description: plot.summary,
            timestamp: '未設定',
            laneId: project.timelineLanes[0]?.id || 'default',
            linkedPlotId: plot.id,
            lastModified: Date.now(),
        };
        const updatedPlot = { ...plot, linkedEventId: newEvent.id, lastModified: Date.now() };
        setActiveProjectData(d => ({
            ...d,
            timeline: [...d.timeline, newEvent],
            plotBoard: d.plotBoard.map(p => p.id === plotId ? updatedPlot : p),
        }), { type: 'timeline', label: `プロットからイベント「${newEvent.title}」を作成` });
        showToast('タイムラインにイベントを追加しました', 'success');
    },
    createPlotFromEvent: (eventId) => {
        const { setActiveProjectData, allProjectsData, activeProjectId, showToast } = get();
        const project = allProjectsData[activeProjectId];
        if (!project) return;
        const event = project.timeline.find(e => e.id === eventId);
        if (!event) return;
        if (event.linkedPlotId) {
            showToast('このイベントはすでにリンクされています', 'info');
            return;
        }
        const newPlot: PlotItem = {
            id: uuidv4(),
            title: event.title,
            summary: event.description,
            type: '章のまとめ',
            linkedEventId: event.id,
            lastModified: Date.now(),
        };
        const updatedEvent = { ...event, linkedPlotId: newPlot.id, lastModified: Date.now() };
        setActiveProjectData(d => ({
            ...d,
            plotBoard: [...d.plotBoard, newPlot],
            timeline: d.timeline.map(e => e.id === eventId ? updatedEvent : e),
        }), { type: 'plot', label: `イベントからプロット「${newPlot.title}」を作成` });
        showToast('プロットカードを作成しました', 'success');
    },
    syncLinkedData: () => {
        const { modalPayload, setActiveProjectData, allProjectsData, activeProjectId, showToast } = get();
        if (!modalPayload) return;
        const project = allProjectsData[activeProjectId];
        const plot = project.plotBoard.find(p => p.id === modalPayload.plotId);
        const event = project.timeline.find(e => e.id === modalPayload.eventId);
        if (!plot || !event) return;
        const updatedEvent = {
            ...event,
            title: plot.title,
            description: plot.summary,
            lastModified: Date.now(),
        };
        const updatedPlot = { ...plot, lastModified: Date.now() };
        setActiveProjectData(d => ({
            ...d,
            timeline: d.timeline.map(e => e.id === updatedEvent.id ? updatedEvent : e),
            plotBoard: d.plotBoard.map(p => p.id === updatedPlot.id ? updatedPlot : p),
        }), { type: 'timeline', label: `リンクされたイベント「${plot.title}」を同期` });
        showToast('関連データを更新しました', 'success');
    },
    unlinkItems: () => {
        const { modalPayload, setActiveProjectData, allProjectsData, activeProjectId, showToast } = get();
        if (!modalPayload) return;
        const project = allProjectsData[activeProjectId];
        const plot = project.plotBoard.find(p => p.id === modalPayload.plotId);
        const event = project.timeline.find(e => e.id === modalPayload.eventId);
        if (!plot || !event) return;
        const updatedPlot = { ...plot, linkedEventId: undefined, lastModified: Date.now() };
        const updatedEvent = { ...event, linkedPlotId: undefined, lastModified: Date.now() };
        setActiveProjectData(d => ({
            ...d,
            plotBoard: d.plotBoard.map(p => p.id === updatedPlot.id ? { ...updatedPlot } : p),
            timeline: d.timeline.map(e => e.id === updatedEvent.id ? { ...updatedEvent } : e),
        }), { type: 'settings', label: `プロットとイベントのリンクを解除` });
        showToast('リンクを解除しました', 'info');
    },
    exportHtml: (options) => {
        const { activeProjectId, allProjectsData } = get();
        const project = allProjectsData[activeProjectId];
        if (!project) return;
        const { novelContent, settings, knowledgeBase, aiSettings } = project;
        const useCurrent = options.useCurrentStyle;
        const theme = useCurrent ? project.displaySettings.theme : options.theme;
        const fontFamily = useCurrent ? project.displaySettings.fontFamily : options.fontFamily;
        const fontSize = useCurrent ? project.displaySettings.fontSize : options.fontSize;
        const fontCss = FONT_MAP[fontFamily] || FONT_MAP['sans'];
        let themeStyles = '';
        switch(theme) {
            case 'sepia': themeStyles = `body { background-color: #fbf0d9; color: #5b4636; } h1, h2, h3 { color: #5b4636; border-color: #dcd3c1; } a { color: #5b4636; }`; break;
            case 'dark': themeStyles = `body { background-color: #1f2937; color: #d1d5db; } h1, h2, h3 { color: #e5e7eb; border-color: #4b5568; } a { color: #93c5fd; }`; break;
            default: themeStyles = `body { background-color: #ffffff; color: #111827; } h1, h2, h3 { color: #111827; border-color: #e5e7eb; } a { color: #2563eb; }`; break;
        }
        const escapeHtml = (unsafe) => unsafe.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#039;");
        const charactersToExport = settings.filter(s => s.type === 'character' && options.selectedCharacterIds.includes(s.id));
        const worldSettingsToExport = settings.filter(s => s.type === 'world' && options.selectedWorldIds.includes(s.id));
        const chapters = novelContent.map((chunk, index) => {
            if (chunk.text.startsWith('# ')) {
                return {
                    id: `ch-${chunk.id}`,
                    title: chunk.text.split('\n')[0].substring(2).trim(),
                    index: index
                };
            }
            return null;
        }).filter(Boolean);
        const body = `
            <div class="container">
                ${options.coverType !== 'none' ? `
                    <div class="cover">
                        ${(options.coverType === 'image_only' || options.coverType === 'image_with_text') && options.coverImageSrc ? `<img src="${escapeHtml(options.coverImageSrc)}" class="cover-image" alt="Cover Image">` : ''}
                        ${(options.coverType === 'text_only' || options.coverType === 'image_with_text') ? `
                            <h1 class="title">${escapeHtml(project.name)}</h1>
                            ${options.authorName ? `<p class="author">${escapeHtml(options.authorName)}</p>` : ''}
                        ` : ''}
                    </div>
                ` : ''}
                ${options.addToc && chapters.length > 0 ? `
                    <div class="toc">
                        <h2>目次</h2>
                        <ul>
                            ${chapters.map(ch => `<li><a href="#${ch.id}">${escapeHtml(ch.title)}</a></li>`).join('')}
                        </ul>
                    </div>
                ` : ''}
                <div class="content">
                    ${novelContent.map(chunk => {
                        const isTitle = chunk.text.startsWith('# ');
                        const chapterId = isTitle ? `ch-${chunk.id}` : '';
                        return `<div id="${chapterId}">${parseMarkdown(chunk.text, settings.filter(s => s.type === 'character'), knowledgeBase, aiSettings)}</div>`;
                    }).join('')}
                </div>
                ${charactersToExport.length > 0 ? `
                    <div class="appendix">
                        <h2>登場人物</h2>
                        ${charactersToExport.map(char => `
                            <div class="char-card">
                                ${options.addCharacterImages && char.appearance?.imageUrl ? `<img src="${escapeHtml(char.appearance.imageUrl)}" alt="${escapeHtml(char.name)}">` : ''}
                                <h3>${escapeHtml(char.name)} ${char.furigana ? `(${escapeHtml(char.furigana)})` : ''}</h3>
                                <p>${escapeHtml(char.exportDescription || char.personality || '')}</p>
                            </div>
                        `).join('')}
                    </div>
                ` : ''}
                ${worldSettingsToExport.length > 0 ? `
                    <div class="appendix">
                        <h2>世界観・用語集</h2>
                        ${worldSettingsToExport.map(world => `
                            <div>
                                <h3>${escapeHtml(world.name)}</h3>
                                <p>${escapeHtml(world.exportDescription || world.longDescription || '')}</p>
                            </div>
                        `).join('')}
                    </div>
                ` : ''}
                ${options.afterword ? `<div class="appendix"><h2>あとがき</h2><div>${parseMarkdown(options.afterword, [], [], aiSettings)}</div></div>` : ''}
            </div>
        `;
        const fullHtml = `<!DOCTYPE html><html lang="ja"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>${escapeHtml(project.name)}</title><style>body { font-family: ${fontCss}; font-size: ${fontSize}px; line-height: 1.8; margin: 0; padding: 0; } .container { max-width: 800px; margin: 4rem auto; padding: 2rem; } ${themeStyles} h1, h2, h3 { line-height: 1.3; font-weight: bold; } h1.title { font-size: 2.5em; text-align: center; margin-bottom: 0.5em; } h1.chapter-title { font-size: 1.5em; margin-top: 3em; border-bottom: 1px solid; padding-bottom: 0.5em; } h2 { font-size: 1.2em; margin-top: 2em; border-bottom: 1px solid; padding-bottom: 0.3em;} p.author { text-align: center; font-size: 1.2em; color: #888; margin-bottom: 4em; } .cover { text-align: center; margin-bottom: 4rem; } .cover-image { max-width: 100%; height: auto; max-height: 70vh; margin: 0 auto 2rem; } .content > div { margin: 1.5em 0; } .toc { margin-bottom: 4rem; padding: 1.5rem; border: 1px solid #ccc; border-radius: 8px; } .toc ul { list-style: none; padding-left: 0; } .toc a { text-decoration: none; } .appendix { margin-top: 4rem; border-top: 1px solid #ccc; padding-top: 2rem; } .appendix h2 { border-bottom: none; } .char-card { margin-bottom: 2rem; overflow: hidden; } .char-card img { max-width: 150px; float: left; margin-right: 1rem; border-radius: 4px; } ruby { ruby-position: over; } rt { font-size: 0.7em; } .knowledge-link { text-decoration: none; color: inherit; font-weight: bold; }</style></head><body>${body}</body></html>`;
        const blob = new Blob([fullHtml], { type: 'text/html;charset=utf-8' });
        const link = document.createElement('a');
        link.href = URL.createObjectURL(blob);
        link.download = `${project.name}.html`;
        link.click();
        URL.revokeObjectURL(link.href);
    },

    analyzeImportedText: async (text: string) => {
      const { activeProjectId, allProjectsData, showToast } = get();
      if (!activeProjectId) return;
      const project = allProjectsData[activeProjectId];

      set({ isLoading: true });
      const result = await analysisApi.analyzeTextForImport(
        text,
        project.settings.filter(s => s.type === 'character'),
        project.settings.filter(s => s.type === 'world'),
        project.knowledgeBase
      );
      set({ isLoading: false });

      // FIX: Explicitly check result.success === true to ensure literal narrowing
      if (result.success === true) {
        set({ lastAnalysisResult: result.data });
        showToast('テキスト解析が完了しました', 'success');
      } else {
        // FIX: result is now correctly narrowed to { success: false, error: Error }
        showToast(`解析に失敗しました: ${result.error.message}`, 'error');
      }
    },
    clearAnalysisResult: () => set({ lastAnalysisResult: null }),

    applyAnalysisResults: (selections, importedText) => {
        const { activeProjectId, setActiveProjectData, showToast } = get();
        if (!activeProjectId) return;

        setActiveProjectData(d => {
            let updatedSettings = [...d.settings];
            let updatedKnowledge = [...d.knowledgeBase];
            let updatedNovelContent = [...d.novelContent];

            const annotation = "【インポート解析による補完】\n";

            // 1. キャラクターの反映
            selections.characters.forEach(sel => {
                if (sel.action === 'create') {
                    const newChar: SettingItem = {
                        id: uuidv4(),
                        type: 'character',
                        name: sel.name,
                        personality: "性格・口調（推定）：" + annotation,
                        memo: "インポートテキスト由来（未確定）",
                        isAutoFilled: true,
                        fields: []
                    };
                    updatedSettings.push(newChar);
                } else if (sel.action === 'link' && sel.targetId) {
                    // 既存キャラの補足
                    updatedSettings = updatedSettings.map(s => {
                        if (s.id === sel.targetId) {
                            const currentMemo = s.memo || "";
                            return {
                                ...s,
                                memo: `${currentMemo}\n\n（インポートテキストからの補足：名称「${sel.name}」として登場）`
                            };
                        }
                        return s;
                    });
                }
            });

            // 2. 世界観・用語の反映
            selections.worldTerms.forEach(sel => {
                if (sel.action === 'world') {
                    const newWorld: SettingItem = {
                        id: uuidv4(),
                        type: 'world',
                        name: sel.name,
                        longDescription: annotation + "インポートテキスト由来の説明（ここに詳細を記述してください）",
                        isAutoFilled: true,
                        fields: []
                    };
                    updatedSettings.push(newWorld);
                } else if (sel.action === 'knowledge') {
                    const newKnowledge: KnowledgeItem = {
                        id: uuidv4(),
                        name: sel.name,
                        content: annotation + "出典：インポートテキスト",
                        isAutoFilled: true
                    };
                    updatedKnowledge.push(newKnowledge);
                }
            });

            // 3. 本文の追加
            const newChunk: NovelChunk = {
                id: uuidv4(),
                text: importedText.trim()
            };
            updatedNovelContent.push(newChunk);

            return {
                ...d,
                settings: updatedSettings,
                knowledgeBase: updatedKnowledge,
                novelContent: updatedNovelContent,
                lastModified: new Date().toISOString()
            };
        }, { type: 'settings', label: 'インポート解析結果を反映' });

        set({ lastAnalysisResult: null });
        showToast('解析結果を反映しました', 'success');
    }
});

import React, { useState, useEffect, useRef, useMemo } from 'react';
import * as Icons from '../../icons';
import { SettingItem } from '../../types';
import { NameGenerator } from '../NameGenerator';
import * as utilityApi from '../../utilityApi';
import { UnsavedChangesPopover } from '../UnsavedChangesPopover';
import { HelpPopover } from '../HelpPopover';
import { useStore } from '../../store/index';
import { compressImage } from '../../utils';

interface CharacterFormProps {
    isOpen: boolean;
    onClose: () => void;
    onSave: (item: any) => void;
    itemToEdit: SettingItem | null;
    allSettings: SettingItem[];
    onOpenCharacterGenModal: (data: Partial<SettingItem> | null) => void;
    onOpenImageGenModal: () => void;
    onShowHelp: () => void;
    isMobile?: boolean;
}

export const CharacterForm: React.FC<CharacterFormProps> = ({
    isOpen,
    onClose,
    onSave,
    itemToEdit,
    allSettings,
    onOpenCharacterGenModal,
    onOpenImageGenModal,
    onShowHelp,
    isMobile = false,
}) => {
    // Local form state
    const [name, setName] = useState('');
    const [appearance, setAppearance] = useState<{ imageUrl: string; traits: { key: string; value: string }[] }>({ imageUrl: '', traits: [] });
    const [furigana, setFurigana] = useState('');
    const [gender, setGender] = useState('');
    const [age, setAge] = useState('');
    const [species, setSpecies] = useState('');
    const [firstPersonPronoun, setFirstPersonPronoun] = useState('');
    const [personality, setPersonality] = useState('');
    const [speechPattern, setSpeechPattern] = useState('');
    const [secret, setSecret] = useState('');
    const [themeColor, setThemeColor] = useState('');
    const [longDescription, setLongDescription] = useState('');
    const [memo, setMemo] = useState('');
    const [exportDescription, setExportDescription] = useState('');
    const [originSelection, setOriginSelection] = useState('');
    const [customOriginValue, setCustomOriginValue] = useState('');
    const [affiliationSelection, setAffiliationSelection] = useState('');
    const [customAffiliationValue, setCustomAffiliationValue] = useState('');

    const [activeTab, setActiveTab] = useState('profile');
    const [isNameGeneratorOpen, setIsNameGeneratorOpen] = useState(false);
    const [isConfirmCloseOpen, setIsConfirmCloseOpen] = useState(false);
    const [initialStateString, setInitialStateString] = useState('');
    const closeButtonRef = useRef(null);
    const originHelpRef = useRef(null);
    const [isOriginHelpOpen, setIsOriginHelpOpen] = useState(false);
    const affiliationHelpRef = useRef(null);
    const [isAffiliationHelpOpen, setIsAffiliationHelpOpen] = useState(false);

    // フィールドごとの変更済みフラグ
    const [editedFields, setEditedFields] = useState<Set<string>>(new Set());

    // Subscribe to external form data changes from AI modal
    const characterFormData = useStore(state => state.characterFormData);

    const organizationOptions = useMemo(() => {
        if (!allSettings) return [];
        return allSettings.filter(item =>
            item.type === 'world' &&
            item.fields?.some(f => f.key === '種別' && ['国家', 'ギルド', '秘密結社', '企業'].includes(f.value))
        );
    }, [allSettings]);

    const locationOptions = useMemo(() => {
        if (!allSettings) return [];
        const organizationIds = new Set(organizationOptions.map(org => org.id));
        return allSettings.filter(item => item.type === 'world' && !organizationIds.has(item.id));
    }, [allSettings, organizationOptions]);


    const populateState = (data) => {
        if (!data) return;

        setName(data.name || '');
        setAppearance(data.appearance || { imageUrl: '', traits: [] });
        setFurigana(data.furigana || '');
        setGender(data.gender || '');
        setAge(data.age || '');
        setSpecies(data.species || '');
        setFirstPersonPronoun(data.firstPersonPronoun || '');
        setPersonality(data.personality || '');
        setSpeechPattern(data.speechPattern || '');
        setSecret(data.secret || '');
        setThemeColor(data.themeColor || '');
        setLongDescription(data.longDescription || '');
        setMemo(data.memo || '');
        setExportDescription(data.exportDescription || '');

        const initialOrigin = data.origin || '';
        const isStandardOrigin = locationOptions.some(o => o.name === initialOrigin);
        if (isStandardOrigin) {
            setOriginSelection(initialOrigin);
            setCustomOriginValue('');
        } else if (initialOrigin) {
            setOriginSelection('その他');
            setCustomOriginValue(initialOrigin);
        } else {
            setOriginSelection('');
            setCustomOriginValue('');
        }

        const initialAffiliation = data.affiliation || '';
        const isStandardAffiliation = organizationOptions.some(o => o.name === initialAffiliation);
        if (isStandardAffiliation) {
            setAffiliationSelection(initialAffiliation);
            setCustomAffiliationValue('');
        } else if (initialAffiliation) {
            setAffiliationSelection('その他');
            setCustomAffiliationValue(initialAffiliation);
        } else {
            setAffiliationSelection('');
            setCustomAffiliationValue('');
        }
    };

    useEffect(() => {
        if (Object.keys(characterFormData).length > 0) {
            const currentData = getCurrentState();
            const mergedData = { ...currentData, ...characterFormData };
            populateState(mergedData);
        }
    }, [characterFormData]);

    const getCurrentState = (): Partial<SettingItem> => {
        const finalOrigin = originSelection === 'その他' ? customOriginValue : originSelection;
        const finalAffiliation = affiliationSelection === 'その他' ? customAffiliationValue : affiliationSelection;
        return { name, furigana, gender, age, species, firstPersonPronoun, personality, origin: finalOrigin, affiliation: finalAffiliation, speechPattern, secret, themeColor, longDescription, memo, exportDescription, appearance };
    };

    const isDirty = useMemo(() => {
        if (!initialStateString) return false;
        return JSON.stringify(getCurrentState()) !== initialStateString;
    }, [name, furigana, gender, age, species, firstPersonPronoun, personality, originSelection, customOriginValue, affiliationSelection, customAffiliationValue, speechPattern, secret, themeColor, longDescription, memo, exportDescription, appearance, initialStateString]);

    useEffect(() => {
        if (isOpen) {
            const initialData = {
                name: itemToEdit?.name || '',
                appearance: itemToEdit?.appearance || { imageUrl: '', traits: [] },
                furigana: itemToEdit?.furigana || '',
                gender: itemToEdit?.gender || '',
                age: itemToEdit?.age || '',
                species: itemToEdit?.species || '',
                firstPersonPronoun: itemToEdit?.firstPersonPronoun || '',
                personality: itemToEdit?.personality || '',
                origin: itemToEdit?.origin || '',
                affiliation: itemToEdit?.affiliation || '',
                speechPattern: itemToEdit?.speechPattern || '',
                secret: itemToEdit?.secret || '',
                themeColor: itemToEdit?.themeColor || '',
                longDescription: itemToEdit?.longDescription || '',
                memo: itemToEdit?.memo || '',
                exportDescription: itemToEdit?.exportDescription || '',
            };
            populateState(initialData);
            useStore.getState().setFormData('character', initialData);
            setEditedFields(new Set());
            setActiveTab('profile');

            setTimeout(() => {
                setInitialStateString(JSON.stringify(getCurrentState()));
            }, 0);
        }
    }, [isOpen, itemToEdit]);

    useEffect(() => {
  if (!isMobile) return;
  const setVh = () => {
    document.documentElement.style.setProperty('--vh', `${window.innerHeight * 0.01}px`);
  };
  setVh();
  window.addEventListener('resize', setVh);
  return () => window.removeEventListener('resize', setVh);
}, [isMobile]);

    const handleImageUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = async () => {
                const result = reader.result as string;
                const compressed = await compressImage(result);
                setAppearance(prev => ({ ...prev, imageUrl: compressed }));
                markEdited('imageUrl');
            };
            reader.readAsDataURL(file);
        }
    };

    const handleAddTrait = () => setAppearance(prev => ({ ...prev, traits: [...(prev?.traits || []), { key: '', value: '' }] }));
    const handleRemoveTrait = (index) => setAppearance(prev => ({ ...prev, traits: (prev?.traits || []).filter((_, i) => i !== index) }));
    const handleTraitChange = (index, prop, value) => { 
        const newTraits = [...(appearance?.traits || [])]; 
        newTraits[index][prop] = value; 
        setAppearance(prev => ({ ...prev, traits: newTraits })); 
        markEdited('traits');
    };

    const markEdited = (fieldName: string) => {
        setEditedFields(prev => new Set(prev).add(fieldName));
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        if (!name.trim()) return;

        const characterData = {
            ...itemToEdit,
            ...getCurrentState(),
            type: 'character',
            appearance: { ...(appearance || {}), traits: (appearance?.traits || []).filter(t => t.key.trim() !== '') },
        };
        onSave(characterData);
    };

    const handleKeyDown = (e: React.KeyboardEvent<HTMLFormElement>) => {
        if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
            e.preventDefault();
            (e.currentTarget as HTMLFormElement).requestSubmit();
        }
    };

    const handleCloseRequest = () => {
        if (isDirty) {
            setIsConfirmCloseOpen(true);
        } else {
            onClose();
        }
    };

    const handleSaveAndClose = () => {
        (document.getElementById('character-form') as HTMLFormElement)?.requestSubmit();
        setIsConfirmCloseOpen(false);
    };

    const handleOpenCharacterGen = () => {
        const currentData = getCurrentState();
         const cleanedData: Partial<SettingItem> = Object.fromEntries(
            Object.entries(currentData).filter(([_, v]) => {
                if (typeof v === 'string') return v.trim() !== '';
                if (Array.isArray(v)) return v.length > 0;
                if (typeof v === 'object' && v !== null) { // for appearance
                    return (v.imageUrl && v.imageUrl.trim() !== '') || (v.traits && v.traits.length > 0);
                }
                return false;
            })
        );
        onOpenCharacterGenModal(Object.keys(cleanedData).length > 0 ? cleanedData : null);
    };

    const characterKeywords = useMemo(() => {
        const keywords = [
            species,
            personality,
            gender,
            ...(appearance?.traits || []).map(t => t.value)
        ];
        return keywords.filter(Boolean).join(', ');
    }, [species, personality, gender, appearance?.traits]);

    const handleGenerateNames = async (category: string, keywords: string): Promise<string[]> => {
        const result = await utilityApi.generateNames({ category, keywords });
        if (result.success === false) {
            alert(`名前の生成に失敗しました: ${result.error.message}`);
            return [];
        }
        return result.data;
    };

    const TabButton = ({ tabId, label }: { tabId: string; label: React.ReactNode }) => (
        <button type="button" onClick={() => setActiveTab(tabId)} className={`px-4 py-2 text-sm font-medium transition-colors ${activeTab === tabId ? 'border-b-2 border-indigo-400 text-indigo-400' : 'border-b-2 border-transparent text-gray-400 hover:text-gray-200'}`}>
            {label}
        </button>
    );

    const handleOriginSelectChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        setOriginSelection(e.target.value);
        if (e.target.value !== 'その他') setCustomOriginValue('');
        markEdited('origin');
    };

    const handleAffiliationSelectChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        setAffiliationSelection(e.target.value);
        if (e.target.value !== 'その他') setCustomAffiliationValue('');
        markEdited('affiliation');
    };

    const renderLabel = (label: string, fieldKey?: string, helpNode?: React.ReactNode) => {
        const isAuto = itemToEdit?.isAutoFilled && fieldKey && !editedFields.has(fieldKey);
        return (
            <div className="flex items-center justify-between mb-1">
                <div className="flex items-center gap-2">
                    <label className="text-sm font-medium text-gray-400">{label}</label>
                    {helpNode}
                    {isAuto && (
                        <span className="text-[10px] bg-indigo-500/20 text-indigo-400 border border-indigo-500/50 px-1.5 py-0.5 rounded font-bold animate-pulse">補完済み</span>
                    )}
                </div>
            </div>
        );
    };

    const modalTitle = itemToEdit ? 'キャラクターを編集' : 'キャラクターを新規作成';
    const imageUrlValue = appearance?.imageUrl ?? '';

    // Styles for mobile optimization
    const modalContainerClass = isMobile 
    ? "bg-gray-900 w-full h-[100dvh] flex flex-col min-h-0 z-[60]" 
    : "bg-gray-800 rounded-lg shadow-xl w-full max-w-4xl border border-gray-700 max-h-[90vh] flex flex-col min-h-0 overflow-hidden";

    const inputClass = `w-full bg-gray-900 border border-gray-600 rounded-md px-3 py-2 text-white ${isMobile ? 'text-base' : 'text-sm'}`;
    const buttonClass = (colorClass: string) => `${colorClass} text-white rounded-md transition btn-pressable flex items-center justify-center gap-2 ${isMobile ? 'p-3 text-base w-full' : 'px-4 py-2 text-sm'}`;

    return (
        <div className={isMobile ? "fixed inset-0 z-[60]" : "fixed inset-0 bg-black/60 backdrop-blur-sm flex justify-center items-center z-50"}>
            <div className={modalContainerClass}>
                <UnsavedChangesPopover isOpen={isConfirmCloseOpen} targetRef={closeButtonRef} onCancel={() => setIsConfirmCloseOpen(false)} onCloseWithoutSaving={onClose} onSaveAndClose={handleSaveAndClose} />

                <div className={`flex justify-between items-center flex-shrink-0 ${isMobile ? 'p-4 border-b border-gray-700' : 'p-6 pb-0 mb-4'}`}>
                    <h2 className={`font-bold text-indigo-400 flex items-center gap-2 ${isMobile ? 'text-lg' : 'text-xl'}`}><Icons.UserPlusIcon />{modalTitle}</h2>
                    <div className="flex items-center gap-2">
                        <button type="button" onClick={onShowHelp} className="p-2 rounded-full hover:bg-gray-700 transition"><Icons.HelpCircleIcon className="h-5 w-5 text-white" /></button>
                        <button ref={closeButtonRef} type="button" onClick={handleCloseRequest} className="p-2 rounded-full hover:bg-gray-700 transition"><Icons.XIcon /></button>
                    </div>
                </div>

                <div className={`flex border-b border-gray-700 mb-6 flex-shrink-0 ${isMobile ? 'overflow-x-auto' : 'px-6'}`}>
                    <TabButton tabId="profile" label="プロフィール" />
                    <TabButton tabId="personality" label="性格・内面" />
                    <TabButton tabId="ai_settings" label="AI設定" />
                </div>

                <form id="character-form" onSubmit={handleSubmit} onKeyDown={handleKeyDown} className={`flex-grow overflow-y-auto min-h-0 ${isMobile ? 'px-4 pb-4' : 'px-6 py-2'}`}>
                    <div className="space-y-6">
                        {activeTab === 'profile' && (
                            <div className={`grid ${isMobile ? 'grid-cols-1 gap-6' : 'grid-cols-1 md:grid-cols-3 gap-6'}`}>
                                <div className={`space-y-4 ${isMobile ? 'order-first' : 'md:col-span-1'}`}>
                                    <div>
                                        {renderLabel("画像", "imageUrl")}
                                        {imageUrlValue ? (
                                            <div className="w-[60%] aspect-square rounded-md overflow-hidden mx-auto border border-gray-600">
                                                <img src={imageUrlValue} alt="Character" className="object-cover object-top w-full h-full" />
                                            </div>
                                        ) : (
                                            <div className="w-[60%] aspect-square flex items-center justify-center bg-gray-700 text-gray-500 text-sm font-bold rounded-md mx-auto border border-gray-600">
                                                NO IMAGE
                                            </div>
                                        )}
                                    </div>
                                    <input type="text" value={imageUrlValue.startsWith('data:') ? '' : imageUrlValue} onChange={e => { setAppearance(prev => ({ ...prev, imageUrl: e.target.value })); markEdited('imageUrl'); }} placeholder="画像URL..." className={inputClass} />
                                    <div className="space-y-3">
                                        <label className={`w-full flex items-center justify-center gap-2 border-2 border-dashed border-gray-600 rounded-lg hover:bg-gray-700/50 hover:border-indigo-500 cursor-pointer transition btn-pressable text-indigo-300 ${isMobile ? 'py-3' : 'py-1.5 text-sm'}`}>
                                            <input type="file" onChange={handleImageUpload} accept="image/*" className="hidden" />
                                            <Icons.UploadCloudIcon className="h-5 w-5" />
                                            <span>ファイルを選択</span>
                                        </label>
                                        <button type="button" onClick={onOpenImageGenModal} className={`w-full flex items-center justify-center gap-2 border-2 border-dashed border-gray-600 rounded-lg transition btn-pressable text-teal-300 hover:bg-gray-700/50 hover:border-teal-500 ${isMobile ? 'py-3' : 'py-1.5 text-sm'}`}>
                                            <Icons.MoonIcon className="h-5 w-5" />
                                            <span className="text-teal-400">AIで立ち絵を生成</span>
                                        </button>
                                    </div>
                                    <div>
                                        {renderLabel("テーマカラー", "themeColor")}
                                        <div className="flex items-center gap-2">
                                            <input type="color" value={themeColor || '#ffffff'} onChange={e => { setThemeColor(e.target.value); markEdited('themeColor'); }} className="w-full h-10 p-1 bg-gray-900 border border-gray-600 rounded-md cursor-pointer flex-grow" />
                                            <button type="button" onClick={() => { setThemeColor(''); markEdited('themeColor'); }} className="w-12 h-10 flex items-center justify-center bg-gray-700 text-gray-400 rounded-md hover:opacity-75 transition btn-pressable flex-shrink-0"><Icons.EraserIcon className="h-5 w-5" /></button>
                                        </div>
                                    </div>
                                </div>

                                <div className={`space-y-6 ${isMobile ? '' : 'md:col-span-2'}`}>
                                    <div className={`grid ${isMobile ? 'grid-cols-1 gap-4' : 'grid-cols-1 md:grid-cols-2 gap-x-6 gap-y-4'}`}>
                                         <div className={isMobile ? "" : "md:col-span-2"}>
                                            {renderLabel("名前 *", "name")}
                                            <div className="flex items-center gap-2">
                                                <input type="text" value={name} onChange={e => { setName(e.target.value); markEdited('name'); }} className={inputClass} required />
                                                <button type="button" onClick={() => setIsNameGeneratorOpen(true)} className={`flex-shrink-0 text-gray-400 hover:text-indigo-400 bg-gray-900 border border-gray-600 rounded-md ${isMobile ? 'p-3' : 'p-2'}`}><Icons.DiceIcon className="h-5 w-5"/></button>
                                            </div>
                                        </div>
                                        <div>{renderLabel("ふりがな", "furigana")}<input type="text" value={furigana} onChange={e => { setFurigana(e.target.value); markEdited('furigana'); }} className={inputClass}/></div>
                                        <div>{renderLabel("性別", "gender")}<input type="text" value={gender} onChange={e => { setGender(e.target.value); markEdited('gender'); }} className={inputClass}/></div>
                                        <div>{renderLabel("年齢", "age")}<input type="text" value={age} onChange={e => { setAge(e.target.value); markEdited('age'); }} className={inputClass}/></div>
                                        <div>{renderLabel("種族", "species")}<input type="text" value={species} onChange={e => { setSpecies(e.target.value); markEdited('species'); }} className={inputClass}/></div>
                                         <div className={isMobile ? "" : "md:col-span-1"}>
                                            {renderLabel("出身地", "origin", <button type="button" ref={originHelpRef} onMouseEnter={() => setIsOriginHelpOpen(true)} onMouseLeave={() => setIsOriginHelpOpen(false)} className="focus:outline-none"><Icons.HelpCircleIcon className="h-4 w-4 text-gray-500 hover:text-white" /></button>)}
                                            <select value={originSelection} onChange={handleOriginSelectChange} className={inputClass}>
                                                <option value="">未設定</option>
                                                {locationOptions.map(loc => (<option key={loc.id} value={loc.name}>{loc.name}</option>))}
                                                <option value="その他">その他（自由記入）</option>
                                            </select>
                                            {originSelection === 'その他' && <input type="text" value={customOriginValue} onChange={e => { setCustomOriginValue(e.target.value); markEdited('origin'); }} placeholder="内容..." className={`${inputClass} mt-2`} autoFocus />}
                                        </div>
                                        <div className={isMobile ? "" : "md:col-span-1"}>
                                            {renderLabel("所属組織", "affiliation", <button type="button" ref={affiliationHelpRef} onMouseEnter={() => setIsAffiliationHelpOpen(true)} onMouseLeave={() => setIsAffiliationHelpOpen(false)} className="focus:outline-none"><Icons.HelpCircleIcon className="h-4 w-4 text-gray-500 hover:text-white" /></button>)}
                                            <select value={affiliationSelection} onChange={handleAffiliationSelectChange} className={inputClass}>
                                                <option value="">未設定</option>
                                                {organizationOptions.map(org => (<option key={org.id} value={org.name}>{org.name}</option>))}
                                                <option value="その他">その他（自由記入）</option>
                                            </select>
                                            {affiliationSelection === 'その他' && <input type="text" value={customAffiliationValue} onChange={e => { setCustomAffiliationValue(e.target.value); markEdited('affiliation'); }} placeholder="内容..." className={`${inputClass} mt-2`} autoFocus />}
                                        </div>
                                    </div>
                                    <div className="space-y-3">
                                        {renderLabel("容姿特徴リスト", "traits")}
                                        {(appearance?.traits || []).map((trait, index) => (
                                            <div key={index} className="flex items-center gap-2">
                                                <input type="text" value={trait.key} onChange={e => handleTraitChange(index, 'key', e.target.value)} placeholder="項目" className={`w-1/3 ${inputClass}`}/>
                                                <input type="text" value={trait.value} onChange={e => handleTraitChange(index, 'value', e.target.value)} placeholder="内容" className={`flex-grow ${inputClass}`}/>
                                                <button type="button" onClick={() => handleRemoveTrait(index)} className={`text-gray-500 hover:text-red-400 transition flex-shrink-0 ${isMobile ? 'p-3' : 'p-2'}`}><Icons.TrashIcon/></button>
                                            </div>
                                        ))}
                                        <button type="button" onClick={handleAddTrait} className={`w-full text-indigo-400 border-2 border-dashed border-gray-600 rounded-md hover:bg-gray-700/50 ${isMobile ? 'py-3 text-base' : 'py-1 text-sm'}`}>特徴を追加</button>
                                    </div>
                                </div>
                            </div>
                        )}
                        {activeTab === 'personality' && ( 
                            <div className="space-y-6">
                                <div>{renderLabel("一人称", "firstPersonPronoun")}<input type="text" value={firstPersonPronoun} onChange={e => { setFirstPersonPronoun(e.target.value); markEdited('firstPersonPronoun'); }} placeholder="例：私、僕" className={inputClass}/></div>
                                <div>{renderLabel("性格", "personality")}<textarea value={personality} onChange={e => { setPersonality(e.target.value); markEdited('personality'); }} rows={6} className={`${inputClass} resize-y`} /></div>
                                <div>{renderLabel("話し方", "speechPattern")}<textarea value={speechPattern} onChange={e => { setSpeechPattern(e.target.value); markEdited('speechPattern'); }} rows={4} className={`${inputClass} resize-y`} /></div>
                                <div>{renderLabel("秘密", "secret")}<textarea value={secret} onChange={e => { setSecret(e.target.value); markEdited('secret'); }} rows={4} className={`${inputClass} resize-y`} /></div>
                            </div>
                        )}
                        {activeTab === 'ai_settings' && (
                            <div className="space-y-6">
                                <div>{renderLabel("詳細設定 (AIが参照)", "longDescription")}<textarea value={longDescription} onChange={e => { setLongDescription(e.target.value); markEdited('longDescription'); }} rows={8} className={`${inputClass} resize-y`} /></div>
                                <div>{renderLabel("メモ (AIは非参照)", "memo")}<textarea value={memo} onChange={e => { setMemo(e.target.value); markEdited('memo'); }} rows={5} className={`${inputClass} resize-y`} /></div>
                                <div>{renderLabel("書き出し用説明文", "exportDescription")}<textarea value={exportDescription} onChange={e => { setExportDescription(e.target.value); markEdited('exportDescription'); }} rows={5} className={`${inputClass} resize-y`} /></div>
                            </div>
                        )}
                    </div>
                </form>

                <div className={`border-t border-gray-700 bg-gray-900/50 flex-shrink-0 ${isMobile ? 'flex flex-col gap-3 px-4 pt-4' : 'flex justify-between items-center px-6 py-4'}`} style={isMobile ? { paddingBottom: 'calc(1rem + env(safe-area-inset-bottom))' } : {}}>
                    <button type="button" onClick={handleOpenCharacterGen} className={`flex items-center justify-center gap-2 font-semibold btn-pressable bg-teal-600 text-white hover:bg-teal-500 ${isMobile ? 'w-full py-3 rounded-md text-base order-1' : 'px-4 py-2 text-sm rounded-md transition'}`}><Icons.MoonIcon className={isMobile ? "h-5 w-5" : "h-4 w-4"} /><span>AIアシスタント</span></button>
                    <div className={`flex gap-3 ${isMobile ? 'flex-col w-full order-2' : ''}`}>
                        <button type="button" onClick={handleCloseRequest} className={buttonClass('bg-gray-600 hover:bg-gray-500')}><Icons.XIcon className="h-4 w-4" />キャンセル</button>
                        <button type="submit" form="character-form" data-testid="modal-save-button" className={buttonClass('bg-indigo-600 hover:bg-indigo-500 font-bold')}><Icons.CheckIcon className="h-4 w-4" />保存</button>
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
