            { key: '発生時期', value: '', type: 'text', placeholder: '例：王国歴345年、約1000年前' },
            { key: '主要な関係者', value: '', type: 'text', placeholder: '例：光の勇者と闇の魔王、〇〇帝国' },
            { key: '後世への影響', value: '', type: 'textarea', placeholder: '例：王家が交代した、禁断の技術として封印された' },
        ] 
