    item: {
        name: '重要アイテム',
        fields: [
            { key: '種別', value: '武器', type: 'select', options: ['武器', '防具', '道具', '秘宝', 'その他'] },
            { key: '由来・来歴', value: '', type: 'textarea', placeholder: '例：古代の鍛冶師が作った、神から授かった' },
            { key: '所有者', value: '', type: 'text', placeholder: '例：主人公、王家、敵のボス' },
