import React, { useState, useEffect, useRef, useMemo } from 'react';
import { createPortal } from 'react-dom';
import * as Icons from '../icons';
import { KnowledgeItem } from '../types';
import { UnsavedChangesPopover } from './UnsavedChangesPopover';
import { HelpPopover } from './HelpPopover';
import { useStore } from '../store/index';

export const KnowledgeModal: React.FC<{
    isOpen: boolean;
    onClose: () => void;
    onSave: (item: Partial<KnowledgeItem>, type?: 'knowledge') => void;
    itemToEdit: KnowledgeItem | null;
    allKnowledge: KnowledgeItem[];
    isMobile?: boolean;
}> = ({
    isOpen,
    onClose,
    onSave,
    itemToEdit,
    allKnowledge,
    isMobile = false,
}) => {
    const [name, setName] = useState('');
    const [content, setContent] = useState('');
    const [category, setCategory] = useState('');
    const [tags, setTags] = useState<string[]>([]);
    const [tagInput, setTagInput] = useState('');
    const [isConfirmCloseOpen, setIsConfirmCloseOpen] = useState(false);
    const [initialStateString, setInitialStateString] = useState('');
    const closeButtonRef = useRef<HTMLButtonElement>(null);
    const [isCategoryHelpOpen, setIsCategoryHelpOpen] = useState(false);
    const categoryHelpRef = useRef<HTMLButtonElement>(null);
    const setHelpTopic = useStore((state: any) => state.setHelpTopic);

    // 編集済みフラグ管理
    const [editedFields, setEditedFields] = useState<Set<string>>(new Set());

    useEffect(() => {
        if (isOpen) {
            const initialData = {
                name: itemToEdit?.name || '',
                content: itemToEdit?.content || '',
                category: itemToEdit?.category || '未分類',
                tags: itemToEdit?.tags || [],
            };
            setName(initialData.name);
            setContent(initialData.content);
            setCategory(initialData.category);
            setTags(initialData.tags);
            setTagInput('');
            setEditedFields(new Set());
            setInitialStateString(JSON.stringify(initialData));
        }
    }, [isOpen, itemToEdit]);

    const isDirty = useMemo(() => {
        if (!initialStateString) return false;
        const currentState = { name, content, category, tags };
        return JSON.stringify(currentState) !== initialStateString;
    }, [name, content, category, tags, initialStateString]);

    const existingCategories = useMemo(() => {
        if (!allKnowledge) return ['未分類'];
        const categories = new Set(allKnowledge.map(k => k.category).filter(Boolean));
        return ['未分類', ...Array.from(categories)];
    }, [allKnowledge]);

    const handleTagInputKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter' || e.key === ',') {
            e.preventDefault();
            const newTag = tagInput.trim();
            if (newTag && !tags.includes(newTag)) {
                setTags([...tags, newTag]);
                markEdited('tags');
            }
            setTagInput('');
        }
    };

    const handleRemoveTag = (tagToRemove: string) => {
        setTags(tags.filter(tag => tag !== tagToRemove));
        markEdited('tags');
    };

    const markEdited = (fieldKey: string) => {
        setEditedFields(prev => new Set(prev).add(fieldKey));
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!name.trim()) return;
        onSave({ ...itemToEdit, name, content, category, tags }, 'knowledge');
    };

    const handleKeyDown = (e: React.KeyboardEvent<HTMLFormElement>) => {
        if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
            e.preventDefault();
            e.currentTarget.requestSubmit();
        }
    };

    const handleCloseRequest = () => {
        if (isDirty) {
            setIsConfirmCloseOpen(true);
        } else {
            onClose();
        }
    };

    const handleSaveAndClose = () => {
        (document.getElementById('knowledge-form') as HTMLFormElement)?.requestSubmit();
        setIsConfirmCloseOpen(false);
    };

    const renderLabel = (label: string, fieldKey?: string, helpNode?: React.ReactNode) => {
        const isAuto = itemToEdit?.isAutoFilled && fieldKey && !editedFields.has(fieldKey);
        return (
            <div className="flex items-center gap-2 mb-1">
                <label className="text-sm font-medium text-gray-300">{label}</label>
                {helpNode}
                {isAuto && (
                    <span className="text-[10px] bg-indigo-500/20 text-indigo-400 border border-indigo-500/50 px-1.5 py-0.5 rounded font-bold animate-pulse">補完済み</span>
                )}
            </div>
        );
    };

    if (!isOpen) return null;

    const modalContainerClass = isMobile 
        ? "fixed inset-0 bg-gray-900 w-full h-[100dvh] flex flex-col z-[60]"
        : "bg-gray-800 rounded-lg shadow-xl w-full max-w-2xl p-6 border border-gray-700 max-h-[90vh] flex flex-col";

    const inputClass = `w-full bg-gray-900 border border-gray-600 rounded-md px-3 py-2 text-white ${isMobile ? 'text-base' : 'text-sm'}`;
    const buttonClass = (colorClass: string) => `${colorClass} text-white rounded-md transition btn-pressable flex items-center justify-center gap-2 ${isMobile ? 'p-3 text-base w-full' : 'px-4 py-2 text-sm'}`;

    return createPortal(
        <div className={isMobile ? "fixed inset-0 z-[60]" : "fixed inset-0 bg-black/60 backdrop-blur-sm flex justify-center items-center z-[80]"}>
            <div className={modalContainerClass}>
                <UnsavedChangesPopover
                    isOpen={isConfirmCloseOpen}
                    targetRef={closeButtonRef}
                    onCancel={() => setIsConfirmCloseOpen(false)}
                    onCloseWithoutSaving={() => { setIsConfirmCloseOpen(false); onClose(); }}
                    onSaveAndClose={handleSaveAndClose}
                />

                <div className={`flex justify-between items-center flex-shrink-0 ${isMobile ? 'p-4 border-b border-gray-700' : 'mb-4'}`}>
                    <h2 className={`font-bold text-yellow-400 flex items-center gap-2 ${isMobile ? 'text-lg' : 'text-xl'}`}>
                        <Icons.LightbulbIcon />
                        {itemToEdit ? 'ナレッジを編集' : 'ナレッジを新規作成'}
                    </h2>
                    <div className="flex items-center gap-2">
                        <button type="button" onClick={() => setHelpTopic && setHelpTopic('knowledgeBase')} className="p-2 rounded-full hover:bg-gray-700 transition" aria-label="ヘルプ">
                            <Icons.HelpCircleIcon className="h-5 w-5 text-white" />
                        </button>
                        <button ref={closeButtonRef} type="button" onClick={handleCloseRequest} className="p-2 rounded-full hover:bg-gray-700 transition"><Icons.XIcon /></button>
                    </div>
                </div>

                <form id="knowledge-form" onSubmit={handleSubmit} onKeyDown={handleKeyDown} className={`flex-grow overflow-y-auto min-h-0 ${isMobile ? 'px-4 pb-24' : 'pr-2'}`}>
                    <div className="space-y-6">
                        <div>
                            {renderLabel("名前 *", "name")}
                            <input
                                id="knowledge-name"
                                type="text"
                                value={name}
                                onChange={e => { setName(e.target.value); markEdited('name'); }}
                                className={inputClass}
                                required
                            />
                        </div>
                        <div className={`grid ${isMobile ? 'grid-cols-1 gap-6' : 'grid-cols-1 md:grid-cols-2 gap-4'}`}>
                            <div>
                                {renderLabel("カテゴリ", "category", (
                                    <button type="button" ref={categoryHelpRef} onMouseEnter={() => setIsCategoryHelpOpen(true)} onMouseLeave={() => setIsCategoryHelpOpen(false)} className="focus:outline-none">
                                        <Icons.HelpCircleIcon className="h-4 w-4 text-gray-400 hover:text-white" />
                                    </button>
                                ))}
                                <input
                                    id="knowledge-category"
                                    type="text"
                                    value={category}
                                    onChange={e => { setCategory(e.target.value); markEdited('category'); }}
                                    list="category-suggestions"
                                    className={inputClass}
                                />
                                <datalist id="category-suggestions">
                                    {existingCategories.map(cat => <option key={cat} value={cat} />)}
                                </datalist>
                            </div>
                            <div>
                                {renderLabel("タグ (Enterで追加)", "tags")}
                                <input
                                    id="knowledge-tags"
                                    type="text"
                                    value={tagInput}
                                    onChange={e => setTagInput(e.target.value)}
                                    onKeyDown={handleTagInputKeyDown}
                                    placeholder="タグを追加..."
                                    className={inputClass}
                                />
                                <div className="flex flex-wrap gap-2 mt-3">
                                    {tags.map(tag => (
                                        <span key={tag} className={`flex items-center gap-1 bg-gray-700 text-white font-medium pl-2.5 pr-1.5 rounded-full ${isMobile ? 'text-sm py-1' : 'text-xs py-1'}`}>
                                            {tag}
                                            <button type="button" onClick={() => handleRemoveTag(tag)} className="text-gray-400 hover:text-white p-1">
                                                <Icons.XIcon className="h-3 w-3" />
                                            </button>
                                        </span>
                                    ))}
                                </div>
                            </div>
                        </div>
                        <div>
                            {renderLabel("内容", "content")}
                            <textarea
                                id="knowledge-content"
                                value={content}
                                onChange={e => { setContent(e.target.value); markEdited('content'); }}
                                rows={10}
                                className={`${inputClass} resize-y`}
                            />
                        </div>
                    </div>
                </form>

                <div 
                    className={`mt-auto border-t border-gray-700 pt-4 bg-gray-900/50 ${isMobile ? 'flex flex-col gap-3 px-4' : 'flex justify-end gap-3 mt-6'}`}
                    style={isMobile ? { paddingBottom: 'calc(1rem + env(safe-area-inset-bottom))' } : {}}
                >
                    <button type="button" onClick={handleCloseRequest} className={buttonClass('bg-gray-600 hover:bg-gray-500')}>
                        <Icons.XIcon className="h-4 w-4" />
                        キャンセル
                    </button>
                    <button type="submit" form="knowledge-form" data-testid="modal-save-button" className={buttonClass('bg-indigo-600 hover:bg-indigo-500 font-bold')}>
                        <Icons.CheckIcon className="h-4 w-4" />
                        保存
                    </button>
                </div>
            </div>
            <HelpPopover
                isOpen={isCategoryHelpOpen}
                targetRef={categoryHelpRef}
                onClose={() => setIsCategoryHelpOpen(false)}
            >
                新しいカテゴリを追加するには、ここに直接名前を入力して保存してください。
            </HelpPopover>
        </div>,
        document.body
    );
};

import React, { useState, useMemo } from 'react';
import * as Icons from '../icons';
import { useStore } from '../store/index';
import { AnalysisResult, SettingItem, KnowledgeItem } from '../types';

type PreviewTarget = {
  type: 'character' | 'world' | 'knowledge';
  name: string;
  isNew: boolean;
  targetId?: string;
  data: any;
};

export const ImportTextModal: React.FC = () => {
  const [inputText, setInputText] = useState('');
  const [step, setStep] = useState<'input' | 'reflect'>('input');
  const [previewItem, setPreviewItem] = useState<PreviewTarget | null>(null);

  const analyzeImportedText = useStore(state => state.analyzeImportedText);
  const lastAnalysisResult = useStore(state => state.lastAnalysisResult);
  const clearAnalysisResult = useStore(state => state.clearAnalysisResult);
  const applyAnalysisResults = useStore(state => state.applyAnalysisResults);
  const closeModal = useStore(state => state.closeModal);
  const isLoading = useStore(state => state.isLoading);
  const activeProjectId = useStore(state => state.activeProjectId);
  const projectData = useStore(state => state.allProjectsData[activeProjectId]);

  const existingSettings = projectData?.settings || [];
  const existingKnowledge = projectData?.knowledgeBase || [];
  const existingCharacters = useMemo(() => existingSettings.filter(s => s.type === 'character'), [existingSettings]);

  // 反映の選択状態
  const [selectedChars, setSelectedChars] = useState<Record<string, { action: 'create' | 'link' | 'ignore'; targetId?: string }>>({});
  const [selectedTerms, setSelectedTerms] = useState<Record<string, { action: 'world' | 'knowledge' | 'ignore' }>>({});

  const handleAnalyze = async () => {
    if (!inputText.trim()) return;
    await analyzeImportedText(inputText);
    setStep('reflect');
  };

  const handleApply = () => {
    const charPayload = (Object.entries(selectedChars) as [string, { action: 'create' | 'link' | 'ignore'; targetId?: string }][])
        .filter(([_, val]) => val.action !== 'ignore')
        .map(([name, val]) => ({ name, ...val }));

    const termPayload = (Object.entries(selectedTerms) as [string, { action: 'world' | 'knowledge' | 'ignore' }][])
        .filter(([_, val]) => val.action !== 'ignore')
        .map(([name, val]) => ({ name, ...val }));

    applyAnalysisResults({
        characters: charPayload,
        worldTerms: termPayload
    }, inputText);
    closeModal();
  };

  const reflectSummary = useMemo(() => {
    const chars = (Object.values(selectedChars) as { action: string }[]).filter(v => v.action !== 'ignore').length;
    const terms = (Object.values(selectedTerms) as { action: string }[]).filter(v => v.action !== 'ignore').length;
    return { chars, terms };
  }, [selectedChars, selectedTerms]);

  // プレビュー表示用のデータを生成
  const showPreview = (item: any, type: 'char' | 'term', category: 'new' | 'similar') => {
    if (type === 'char') {
      const name = category === 'new' ? item : item.text;
      const targetId = category === 'similar' ? (selectedChars[name]?.targetId || existingCharacters.find(c => c.name === item.target)?.id) : undefined;
      setPreviewItem({
        type: 'character',
        name,
        isNew: category === 'new',
        targetId,
        data: {
          personality: "性格・口調（推定）: インポート解析による補完",
          memo: category === 'new' ? "インポートテキスト由来" : `（追記予定）名称「${name}」として登場`
        }
      });
    } else {
      const name = item;
      const action = selectedTerms[name]?.action || 'world';
      setPreviewItem({
        type: action === 'knowledge' ? 'knowledge' : 'world',
        name,
        isNew: true,
        data: {
          description: "インポート解析による補完。出典：インポートテキスト"
        }
      });
    }
  };

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex justify-center items-center z-[80] p-4">
      <div className="bg-gray-800 rounded-lg shadow-xl w-full max-w-6xl h-[90vh] flex flex-col border border-gray-700 overflow-hidden">
        {/* Header */}
        <div className="flex justify-between items-center p-4 border-b border-gray-700 flex-shrink-0 bg-gray-800/50">
          <h2 className="text-xl font-bold text-indigo-400 flex items-center gap-2">
            <Icons.UploadIcon className="h-6 w-6" />
            テキストインポート解析 {step === 'reflect' && '・反映プレビュー'}
          </h2>
          <button onClick={closeModal} className="p-2 rounded-full hover:bg-gray-700 transition">
            <Icons.XIcon />
          </button>
        </div>

        <div className="flex-grow flex min-h-0 overflow-hidden">
          {step === 'input' ? (
            <>
              {/* Input Phase */}
              <div className="w-1/2 flex flex-col p-6 border-r border-gray-700">
                <label className="block text-sm font-medium text-gray-400 mb-2">取り込むテキストをペースト</label>
                <textarea
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  placeholder="ここに外部で書いた本文を貼り付けてください..."
                  className="flex-grow bg-gray-900 border border-gray-600 rounded-md p-4 text-sm text-white resize-none focus:ring-2 focus:ring-indigo-500 outline-none leading-relaxed"
                />
                <div className="mt-6">
                  <button
                    onClick={handleAnalyze}
                    disabled={isLoading || !inputText.trim()}
                    className="w-full flex items-center justify-center gap-2 px-6 py-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded-md transition font-bold disabled:opacity-50 shadow-lg"
                  >
                    {isLoading ? <Icons.LoaderIcon className="animate-spin" /> : <Icons.SparklesIcon />}
                    AIで設定を抽出して反映準備
                  </button>
                </div>
              </div>
              <div className="w-1/2 flex flex-col items-center justify-center p-12 text-gray-400 text-center">
                <div className="bg-indigo-500/10 p-6 rounded-full mb-6">
                  <Icons.SparklesIcon className="h-16 w-16 text-indigo-400" />
                </div>
                <h3 className="text-xl font-bold mb-4 text-white">執筆準備をスマートに</h3>
                <p className="text-sm leading-relaxed max-w-md">
                  貼り付けたテキストから、AIが自動で登場人物や用語を抽出します。<br/>
                  抽出された設定は、既存の設定と照らし合わせて「新規登録」するか「既存キャラに追記」するかを自由に選べます。
                </p>
              </div>
            </>
          ) : (
            /* Reflection Phase */
            <div className="w-full flex min-h-0">
              {/* Left Column: List */}
              <div className="w-1/3 flex flex-col border-r border-gray-700 bg-gray-900/20 overflow-y-auto p-4 space-y-6">
                {!lastAnalysisResult ? (
                  <div className="flex flex-col justify-center items-center h-full gap-3">
                    <Icons.LoaderIcon className="animate-spin h-8 w-8 text-indigo-500" />
                    <span className="text-sm text-gray-500">解析データを読み込み中...</span>
                  </div>
                ) : (
                  <>
                    <section>
                      <h3 className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-3 px-2">登場人物候補</h3>
                      <div className="space-y-2">
                        {lastAnalysisResult.characters.similar.map((item, idx) => (
                          <div 
                            key={`sim-${idx}`} 
                            onClick={() => showPreview(item, 'char', 'similar')}
                            className={`p-3 rounded-lg border cursor-pointer transition flex items-center gap-3 ${previewItem?.name === item.text ? 'bg-indigo-600/20 border-indigo-500' : 'bg-gray-800/40 border-gray-700 hover:bg-gray-700/50'}`}
                          >
                            <input 
                              type="checkbox" 
                              checked={selectedChars[item.text]?.action === 'link'} 
                              onChange={(e) => {
                                e.stopPropagation();
                                setSelectedChars(prev => ({
                                  ...prev,
                                  [item.text]: { action: e.target.checked ? 'link' : 'ignore', targetId: prev[item.text]?.targetId || existingCharacters.find(c => c.name === item.target)?.id }
                                }));
                              }}
                              className="w-4 h-4 rounded border-gray-600 bg-gray-900 text-indigo-600"
                            />
                            <div className="flex-grow min-w-0">
                              <p className="text-sm font-bold text-white truncate">{item.text}</p>
                              <p className="text-[10px] text-yellow-500">既存: {item.target} に追記</p>
                            </div>
                          </div>
                        ))}
                        {lastAnalysisResult.characters.new.map((name) => (
                          <div 
                            key={`new-${name}`} 
                            onClick={() => showPreview(name, 'char', 'new')}
                            className={`p-3 rounded-lg border cursor-pointer transition flex items-center gap-3 ${previewItem?.name === name ? 'bg-indigo-600/20 border-indigo-500' : 'bg-gray-800/40 border-gray-700 hover:bg-gray-700/50'}`}
                          >
                            <input 
                              type="checkbox" 
                              checked={selectedChars[name]?.action === 'create'} 
                              onChange={(e) => {
                                e.stopPropagation();
                                setSelectedChars(prev => ({
                                  ...prev,
                                  [name]: { action: e.target.checked ? 'create' : 'ignore' }
                                }));
                              }}
                              className="w-4 h-4 rounded border-gray-600 bg-gray-900 text-indigo-600"
                            />
                            <div className="flex-grow min-w-0">
                              <p className="text-sm font-bold text-white truncate">{name}</p>
                              <p className="text-[10px] text-blue-400">新規登録予定</p>
                            </div>
                          </div>
                        ))}
                      </div>
                    </section>

                    <section>
                      <h3 className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-3 px-2">用語・世界観候補</h3>
                      <div className="space-y-2">
                        {lastAnalysisResult.worldTerms.new.map((name) => (
                          <div 
                            key={`term-${name}`} 
                            onClick={() => showPreview(name, 'term', 'new')}
                            className={`p-3 rounded-lg border cursor-pointer transition flex items-center gap-3 ${previewItem?.name === name ? 'bg-indigo-600/20 border-indigo-500' : 'bg-gray-800/40 border-gray-700 hover:bg-gray-700/50'}`}
                          >
                            <input 
                              type="checkbox" 
                              checked={selectedTerms[name]?.action !== 'ignore'} 
                              onChange={(e) => {
                                e.stopPropagation();
                                setSelectedTerms(prev => ({
                                  ...prev,
                                  [name]: { action: e.target.checked ? 'world' : 'ignore' }
                                }));
                              }}
                              className="w-4 h-4 rounded border-gray-600 bg-gray-900 text-indigo-600"
                            />
                            <div className="flex-grow min-w-0">
                              <p className="text-sm font-bold text-white truncate">{name}</p>
                              <p className="text-[10px] text-green-400">
                                {selectedTerms[name]?.action === 'knowledge' ? 'ナレッジに登録' : '世界観に登録'}
                              </p>
                            </div>
                          </div>
                        ))}
                      </div>
                    </section>
                  </>
                )}
              </div>

              {/* Right Column: Detail Preview */}
              <div className="w-2/3 flex flex-col bg-gray-900/40 overflow-hidden relative">
                {previewItem ? (
                  <div className="flex flex-col h-full animate-in fade-in slide-in-from-right-4 duration-200">
                    <div className="p-6 border-b border-gray-700 flex justify-between items-center bg-gray-800/30">
                      <div>
                        <div className="flex items-center gap-2 mb-1">
                          <h3 className="text-xl font-bold text-white">{previewItem.name}</h3>
                          <span className={`text-[10px] px-1.5 py-0.5 rounded font-bold border ${previewItem.isNew ? 'bg-blue-500/10 text-blue-400 border-blue-500/30' : 'bg-yellow-500/10 text-yellow-500 border-yellow-500/30'}`}>
                            {previewItem.isNew ? '新規' : '追記予定'}
                          </span>
                          <span className="text-[10px] px-1.5 py-0.5 rounded font-bold border bg-indigo-500/10 text-indigo-400 border-indigo-500/30">推定</span>
                        </div>
                        <p className="text-xs text-gray-500">
                          {previewItem.type === 'character' ? '登場人物設定' : '世界観・ナレッジ設定'} として反映されます
                        </p>
                      </div>
                      <div className="flex items-center gap-4">
                        <label className="flex items-center gap-2 cursor-pointer bg-gray-800 px-3 py-1.5 rounded-lg border border-gray-600 hover:border-indigo-500 transition">
                          <input 
                            type="checkbox"
                            checked={previewItem.type === 'character' ? (selectedChars[previewItem.name]?.action !== 'ignore') : (selectedTerms[previewItem.name]?.action !== 'ignore')}
                            onChange={(e) => {
                              if (previewItem.type === 'character') {
                                setSelectedChars(prev => ({
                                  ...prev,
                                  [previewItem.name]: { ...prev[previewItem.name], action: e.target.checked ? (previewItem.isNew ? 'create' : 'link') : 'ignore' }
                                }));
                              } else {
                                setSelectedTerms(prev => ({
                                  ...prev,
                                  [previewItem.name]: { ...prev[previewItem.name], action: e.target.checked ? 'world' : 'ignore' }
                                }));
                              }
                            }}
                          />
                          <span className="text-sm font-bold text-gray-300">この項目を反映する</span>
                        </label>
                      </div>
                    </div>

                    <div className="flex-grow overflow-y-auto p-6 space-y-8">
                      {/* Comparison Area */}
                      <div className="grid grid-cols-2 gap-6">
                        {/* Left: Original (Read Only) */}
                        <div className="space-y-4">
                          <h4 className="text-xs font-bold text-gray-500 uppercase flex items-center gap-2">
                             <Icons.HistoryIcon className="h-3 w-3"/> 現在の設定
                          </h4>
                          <div className="bg-gray-800/30 rounded-lg p-4 border border-gray-700/50 min-h-[200px]">
                            {!previewItem.isNew && previewItem.targetId ? (
                              <div className="space-y-3 opacity-60">
                                {existingCharacters.find(c => c.id === previewItem.targetId)?.personality && (
                                  <div>
                                    <p className="text-[10px] text-gray-500 mb-1">性格</p>
                                    <p className="text-sm text-gray-300 line-clamp-3">{existingCharacters.find(c => c.id === previewItem.targetId)?.personality}</p>
                                  </div>
                                )}
                                <div>
                                  <p className="text-[10px] text-gray-500 mb-1">メモ</p>
                                  <p className="text-sm text-gray-300">{existingCharacters.find(c => c.id === previewItem.targetId)?.memo || '(空)'}</p>
                                </div>
                              </div>
                            ) : (
                              <div className="flex flex-col items-center justify-center h-full text-gray-600 italic">
                                <Icons.PlusCircleIcon className="h-8 w-8 mb-2 opacity-20"/>
                                <p className="text-xs">新規項目のため既存データはありません</p>
                              </div>
                            )}
                          </div>
                        </div>

                        {/* Right: To be Added */}
                        <div className="space-y-4">
                          <h4 className="text-xs font-bold text-indigo-400 uppercase flex items-center gap-2">
                            <Icons.ArrowRightIcon className="h-3 w-3"/> 反映後の追加内容
                          </h4>
                          <div className="bg-indigo-900/10 rounded-lg p-4 border border-indigo-500/30 min-h-[200px] shadow-inner">
                            {previewItem.type === 'character' ? (
                              <div className="space-y-4">
                                <div>
                                  <p className="text-[10px] text-indigo-300 mb-1">性格・口調 (AI補完)</p>
                                  <p className="text-sm text-white font-medium bg-indigo-500/10 p-2 rounded border border-indigo-500/20">{previewItem.data.personality}</p>
                                </div>
                                <div>
                                  <p className="text-[10px] text-indigo-300 mb-1">メモへの追記</p>
                                  <p className="text-sm text-white italic">{previewItem.data.memo}</p>
                                </div>
                              </div>
                            ) : (
                              <div className="space-y-4">
                                <div>
                                  <p className="text-[10px] text-indigo-300 mb-1">説明文 (AI補完)</p>
                                  <p className="text-sm text-white bg-indigo-500/10 p-2 rounded border border-indigo-500/20">{previewItem.data.description}</p>
                                </div>
                                <div className="flex gap-4">
                                  <label className="text-[10px] text-gray-400 flex items-center gap-1">
                                    <input 
                                      type="radio" 
                                      name="termType" 
                                      checked={selectedTerms[previewItem.name]?.action === 'world'}
                                      onChange={() => setSelectedTerms(prev => ({ ...prev, [previewItem.name]: { action: 'world' } }))}
                                    />
                                    世界観
                                  </label>
                                  <label className="text-[10px] text-gray-400 flex items-center gap-1">
                                    <input 
                                      type="radio" 
                                      name="termType" 
                                      checked={selectedTerms[previewItem.name]?.action === 'knowledge'}
                                      onChange={() => setSelectedTerms(prev => ({ ...prev, [previewItem.name]: { action: 'knowledge' } }))}
                                    />
                                    ナレッジ
                                  </label>
                                </div>
                              </div>
                            )}
                            <div className="mt-4 pt-4 border-t border-indigo-500/20">
                              <p className="text-[10px] text-gray-500 italic">
                                ※既存の設定は上書きされず、安全に追記・作成されます。
                              </p>
                            </div>
                          </div>
                        </div>
                      </div>

                      {/* AI Memo */}
                      {lastAnalysisResult.notes.length > 0 && (
                        <div className="bg-gray-800/50 border border-gray-700 p-4 rounded-lg">
                          <h4 className="text-xs font-bold text-gray-400 mb-2 flex items-center gap-2">
                             <Icons.BotIcon className="h-3 w-3"/> 解析エンジンからの注記
                          </h4>
                          <p className="text-xs text-gray-400 leading-relaxed">
                            このテキストには「{previewItem.name}」に関連する記述が複数箇所含まれています。
                            話者カラーは設定に基づき自動判定されます。
                          </p>
                        </div>
                      )}
                    </div>
                  </div>
                ) : (
                  <div className="flex flex-col items-center justify-center h-full text-gray-600 text-center p-12">
                    <Icons.EyeIcon className="h-16 w-16 mb-4 opacity-20" />
                    <h3 className="text-lg font-bold mb-2">プレビューを選択</h3>
                    <p className="text-sm max-w-xs">
                      左側のリストから項目を選択して、反映内容を確認してください。
                    </p>
                  </div>
                )}
              </div>
            </div>
          )}
        </div>

        {/* Footer Summary Area */}
        {step === 'reflect' && (
          <div className="p-4 border-t border-gray-700 bg-gray-900/50 flex items-center justify-between flex-shrink-0">
            <div className="flex items-center gap-8 ml-4">
              <div className="flex flex-col">
                <span className="text-[10px] text-gray-500 font-bold uppercase tracking-tighter">REFLECT TARGET</span>
                <div className="flex gap-4 text-sm font-bold text-white">
                  <span>キャラ: {reflectSummary.chars} 件</span>
                  <span>用語: {reflectSummary.terms} 件</span>
                </div>
              </div>
            </div>

            <div className="flex gap-3">
              <button
                onClick={handleBackToInput}
                className="px-6 py-2 bg-gray-700 hover:bg-gray-600 text-white rounded-md transition font-bold flex items-center gap-2"
              >
                <Icons.ArrowLeftIcon className="h-4 w-4"/>
                戻る
              </button>
              <button 
                onClick={handleApply}
                disabled={reflectSummary.chars === 0 && reflectSummary.terms === 0}
                className="px-8 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-md font-bold transition shadow-lg active:scale-95 disabled:opacity-50"
              >
                選択した設定を反映して取り込む
              </button>
            </div>
          </div>
        )}

        {step === 'input' && (
          <div className="p-4 border-t border-gray-700 bg-gray-900/50 flex justify-end flex-shrink-0">
             <button
                onClick={closeModal}
                className="px-6 py-2 bg-gray-700 hover:bg-gray-600 text-white rounded-md transition font-bold"
              >
                キャンセル
              </button>
          </div>
        )}
      </div>
    </div>
  );
};

